import {IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _shapechange = {title: "Shapechange", jsx: <><h2 id="spell-shapechange-shapechange">Shapechange</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 341</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> arcanist 9, druid 9, shaman 9, sorcerer 9, wizard 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (jade circlet worth 1,500 gp)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 10 minutes/level (D)</p><p>This spell allows you to take the form of a wide variety of creatures. This spell can function as alter self, beast shape IV, elemental body IV, form of the dragon III, giant form II, and plant shape III depending on what form you take. You can change form once each round as a free action. The change takes place either immediately before your regular action or immediately after it, but not during the action.</p>
</>};
const _shapechangers_gift = {title: "Shapechanger's Gift", jsx: <><h2 id="spell-shapechangers_gift-shapechangers-gift">Shapechanger's Gift</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 235</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> alchemist 5, arcanist 5, investigator 5, magus 5, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a piece of the creature whose form you plan to assume)<br/><strong>Range</strong> touch<br/><strong>Target</strong> willing living creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You change the target into an animal (as per beast shape I), humanoid (as per alter self), or monstrous humanoid (as per monstrous physique I). The chosen form can't have a fly speed. The subject's statistics change as per the appropriate spell except the creature's ability scores and natural armor do not change. The creature can change between its natural form and the chosen form at will as a standard action.</p>
<h3 id="spell-shapechangers_gift-greater-shapechangers-gift">Greater Shapechanger's Gift</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 235</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> arcanist 7, sorcerer 7, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a piece of the creature whose form you plan to assume)<br/><strong>Range</strong> touch<br/><strong>Target</strong> willing living creature touched<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions as shapechanger's gift except the chosen form can be an animal (as per beast shape I), elemental (as per elemental body I), fey (as per fey form I), humanoid (as per alter self), monstrous humanoid (as per monstrous physique I), or vermin (as per vermin shape I) and the chosen form can have a fly speed.</p>
</>};
const _shard_of_chaos = {title: "Shard of Chaos", jsx: <><h2 id="spell-shard_of_chaos-shard-of-chaos">Shard of Chaos</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 237</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/chaotic">chaotic</Link>]; <strong>Level</strong> cleric 2, oracle 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> dart-shaped projectile of chaotic energy<br/><strong>Duration</strong> instantaneous (1d6 rounds)<br/><strong>Saving Throw</strong> Will partial (see text); <strong>Spell Resistance</strong> yes</p><p>You hurl a multicolored shard of congealed chaos from your holy symbol, affecting any one target in range as a ranged touch attack.</p>
<p>A lawful creature struck by the shard takes 1d8 points of damage per two caster levels (maximum 5d8). A lawful outsider instead takes 1d6 points of damage per caster level (maximum 10d6) and is slowed (as slow) for 1 round. A successful Will save reduces the damage to half and negates the slow effect. The bolt has no effect on chaotic creatures. This spell deals only half damage to creatures that are neither lawful nor chaotic, and they are not slowed.</p>
</>};
const _share_glory = {title: "Share Glory", jsx: <><h2 id="spell-share_glory-share-glory">Share Glory</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 114</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, bard 2, cleric 3, druid 3, hunter 3, medium 1, oracle 3, psychic 3, red mantis assassin 3, skald 2, sorcerer 3, summoner 2, unchained summoner 2, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one non-mythic creature/3 levels<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You imbue the targets with a fraction of your mythic nature. They count as mythic creatures for the purpose of path abilities, spells, and other effects that function differently for mythic creatures. This doesn't grant the targets mythic tiers or any uses of mythic power; it merely gives them a greater advantage when others use abilities that work differently for mythic creatures. You must be at least a 1st-tier mythic character to cast this spell.</p>
</>};
const _share_language = {hasJL:true,title: "Share Language", jsx: <><div className="jumpList" id="spell-share_language-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-share_language-compel-tongue">Compel Tongue</InnerLink></li><li><InnerLink toTop to="spell-share_language-communal-share-language">Communal Share Language</InnerLink></li><li><InnerLink toTop to="spell-share_language-mass-compel-tongue">Mass Compel Tongue</InnerLink></li></ul></div><h2 id="spell-share_language-share-language">Share Language</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 243</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 2, bard 1, cleric 2, druid 2, hunter 2, medium 1, mesmerist 1, occultist 2, oracle 2, psychic 1, skald 1, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a page from a dictionary)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 24 hours<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You can share your facility for one particular language with another creature. For 24 hours the target can read, understand, and communicate to the best of its ability in any one language which you already know. For every 5 levels you possess, you can grant the use of another language you know, to a maximum of 5 <Link to="/misc/languages">languages</Link> at 20th level. The target must have the physical capacity to articulate sounds, make gestures, or engage in whatever other method speakers of the language use to communicate with each other in order to actually converse. If the target lacks the mental capacity to grasp an actual language it still gains enough knowledge to respond to and carry out even extremely complex commands or suggestions coached in the language (whether written or spoken). However, since this spell does not endow the target with greater reasoning capacity, merely a temporarily enhanced vocabulary, the person offering up instructions to non-sentient creatures must take care to remove any ambiguity or guesswork.</p>
<p>Similarly, this spell does not affect the basic nature of the target, or its disposition toward you or anyone else, so convincing it to actually carry out these instructions could require negotiation, threats, or outright bribery.</p>
<h3 id="spell-share_language-compel-tongue" data-hash-target>Compel Tongue</h3>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 24</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 2, bard 1, cleric 2, druid 2, hunter 2, oracle 2, skald 1, sorcerer 2, warpriest 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a wooden block carved with a letter)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions as share language, granting a creature the ability to read, understand, and communicate to the best of its ability in any one language you know. For the spell's entire duration, the target can speak and write only in the language imparted, but its ability to understand other languages is unaffected.</p>
<h3 id="spell-share_language-communal-share-language" data-hash-target>Communal Share Language</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 243</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 3, bard 2, cleric 3, druid 3, hunter 3, mesmerist 2, occultist 3, oracle 3, psychic 2, skald 2, sorcerer 3, warpriest 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a page from a dictionary)<br/><strong>Range</strong> touch<br/><strong>Targets</strong> creatures touched<br/><strong>Duration</strong> 24 hours<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like share language, except you divide the duration in 1-hour increments among the creatures touched.</p>
<h3 id="spell-share_language-mass-compel-tongue" data-hash-target>Mass Compel Tongue</h3>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 24</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 5, bard 4, cleric 5, druid 5, hunter 5, oracle 5, skald 4, sorcerer 5, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a wooden block carved with a letter)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions as compel tongue, except it affects multiple creatures. The same language restriction applies to all creatures, and the same language must be imparted to all creatures affected by the same casting on this spell.</p>
</>};
const _share_memory = {title: "Share Memory", jsx: <><h2 id="spell-share_memory-share-memory">Share Memory</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 238</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 2, bard 2, medium 2, mesmerist 2, occultist 2, psychic 2, skald 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> you and one creature touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You momentarily link your mind with the target and share a single memory of no longer than 1 minute. You can show the target one of your memories, show the target one of its own memories, or view one of the target's memories.</p>
</>};
const _share_senses = {title: "Share Senses", jsx: <><h2 id="spell-share_senses-share-senses">Share Senses</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 243</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> (<Link to="/spelldef/scrying">scrying</Link>); <strong>Level</strong> arcanist 4, medium 3, psychic 3, sorcerer 4, witch 3, wizard 4<br/><strong>Casting Time</strong> 1 full-round action<br/><strong>Components</strong> V, S, M (a hair, scale, or feather from your familiar)<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Target</strong> your familiar<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>Spending a moment in meditation and conjuring an image of the creature to mind, you reshape your link with your familiar, causing it to functions like a scrying sensor. Upon casting this spell you can hear, see, or smell (any one, your choice) what your familiar is experiencing. You gain the benefits of any nonmagical special abilities your familiar has tied to the chosen sense (such as low-light vision or scent), but use your own Perception skill. You don't need line of sight or line of effect to your familiar, but you must have an active empathic link. You may change the sense you are sharing as a standard action. Unlike other scrying spells, share senses does not allow magically or supernaturally enhanced senses to work through it, and you are unable to see in magical or natural darkness unless your familiar possesses the ability to see in such conditions.</p>
<p>The sensory link with your familiar can be detected as though it were a scrying sensor.</p>
</>};
const _share_skin = {title: "Share Skin", jsx: <><h2 id="spell-share_skin-share-skin">Share Skin</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 11</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> druid 6, hunter 6, witch 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> one animal touched<br/><strong>Duration</strong> 1 minute/level or until you return to your body</p><blockquote>
<p><em>The following spells are common among <Link to="/template/lycanthrope">werebears</Link> coldborn <Link to="/race/skinwalker">skinwalkers</Link>, and those who associate with them.</em></p>
</blockquote>
<p>You can possess an animal's body in a manner that functions like magic jar, except as noted here. Your body vanishes while the effect lasts and you don't require a receptacle.</p>
<h3 id="spell-share_skin-greater-share-skin">Greater Share Skin</h3>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 11</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> witch 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> one creature touched<br/><strong>Duration</strong> 1 minute/level or until you return to your body</p><p>This spell functions like share skin, except as noted here.</p>
</>};
const _shared_sacrifice = {title: "Shared Sacrifice", jsx: <><h2 id="spell-shared_sacrifice-shared-sacrifice">Shared Sacrifice</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 240</Link>, <Link to="/source/faiths_of_corruption">Faiths of Corruption pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> antipaladin 3, cleric 2, oracle 2, shaman 2, summoner 3, unchained summoner 3, warpriest 2, witch 2 (Asmodeus; see below)<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You create a link to a target and can direct pain and damage through this link. You take only half damage from effects and attacks that deal hit point damage. The target of this spell takes the remainder of the damage. Forms of harm that do not involve hit points, such as charm effects, temporary ability damage, level drain, and death effects cannot be shared through this link. If you suffer a reduction in hit points because of a lowered Constitution score, the reduction is not split with the target of this spell because it is not hit point damage. When the spell ends, subsequent damage is no longer divided between the subject and you, but damage already split is not reassigned back to you.</p>
<p>If you and the target of the spell move out of range of each other, the spell immediately ends.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _shared_suffering = {title: "Shared Suffering", jsx: <><h2 id="spell-shared_suffering-shared-suffering">Shared Suffering</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> antipaladin 2, arcanist 2, inquisitor 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, F (a silver dagger inlaid with onyx and jade worth 100 gp)<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>You infuse a dagger with necromantic energy, then plunge the dagger into your own body. You take 1d6 points of negative energy damage plus 1d6 points of damage for every 2 caster levels you possess beyond 1st (to a maximum of 5d6 at 9th level). The target takes an amount of damage equal to the damage you took this way, plus an amount equal to your Intelligence modifier (if you're a witch or wizard), Wisdom modifier (if you're an inquisitor), or Charisma modifier (if you're an antipaladin or sorcerer).</p>
<p>Damage from this spell cannot be divided by effects such as <Link to="/spell/shield_other">shield other</Link> or unwilling shield; it cuts through such protections completely.</p>
</>};
const _shared_training = {title: "Shared Training", jsx: <><h2 id="spell-shared_training-shared-training">Shared Training</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 15</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 3, bard 2, cleric 3, hunter 2, inquisitor 2, magus 2, oracle 3, paladin 2, psychic 3, ranger 2, skald 2, sorcerer 3, warpriest 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> you plus one willing creature per 3 levels, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>Select one teamwork feat you have. You can grant this feat to allies within range for the duration of the spell. Allies do not need to meet the prerequisites of this teamwork feat. At caster level 9th, you can grant two teamwork feats you have to your allies. At caster level 13th, you can grant three teamwork feats, and at caster level 17th, you can grant up to four teamwork feats.</p>
</>};
const _sharesister = {title: "Sharesister", jsx: <><h2 id="spell-sharesister-sharesister">Sharesister</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 58</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> cleric 3, oracle 3, warpriest 3, witch 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a drop of your own blood)<br/><strong>Range</strong> touch<br/><strong>Target</strong> you and one creature of your gender<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>Ithuna Vardsdottir claims to have unearthed this ancient prayer in a ruined temple of Desna, though Pathfinders have reported the use of similar magic in Irrisen among the White Witches. While the name of this spell is sharesister, it works equally well on male or female creatures - both targets of the spell must simply be of the same gender.</p>
<p>When you deliver the spell, you receive a negative level for the duration of the spell, and the other target receives a +1 insight bonus to her caster level and a +1 insight bonus to the save DCs of all of her spells. At 11th level, you can opt to take four negative levels to grant a +2 insight bonus to the other target's caster level and spell save DCs if you wish, while at 17th level you can take 6 negative levels to increase the insight bonus to +3. Any effect that removes or prevents the negative level immediately ends the sharesister spell. Negative levels received from the spell vanish as soon as this spell effect ends. Negative levels from multiple castings of this spell stack.</p>
</>};
const _shatter = {title: "Shatter", jsx: <><h2 id="spell-shatter-shatter">Shatter</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 341</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/sonic">sonic</Link>]; <strong>Level</strong> arcanist 2, bloodrager 2, bard 2, cleric 2, magus 2, occultist 2, oracle 2, psychic 2, skald 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a chip of mica)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area or Target</strong> 5-ft.-radius spread; or one solid object or one crystaline creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (object); Will negates (object) or Fortitude half; see text; <strong>Spell Resistance</strong> yes</p><p>Shatter creates a loud, ringing noise that breaks brittle, nonmagical objects; sunders a single solid, nonmagical object; or damages a crystalline creature.</p>
<p>Used as an area attack, shatter destroys nonmagical objects of crystal, glass, ceramic, or porcelain. All such unattended objects within a 5-foot radius of the point of origin are smashed into dozens of pieces by the spell. Objects weighing more than 1 pound per your level are not affected, but all other objects of the appropriate composition are shattered.</p>
<p>Alternatively, you can target shatter against a single solid nonmagical object, regardless of composition, weighing up to 10 pounds per caster level. Targeted against a crystalline creature (of any weight), shatter deals 1d6 points of sonic damage per caster level (maximum 10d6), with a Fortitude save for half damage.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-shatter--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Shatter</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 107</Link><br/>Add your tier to your caster level when determining the maximum object weight you can affect. When targeting a crystalline creature, the spell's damage increases to 1d8 points of sonic damage per caster level (maximum 10d8). You may damage a single magical object as if it were a crystalline creature. If the spell destroys an object or damages a crystalline creature, broken shards litter the spell area or creature's space and act as caltrops.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _sheet_lightning = {title: "Sheet Lightning", jsx: <><h2 id="spell-sheet_lightning-sheet-lightning">Sheet Lightning</h2>
<p><strong>Sources</strong> <Link to="/source/rival_guide">Rival Guide pg. 23</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/electricity">electricity</Link>]; <strong>Level</strong> arcanist 3, druid 3, hunter 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> 20-ft.-radius spread<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude partial; <strong>Spell Resistance</strong> yes</p><p>You create a dazzling flash of electricity that fills the target area. Sheet lightning inflicts 1 point of electricity damage to all creatures within the area of effect (no save). The true power of the spell, though, lies not in the damage it inflicts but in the overwhelming pain the lightning creates. The sudden flash and jolt dazes living creatures for 1 round if they fail a saving throw. Creatures that save are instead dazzled for 1 round. Any creature wearing metal armor takes a -2 penalty to its saving throw against this spell.</p>
</>};
const _shield = {title: "Shield", jsx: <><h2 id="spell-shield-shield">Shield</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 342</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> alchemist 1, arcanist 1, bloodrager 1, investigator 1, magus 1, occultist 1, psychic 1, sorcerer 1, spiritualist 1, summoner 1, unchained summoner 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level (D)</p><p>Shield creates an invisible shield of force that hovers in front of you. It negates <Link to="/spell/magic_missile">magic missile</Link> attacks directed at you. The disk also provides a +4 shield bonus to AC. This bonus applies against incorporeal touch attacks, since it is a force effect. The shield has no armor check penalty or arcane spell failure chance.</p>
</>};
const _shield_companion_acg = {title: "Shield Companion (ACG)", jsx: <><h2 id="spell-shield_companion_acg-shield-companion-acg">Shield Companion (ACG)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 191</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 3, hunter 2, paladin 2, ranger 2, shaman 2, sorcerer 3, summoner 3, unchained summoner 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> your companion creature<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell creates a special mystical connection between you and your companion creature - animal companion, bonded mount, eidolon, or familiar - which allows you to transfer its wounds to you. The creature gains a +1 deflection bonus to AC and a +1 resistance bonus on saves. As an immediate action when your companion takes damage, you can take that damage yourself to prevent your companion from being harmed (similar to <Link to="/spell/shield_other">shield other</Link>, except the damage is not split between you and the target). Forms of harm that do not involve the loss of hit points, such as charm effects, temporary ability damage, level drain, and death effects, are not affected. If the creature suffers a reduction of hit points from a lowered Constitution score, you cannot take that damage on behalf of your companion creature because it is not hit point damage. When the spell ends, damage directed to you by the spell is not reassigned to the subject.</p>
<p>If you and your companion move out of range of each other, the spell ends.</p>
</>};
const _shield_of_darkness = {title: "Shield of Darkness", jsx: <><h2 id="spell-shield_of_darkness-shield-of-darkness">Shield of Darkness</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/darkness">darkness</Link>, <Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> antipaladin 3, cleric 3, inquisitor 3, oracle 3, shaman 3, spiritualist 3, warpriest 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You shield yourself with darkness, reducing the illumination level in your space to magical darkness and granting you <Link to="/rule/concealment">total concealment</Link>. Your opponents are automatically aware of which squares you occupy, preventing you from attempting Stealth checks using this concealment unless every square adjacent to you has an illumination level of darkness or lower. Shield of darkness does not hinder your vision, and creatures that can see in magical darkness ignore this effect.</p>
</>};
const _shield_of_faith = {title: "Shield of Faith", jsx: <><h2 id="spell-shield_of_faith-shield-of-faith">Shield of Faith</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 342</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 1, inquisitor 1, oracle 1, warpriest 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (parchment with a holy text written on it)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell creates a shimmering, magical field around the target that averts and deflects attacks. The spell grants the subject a +2 deflection bonus to AC, with an additional +1 to the bonus for every six levels you have (maximum +5 deflection bonus at 18th level).</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-shield_of_faith--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Shield of Faith</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 108</Link><br/>Add half your tier to the spell's deflection bonus.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _shield_of_fortification = {title: "Shield of Fortification", jsx: <><h2 id="spell-shield_of_fortification-shield-of-fortification">Shield of Fortification</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 192</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 2, inquisitor 1, oracle 2, paladin 1, psychic 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You create a magical barrier that protects a target's vital areas. When the target is struck by a critical hit or a sneak attack, there is a 25% chance that the critical hit or sneak attack is negated and damage is instead rolled normally. This benefit does not stack with other effects that can turn critical hits or sneak attacks into normal attacks, such as the fortification armor special ability.</p>
<h3 id="spell-shield_of_fortification-greater-shield-of-fortification">Greater Shield of Fortification</h3>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 192</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 4, inquisitor 3, oracle 4, paladin 3, psychic 4, warpriest 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions as shield of fortification, except there is a 50% chance that the critical hit or sneak attack is negated and damage is instead be rolled normally, rather than 25%.</p>
</>};
const _shield_of_law = {title: "Shield of Law", jsx: <><h2 id="spell-shield_of_law-shield-of-law">Shield of Law</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 342</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/lawful">lawful</Link>]; <strong>Level</strong> cleric 8, oracle 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a reliquary worth 500 gp)<br/><strong>Range</strong> 20 ft.<br/><strong>Targets</strong> one creature/level in a 20-ft.-radius burst centered on you<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> see text; <strong>Spell Resistance</strong> yes</p><p>A dim, blue glow surrounds the subjects, protecting them from attacks, granting them resistance to spells cast by chaotic creatures, and slowing chaotic creatures when they strike the subjects. This abjuration has four effects.</p>
<p>First, each warded creature gains a +4 deflection bonus to AC and a +4 resistance bonus on saves. Unlike <Link to="/spell/protection_from_chaos">protection from chaos</Link>, this benefit applies against all attacks, not just against attacks by chaotic creatures.</p>
<p>Second, a warded creature gains spell resistance 25 against chaotic spells and spells cast by chaotic creatures.</p>
<p>Third, the abjuration protects you from possession and mental influence, just as protection from chaos does.</p>
<p>Finally, if a chaotic creature succeeds on a melee attack against a warded creature, the attacker is slowed (Will save negates, as the <Link to="/spell/slow">slow</Link> spell, but against shield of law's save DC).</p>
</>};
const _shield_of_shards = {title: "Shield Of Shards", jsx: <><h2 id="spell-shield_of_shards-shield-of-shards">Shield Of Shards</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 23</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> bloodrager 1, cleric 2, inquisitor 2, magus 2, medium 2, oracle 2, paladin 1, shaman 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a shield)<br/><strong>Range</strong> personal<br/><strong>Target</strong> one shield you wield<br/><strong>Duration</strong> 1 round/level</p><p>This defensive spell must be cast on a shield you are currently wielding, and fractures the shield into two shards, plus one additional shard per 2 caster levels (to a maximum of 12 shards at 20th level). While shield of shards is active, you lose your shield's bonus to AC as its broken pieces orbit you. On your turn, you can direct the shards to attack an adjacent opponent as a move action. The shards' attack bonus is equal to your caster level + the modifier for the ability score that determines your spell save DCs. The shards deal an amount of slashing and piercing damage equal to 1d4 points + 1 point per shard beyond the first, and have a threat range of 19-20. They are considered magic weapons for the purpose of bypassing damage reduction. Additionally, if your shield is made from a special material (such as adamantine), the shards penetrate damage reduction and hardness as if they were weapons made from the same material.</p>
<p>At the end of this spell's duration, the shards reform into their original shield form. You regain its shield bonus to AC, provided you still have a free hand in which to wield it. Otherwise, the shield falls at your feet in your square.</p>
</>};
const _shield_of_the_dawnflower = {hasJL:true,title: "Shield of the Dawnflower", jsx: <><div className="jumpList" id="spell-shield_of_the_dawnflower-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-shield_of_the_dawnflower-mythic_shield_of_the_dawnflower">Mythic Shield of the Dawnflower</InnerLink></li><li><InnerLink toTop to="spell-shield_of_the_dawnflower-greater-shield-of-the-dawnflower">Greater Shield of the Dawnflower</InnerLink></li></ul></div><h2 id="spell-shield_of_the_dawnflower-shield-of-the-dawnflower">Shield of the Dawnflower</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 296</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 35</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>, <Link to="/spelldef/good">good</Link>, <Link to="/spelldef/light">light</Link>]; <strong>Level</strong> bard 4, cleric 4, hunter 4, magus 4, oracle 4, paladin 4, ranger 4, skald 4, warpriest 4 (Sarenrae; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> see text; <strong>Spell Resistance</strong> no</p><p>You create a disk of sunlight on one arm. Any creature that strikes you with a melee attack deals normal damage, but also takes 1d6 points of fire damage + 1 point per caster level (maximum +15). Creatures with reach weapons are not subject to this damage if they attack you. The shield provides illumination as if it were a <Link to="/spell/continual_flame">continual flame</Link> spell. You can only have one instance of this spell in effect at a time. It does not stack with similar damaging aura spells such as fire shield.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-shield_of_the_dawnflower--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-shield_of_the_dawnflower-mythic_shield_of_the_dawnflower" data-hash-target>Mythic Shield of the Dawnflower</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_origins">Mythic Origins pg. 13</Link></p>
<p>The disk of sunlight protects you as a buckler with a +1 enhancement bonus per 4 caster levels (maximum +5).</p>
<p>You can make a melee touch attack with your shield of the Dawnflower in place of a normal attack to deal its fire damage to a creature. Creatures taking damage from your shield catch on fire (Reflex negates); the save DC to extinguish the fire is equal to the DC of the spell.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-shield_of_the_dawnflower-greater-shield-of-the-dawnflower" data-hash-target>Greater Shield of the Dawnflower</h3>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>, <Link to="/spelldef/good">good</Link>, <Link to="/spelldef/light">light</Link>]; <strong>Level</strong> bard 6, cleric 6, magus 6, oracle 6, skald 6, warpriest 6 (Sarenrae; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>You create a disk of sunlight on one arm. Any creature that strikes you with a melee attack deals normal damage, but also takes 1d6 points of damage + 1 point per caster level. Half of this damage is fire damage and half is holy damage (as the spell <Link to="/spell/flame_strike">flame strike</Link>). An undead creature or a creature particularly vulnerable to light that hits you instead takes 2d6 points of damage +1 point per caster level. Creatures with reach weapons are not subject to this damage if they attack you. The shield provides illumination equivalent to a <Link to="/spell/daylight">daylight</Link> spell. You can have only one instance of this spell in effect at a time. It does not stack with similar damaging aura spells such as fire shield or shield of the Dawnflower.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _shield_of_wings = {title: "Shield of Wings", jsx: <><h2 id="spell-shield_of_wings-shield-of-wings">Shield of Wings</h2>
<p><strong>Sources</strong> <Link to="/source/paths_of_the_righteous">Paths of the Righteous pg. 9</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> cleric 3, inquisitor 3, oracle 3, paladin 3, ranger 3, warpriest 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level (see below)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><blockquote>
<p><em>The following spell is available to worshipers of <Link to="/faith/ragathiel">Ragathiel</Link>.</em></p>
</blockquote>
<p>You gain five burning wings that grant a fly speed equal to the number of wings &times; 10 (average maneuverability) for an initial fly speed of 50 feet. The first time in a round where you would take fire damage, a wing vanishes (reducing the fly speed granted) and you gain fire resistance 30 for the remainder of the round. When you are down to one wing (and a fly speed of 10 feet), your maneuverability drops to poor. When you lose your final wing, you become immune to fire damage for 1 additional minute, after which the effects of this spell end.</p>
</>};
const _shield_other = {hasJL:true,title: "Shield Other", jsx: <><div className="jumpList" id="spell-shield_other-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-shield_other-mythic_shield_other">Mythic Shield Other</InnerLink></li><li><InnerLink toTop to="spell-shield_other-shield-companion-aa">Shield Companion (AA)</InnerLink></li></ul></div><h2 id="spell-shield_other-shield-other">Shield Other</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 342</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 2, inquisitor 2, oracle 2, paladin 2, psychic 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a pair of platinum rings worth 50 gp worn by both you and the target)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell wards the subject and creates a mystic connection between you and the subject so that some of its wounds are transferred to you. The subject gains a +1 deflection bonus to AC and a +1 resistance bonus on saves. Additionally, the subject takes only half damage from all wounds and attacks (including those dealt by special abilities) that deal hit point damage. The amount of damage not taken by the warded creature is taken by you. Forms of harm that do not involve hit points, such as charm effects, temporary ability damage, level draining, and death effects, are not affected. If the subject suffers a reduction of hit points from a lowered Constitution score, the reduction is not split with you because it is not hit point damage. When the spell ends, subsequent damage is no longer divided between the subject and you, but damage already split is not reassigned to the subject.</p>
<p>If you and the subject of the spell move out of range of each other, the spell ends.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-shield_other--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-shield_other-mythic_shield_other" data-hash-target>Mythic Shield Other</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 108</Link></p>
<p>Increase the range to long (400 feet + 40 feet per caster level). Subtract your tier from any damage transmitted to you through the mystical connection before applying the damage (minimum 1 hp of damage). When you use your surge ability to modify a saving throw against an effect that also affects your linked ally, the ally also applies your surge bonus die result to the ally's saving throw. If the ally also uses its own surge ability, it takes either your result or its result, whichever is higher.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-shield_other-shield-companion-aa" data-hash-target>Shield Companion (AA)</h3>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> antipaladin 1, arcanist 1, druid 1, hunter 1, paladin 1, ranger 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a pair of platinum rings worth 50 gp worn by both you and the target)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> your animal companion, familiar, or fiendish servant<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions as <Link to="/spell/shield_other">shield other</Link> but affects only the caster's animal companion or familiar. Spellcasters from classes that do not normally gain an animal companion, familiar, or fiendish servant but who gain one through an alternate class feature, archetype, or prestige class can prepare and cast this spell as a 1st-level spell if they are capable of casting spells.</p>
</>};
const _shield_speech = {title: "Shield Speech", jsx: <><h2 id="spell-shield_speech-shield-speech">Shield Speech</h2>
<p><strong>Sources</strong> <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 1, bard 1, cleric 1, druid 1, hunter 1, oracle 1, skald 1, sorcerer 1, warpriest 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 10 ft.<br/><strong>Target</strong> you and one other creature<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You can securely communicate with one creature within range. So long as your target remains within 10 feet of you, you and it can speak freely to each other without fear of being overheard. Communications that involve shield speech cannot be spied on, such as with a divination spell, and observers of the conversation can tell you are communicating but cannot read lips or hear the conversation unless they are the target of the spell. If you or the target speak to any other creatures, they can hear you normally (only communication between you and the target is protected). The spell does not shield writing, sign language, or any form of communication other than speaking.</p>
<h3 id="spell-shield_speech-greater-shield-speech">Greater Shield Speech</h3>
<p><strong>Sources</strong> <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 4, cleric 4, druid 4, hunter 4, oracle 4, sorcerer 4, warpriest 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 30 ft.<br/><strong>Area</strong> 30-ft. emanation centered on you<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions as shield speech, except all creatures within the dome may communicate with each other as if linked by shield speech. If they speak with anyone outside the area, those outside the area hear them normally.</p>
</>};
const _shield_the_banner = {title: "Shield the Banner", jsx: <><h2 id="spell-shield_the_banner-shield-the-banner">Shield the Banner</h2>
<p><strong>Sources</strong> <Link to="/source/orcs_of_golarion">Orcs of Golarion pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> adept 1, cleric 1, oracle 1, warpriest 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> object touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> no</p><p>This spell is used to protect one of a tribe's most valuable possessions: its tribal banner. Any creature (other than a member of the tribe which the standard represents) attempting to directly attack or touch the standard must make a Will save. This spell functions as <Link to="/spell/sanctuary">sanctuary</Link>, but only protects a standard or banner. In addition, the spell grants a +2 bonus to the standard's hardness, and +10 to the standard's hit points for the duration of the spell.</p>
</>};
const _shifted_steps = {title: "Shifted Steps", jsx: <><h2 id="spell-shifted_steps-shifted-steps">Shifted Steps</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 225</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> alchemist 2, antipaladin 2, arcanist 2, bard 2, inquisitor 2, investigator 2, magus 2, medium 2, mesmerist 2, occultist 2, psychic 2, skald 2, sorcerer 2, spiritualist 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature or object up to 10 feet across<br/><strong>Duration</strong> concentration+ 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless) and Will disbelief (if interacted with); see text; <strong>Spell Resistance</strong> no</p><p>You cause the target to sound as if it is elsewhere within range, including its movements, speech, and all other sounds. As long as you concentrate, you can cause the sound's apparent location to change as you see fit within range from your current location. Once you cease concentrating, the sound moves so that it remains the same relative distance and direction from the target. This spell can fool any sound-based blindsense or blindsight (including echolocation), but it can't fool other forms of detection such as other forms of blindsense or blindsight, lifesense, normal vision, and tremorsense. The target receives a saving throw against the effect if it doesn't wish for you to shift its sound, and any creature that interacts with the illusion receives a Will save to disbelieve the glamer.</p>
</>};
const _shifting_sand = {title: "Shifting Sand", jsx: <><h2 id="spell-shifting_sand-shifting-sand">Shifting Sand</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 243</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> arcanist 3, druid 3, hunter 3, red mantis assassin 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a handful of sand)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> 20-ft. spread<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Reflex negates, see text; <strong>Spell Resistance</strong> no</p><p>You cause an earthen or sandy surface to shift and churn within the area. The shifting sand obliterates tracks and is considered difficult terrain. Acrobatics checks in the area take a penalty equal to your caster level (maximum +10). Creatures entering or beginning their turn in the shifting sand must make a Reflex save each round or become entangled until the beginning of their next turn. If they attempt to move while entangled, they must make a second Reflex save or fall prone. Creatures with the stability racial trait (like dwarves) may apply it as a bonus on their saving throws.</p>
<p>As a move action, you may move the area of shifting sand up to 10 feet in any direction. Creatures that are entangled or prone in the spell's area are carried along with the shifting sand in the same direction if possible. This movement does not provoke attacks of opportunity. Unattended Medium or smaller objects may also be carried along or shallowly buried by the shifting sand.</p>
</>};
const _shifting_shadows = {title: "Shifting Shadows", jsx: <><h2 id="spell-shifting_shadows-shifting-shadows">Shifting Shadows</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/darkness">darkness</Link>]; <strong>Level</strong> arcanist 3, bard 3, skald 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a drop of ink)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> 20-ft.-radius emanation centered on a point in space<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> none, see text; <strong>Spell Resistance</strong> no</p><p>Waves of shifting shadows obscure the appearance of all creatures caught within the emanation, making it harder to tell friends from foes.</p>
<p>This spell does not cause affected creatures to risk accidentally attacking their allies, but it does require them to concentrate harder to keep track of their allies and foes. While this spell is in effect, every creature in the area can treat any other creature in the area as an allied threatening creature for the purpose of flanking. Further, whenever a creature in the area would provoke an attack of opportunity from an enemy, that creatures' allies in the area must succeed at a Reflex save or lose one attack of opportunity for that round as they suppress the instinct to attack a vulnerable target that might be an ally. The shadows do not hinder precision-based attacks or create areas of dim light.</p>
<p>Creatures under the effect of <Link to="/spell/true_seeing">true seeing</Link> are not affected by this spell. Creatures with <Link to="/umr/scent">scent</Link> or <Link to="/umr/keen_scent">keen scent</Link>, creatures that are blind, and creatures that operate effectively without vision (such as creatures with <Link to="/umr/blindsight">blindsight</Link> or <Link to="/umr/blindsense">blindsense</Link>) are also not affected by this spell.</p>
</>};
const _shillelagh = {title: "Shillelagh", jsx: <><h2 id="spell-shillelagh-shillelagh">Shillelagh</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 342</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> druid 1, hunter 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> one touched nonmagical oak club or quarterstaff<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>Your own nonmagical club or quarterstaff becomes a weapon with a +1 enhancement bonus on attack and damage rolls. A quarterstaff gains this enhancement for both ends of the weapon. It deals damage as if it were two size categories larger (a Small club or quarterstaff so transmuted deals 1d8 points of damage, a Medium 2d6, and a Large 3d6), +1 for its enhancement bonus. These effects only occur when the weapon is wielded by you. If you do not wield it, the weapon behaves as if unaffected by this spell.</p>
</>};
const _shining_cord = {title: "Shining Cord", jsx: <><h2 id="spell-shining_cord-shining-cord">Shining Cord</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_magic">Inner Sea Magic pg. 60</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> magus 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a small length fine of silver chain worth 100 gp)<br/><strong>Range</strong> 30 ft.<br/><strong>Target</strong> 1 creature<br/><strong>Duration</strong> 1 round/level or instantaneous (see below)<br/><strong>Saving Throw</strong> Fortitude partial (see below); <strong>Spell Resistance</strong> yes</p><p>When you cast this spell, you make a ranged touch attack against a single opponent within 30 feet. If you hit, a thin silver strand extends from your body to its, forming a connection that allows you to anticipate its actions. For the duration of the spell, you receive a +5 insight bonus on all Perception and Sense Motive checks opposed by the target. You gain a +5 insight bonus on all Spellcraft checks made to identify your opponent's spell as part of a counterspelling attempt. Finally, you gain a +2 dodge bonus to your AC against attacks made against you by the target.</p>
<p>Lastly, if either you or the target moves more than 30 feet away from the other, the cord crackles with a surge of light and sends a blast of force along its length to the other end. This blast deals 1d6 points of damage per two caster levels (maximum 10d6) and stuns the one who moved out of range for 1 round - a successful Fortitude save halves the damage and negates the stun effect. This blast ends the spell and severs the connection between you and your target.</p>
<p>Although the shining cord makes a visible connection between you and your target, creatures can move through it without ill effect. The cord even passes through solid objects as necessary to maintain the connection between you and the target.</p>
</>};
const _shock_shield = {title: "Shock Shield", jsx: <><h2 id="spell-shock_shield-shock-shield">Shock Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 243</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/electricity">electricity</Link>, <Link to="/spelldef/force">force</Link>]; <strong>Level</strong> alchemist 1, arcanist 1, bloodrager 1, investigator 1, magus 1, occultist 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level (D)</p><p>This spell creates an invisible shield similar to but not as strong as the <Link to="/spell/shield">shield</Link> spell. This shield hovers in front of you and negates <Link to="/spell/magic_missile">magic missile</Link> attacks directed at you. The disk provides a +2 shield bonus to AC. This bonus applies against incorporeal touch attacks.</p>
<p>At any time, as a free action, you may dismiss your shield, at which point it deals 1d6 points of electrical damage to all creatures within a 5-foot burst, including you. A Reflex saving throw halves the damage.</p>
</>};
const _shocking_grasp = {title: "Shocking Grasp", jsx: <><h2 id="spell-shocking_grasp-shocking-grasp">Shocking Grasp</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 343</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/electricity">electricity</Link>]; <strong>Level</strong> arcanist 1, bloodrager 1, magus 1, occultist 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature or object touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>Your successful melee touch attack deals 1d6 points of electricity damage per caster level (maximum 5d6). When delivering the jolt, you gain a +3 bonus on attack rolls if the opponent is wearing metal armor (or is carrying a metal weapon or is made of metal).</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-shocking_grasp--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Shocking Grasp</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 108</Link><br/>The spell's damage increases to 1d8 points of electricity damage per caster level (maximum 5d8). If the target is wearing metal armor or is made of metal, you may attempt a free grapple combat maneuver against the target.</p>
<p>Alternatively, if the target is carrying a metal weapon, you may attempt a free disarm combat maneuver against that weapon. This free combat maneuver doesn't provoke attacks of opportunity.</p>
<p><em>Augmented:</em> If you expend two uses of mythic power and the free grapple or disarm combat maneuver is successful, the target is staggered until your next turn. This is an electricity effect.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _shocking_image = {title: "Shocking Image", jsx: <><h2 id="spell-shocking_image-shocking-image">Shocking Image</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 243</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/figment">figment</Link>) [<Link to="/spelldef/electricity">electricity</Link>]; <strong>Level</strong> arcanist 4, bloodrager 4, bard 4, mesmerist 4, occultist 4, red mantis assassin 4, skald 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> see text</p><p>This spell works like mirror image, except the illusory doubles it creates discharge an electric shock when destroyed. An opponent that uses a melee attack to destroy one of your images takes 2d6 points of electricity damage. You must overcome a target's spell resistance the first time you deal this electricity damage to it. Failure renders the target immune to damage from this spell.</p>
</>};
const _shout = {hasJL:true,title: "Shout", jsx: <><div className="jumpList" id="spell-shout-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-shout-mythic_shout">Mythic Shout</InnerLink></li><li><InnerLink toTop to="spell-shout-greater-shout">Greater Shout</InnerLink></li></ul></div><h2 id="spell-shout-shout">Shout</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 343</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/sonic">sonic</Link>]; <strong>Level</strong> arcanist 4, bloodrager 4, bard 4, magus 4, occultist 4, psychic 4, skald 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> 30 ft.<br/><strong>Area</strong> cone-shaped burst<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude partial or Reflex negates (object); see text; <strong>Spell Resistance</strong> yes (object)</p><p>You emit an ear-splitting yell that deafens and damages creatures in its path. Any creature within the area is deafened for 2d6 rounds and takes 5d6 points of sonic damage. A successful save negates the deafness and reduces the damage by half. Any exposed brittle or crystalline object or crystalline creature takes 1d6 points of sonic damage per caster level (maximum 15d6). An affected creature is allowed a Fortitude save to reduce the damage by half, and a creature holding fragile objects can negate damage to them with a successful Reflex save. A shout spell cannot penetrate a silence spell.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-shout--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-shout-mythic_shout" data-hash-target>Mythic Shout</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 108</Link></p>
<p>The duration that creatures in the area are deafened increases to 4d6 rounds, and the damage dealt increases to 5d8 points of sonic damage. The damage dealt to crystalline creatures and exposed brittle or crystalline objects increases to 1d8 points of sonic damage per caster level (maximum 15d8). Crystalline creatures reverberate with sonic energy, taking 4 points of sonic damage on your turn for a number of rounds equal to your tier.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-shout-greater-shout" data-hash-target>Greater Shout</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 343</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/sonic">sonic</Link>]; <strong>Level</strong> arcanist 8, bard 6, psychic 8, skald 6, sorcerer 8, wizard 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a metal or ivory horn)<br/><strong>Range</strong> 60 ft.<br/><strong>Area</strong> cone-shaped burst<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude partial or Reflex negates (object); see text; <strong>Spell Resistance</strong> yes (object)</p><p>This spell functions like shout, except that the cone deals 10d6 points of sonic damage (or 1d6 points of sonic damage per caster level, maximum 20d6, against exposed brittle or crystalline objects or crystalline creatures). It also causes creatures to be stunned for 1 round and deafened for 4d6 rounds. A creature in the area of the cone can negate the stunning and halve both the damage and the duration of the deafness with a successful Fortitude save. A creature holding vulnerable objects can attempt a Reflex save to negate the damage to those objects.</p>
</>};
const _shrink_item = {title: "Shrink Item", jsx: <><h2 id="spell-shrink_item-shrink-item">Shrink Item</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 342</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, occultist 3, psychic 3, red mantis assassin 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> one touched object of up to 2 cu. ft./level<br/><strong>Duration</strong> 1 day/level; see text<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>You are able to shrink one nonmagical item (if it is within the size limit) to 1/16 of its normal size in each dimension (to about 1/4,000 the original volume and mass). This change effectively reduces the object's size by four categories. Optionally, you can also change its now shrunken composition to a cloth-like one. Objects changed by a shrink item spell can be returned to normal composition and size merely by tossing them onto any solid surface or by a word of command from the original caster. Even a burning fire and its fuel can be shrunk by this spell. Restoring the shrunken object to its normal size and composition ends the spell.</p>
<p>Shrink item can be made permanent with a <Link to="/spell/permanency">permanency</Link> spell, in which case the affected object can be shrunk and expanded an indefinite number of times, but only by the original caster.</p>
</>};
const _shroud_of_darkness = {title: "Shroud of Darkness", jsx: <><h2 id="spell-shroud_of_darkness-shroud-of-darkness">Shroud of Darkness</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 13</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/darkness">darkness</Link>]; <strong>Level</strong> antipaladin 4, arcanist 5, bard 5, cleric 5, inquisitor 5, mesmerist 4, oracle 5, shaman 5, skald 5, sorcerer 5, warpriest 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a pinch of black sand)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Targets</strong> one creature/3 levels, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>With a dark incantation and a gesture of your hand over your eyes, you cause a shroud of darkness to descend upon the targets of this spell. The subjects treat the light level as two steps lower than normal for the duration of this spell. Bright light becomes dim light, normal light becomes darkness, and areas of dim light and darkness become supernaturally dark (as darkness, but even creatures with darkvision cannot see).</p>
</>};
const _shroud_of_innocuity = {title: "Shroud of Innocuity", jsx: <><h2 id="spell-shroud_of_innocuity-shroud-of-innocuity">Shroud of Innocuity</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court pg. 10</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> arcanist 3, bard 3, medium 3, mesmerist 3, psychic 3, shaman 3, skald 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one willing creature plus one/2 caster levels, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> none (harmless); see text; <strong>Spell Resistance</strong> no</p><p>All affected creatures are veiled with a commonplace appearance. This appearance varies based on the viewer, but is always an ordinary member of that viewer's race, ethnicity, or nationality. This familiarity grants a +2 bonus on Diplomacy checks attempted by affected targets against those not affected by the spell.</p>
<p>Creatures with an attitude of unfriendly or hostile toward an affected target can attempt a Will save to disbelieve the effect the first time they encounter that target.</p>
</>};
const _sickening_strikes = {title: "Sickening Strikes", jsx: <><h2 id="spell-sickening_strikes-sickening-strikes">Sickening Strikes</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 155</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/disease">disease</Link>]; <strong>Level</strong> alchemist 2, antipaladin 2, druid 2, hunter 2, investigator 2, magus 3, ranger 4, witch 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Fortitude negates, see text; <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em><Link to="/race/ratfolk">Ratfolk</Link> have access to the following spell.</em></p>
</blockquote>
<p>You are imbued with disease, and any creature you strike with a melee attack must make a Fortitude save or be sickened for 1 minute. Creatures that are immune to disease are immune to this sickened effect.</p>
</>};
const _siege_of_trees = {title: "Siege of Trees", jsx: <><h2 id="spell-siege_of_trees-siege-of-trees">Siege of Trees</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 244</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> druid 7<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one Large plant per three caster levels<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You imbue inanimate plants with limited mobility and a semblance of life. Each plant targeted acts as a <Link to="/eq-siegeengine/light_catapult">light catapult</Link> until the end of the spell's duration, though you must spend a standard action to aim each of these tree catapults before the first time they fire, and anytime thereafter when you want the trees to fire at a new target. The catapult uses your caster level as its targeting bonus. With a free action, you can command one or all of the trees under your command to stop firing. You do not need to supply ammunition to these tree catapults; they will automatically load themselves with rocks and boulders in the area, digging them deep from the ground if need be. You can supply the trees ammunition if you desire. The tree will not load flaming ammunition, and these catapult trees cannot be affected by energy siege shot if the energy selected is fire.</p>
<h3 id="spell-siege_of_trees-greater-siege-of-trees">Greater Siege of Trees</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 244</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> druid 9<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one Gargantuan, Huge, or Large plant per three caster levels<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>As siege of trees, but you can affect larger-sized plants. Each plant acts as a catapult of its size.</p>
</>};
const _siege_scatter = {title: "Siege Scatter", jsx: <><h2 id="spell-siege_scatter-siege-scatter">Siege Scatter</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 223</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> druid 5, hunter 4, ranger 4, shaman 5<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Area</strong> 50-ft.-radius spread<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex partial (see text); <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em>The following spell is available to the indicated race or ethnicity: <Link to="/race/dwarf">Dwarf</Link></em></p>
</blockquote>
<p>A roiling blast of rough rock and dirt scatters along the ground in the area, dealing 1d6 points of slashing damage per 2 caster levels (maximum 5d6) to all creatures on the ground in the area, even on a successful saving throw. Creatures in the area that fail the Reflex save fall prone and are knocked to the nearest edge of the area, taking 1d6 points of bludgeoning damage for every 10 feet they travel this way. Creatures that did not move during the past round and those with the stability racial trait gain a +4 bonus on the saving throw.</p>
</>};
const _sift = {title: "Sift", jsx: <><h2 id="spell-sift-sift">Sift</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 244</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> bard 0, inquisitor 0, medium 0, occultist 0, psychic 0, skald 0<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 30 ft.<br/><strong>Area</strong> one 10-ft. cube<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You examine an area at range as if you were searching for fine details with the Perception skill. Make a Perception check with a -5 penalty, modified as normal for conditions. No penalty is applied for distance. Apply the result against the DC for any hidden features, such as secret doors, traps, or hidden treasure. You must be able to see the area you are attempting to search, and you only find details that can be perceived with sight or touch. Sift detects only objects and features, not actual creatures.</p>
</>};
const _sign_of_the_dawnflower = {title: "Sign of the Dawnflower", jsx: <><h2 id="spell-sign_of_the_dawnflower-sign-of-the-dawnflower">Sign of the Dawnflower</h2>
<p><strong>Sources</strong> <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> cleric 0, druid 0, hunter 0, oracle 0, paladin 1, ranger 1, warpriest 0 (Sarenrae; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S, F (your holy symbol, or a depiction of either Sarenrae's holy symbol or the goddess herself)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature/level<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>As message, except the only information you can transmit is that you are a worshiper of Sarenrae. Once notified, the target can reply that he understands your sign. The spell transmits meaning, not sound, and transcends language barriers.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _sign_of_wrath = {title: "Sign of Wrath", jsx: <><h2 id="spell-sign_of_wrath-sign-of-wrath">Sign of Wrath</h2>
<p><strong>Sources</strong> <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 419</Link>, <Link to="/source/pathfinder_5_sins_of_the_saviors">Pathfinder #5: Sins of the Saviors pg. 63</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> arcanist 6, cleric 6, oracle 6, sorcerer 6, warpriest 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a gem worth 1,000 gp inscribed with the Thassilonian symbol of wrath)<br/><strong>Range</strong> personal<br/><strong>Area</strong> 25-ft.-radius burst centered on you<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><p>A giant, glowing symbol of wrath appears below you, forcibly repulsing all nearby creatures. All creatures within the area of effect take 1d6 points of force damage per caster level (maximum 15d6) and are subjected to a bull rush that attempts to push them directly away from you. The blast's bull rush effect has a CMB bonus equal to your caster level + your Intelligence, Wisdom, or Charisma modifier (whichever is highest). You are unaffected by both the spell's damage and its bull rush effect, and may select up to one creature per 4 caster levels to also be ignored by the spells effects.</p>
</>};
const _signifers_rally = {title: "Signifer's Rally", jsx: <><h2 id="spell-signifers_rally-signifers-rally">Signifer's Rally</h2>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils pg. 23</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/teleportation">teleportation</Link>) [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> arcanist 7, cleric 7, oracle 7, sorcerer 7, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (100 gp worth of bloodstone for every ally teleported)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one willing ally/5 levels<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You teleport up to one ally per five caster levels to your location. You determine which allies you want to teleport at the time of casting; these allies have 1 round to decide to allow or refuse your spell, and they teleport immediately upon accepting. Allies are teleported as if you had cast teleport on them (your current location is at least "studied carefully" for this purpose), appearing in a puff of brimstone in a space adjacent to you. If you are in combat and your allies were not, your allies may roll initiative upon arrival but are not considered flat-footed even though they have not taken any actions. The spell does not function in areas warded against intrusion by evil creatures (such as a <Link to="/spell/magic_circle_against_evil">magic circle against evil</Link> effect).</p>
</>};
const _silence = {title: "Silence", jsx: <><h2 id="spell-silence-silence">Silence</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 343</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> antipaladin 2, bard 2, cleric 2, inquisitor 2, mesmerist 2, oracle 2, psychic 2, skald 2, warpriest 2<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Area</strong> 20-ft.-radius emanation centered on a creature, object, or point in space<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates; see text or none (object); <strong>Spell Resistance</strong> yes; see text or no (object)</p><p>Upon the casting of this spell, complete silence prevails in the affected area. All sound is stopped: Conversation is impossible, spells with verbal components cannot be cast, and no noise whatsoever issues from, enters, or passes through the area. The spell can be cast on a point in space, but the effect is stationary unless cast on a mobile object. The spell can be centered on a creature, and the effect then radiates from the creature and moves as it moves. An unwilling creature can attempt a Will save to negate the spell and can use spell resistance, if any. Items in a creature's possession or magic items that emit sound receive the benefits of saves and spell resistance, but unattended objects and points in space do not. Creatures in an area of a silence spell are immune to sonic or language-based attacks, spells, and effects.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-silence--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Silence</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 108</Link><br/>This spell also applies to telepathy, cutting off any mental communication within the area. At the time of casting, you can choose to be immune to your own mythic silence effect and can designate up to one creature per tier to also gain this immunity. Creatures immune to the mythic silence are subject to sonic effects as normal.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _silent_image = {title: "Silent Image", jsx: <><h2 id="spell-silent_image-silent-image">Silent Image</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 343</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/figment">figment</Link>); <strong>Level</strong> arcanist 1, bard 1, magus 1, medium 1, mesmerist 1, occultist 1, psychic 1, red mantis assassin 1, skald 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a bit of fleece)<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Effect</strong> visual figment that cannot extend beyond four 10-ft. cubes + one 10-ft. cube/level (S)<br/><strong>Duration</strong> concentration<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); <strong>Spell Resistance</strong> no</p><p>This spell creates the visual illusion of an object, creature, or force, as visualized by you. The illusion does not create sound, smell, texture, or temperature. You can move the image within the limits of the size of the effect.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-silent_image--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Silent Image</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 108</Link><br/>The duration increases to concentration + 1 round per caster level, and the effect increases to a visual figment that can't extend beyond eight 10-foot cubes + 1 10-foot cube per caster level.</p>
<p><em>Augmented (6th):</em> If you expend two uses of mythic power, the duration changes to concentration + 1 minute per caster level and the effect changes to a visual figment no larger than a 50-foot emanation. An augmented mythic silent image can't move.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _silent_table = {title: "Silent Table", jsx: <><h2 id="spell-silent_table-silent-table">Silent Table</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 192</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> arcanist 2, bard 2, cleric 2, mesmerist 2, oracle 2, psychic 2, red mantis assassin 2, skald 2, sorcerer 2, warpriest 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> 5-ft.-diameter emanation centered on an object or a point in space<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong>  (object); <strong>Spell Resistance</strong> no (object)</p><p>You protect an area against casual eavesdropping. Sounds and sonic effects that originate inside the area are muffled for anyone outside the area; Perception DCs to hear or understand sounds leaving the area increase by 20, and any saving throw DCs of these effects decrease by 2. The spell does not affect sounds that enter the area or the Perception checks of creatures inside it.</p>
</>};
const _silk_to_steel = {title: "Silk To Steel", jsx: <><h2 id="spell-silk_to_steel-silk-to-steel">Silk To Steel</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 238</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, bard 2, occultist 2, red mantis assassin 2, skald 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> one scarf<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You imbue an ordinary scarf (or similar piece of clothing) with the strength of steel without altering its weight or flexibility. Each round on your turn, you can decide to use the scarf to defend yourself (gaining a +2 shield bonus to your Armor Class) or to attack as if the scarf were a whip.</p>
</>};
const _silt_sphere = {title: "Silt Sphere", jsx: <><h2 id="spell-silt_sphere-silt-sphere">Silt Sphere</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_sea">Blood of the Sea pg. 21</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> arcanist 3, bard 3, skald 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a smooth stone)<br/><strong>Range</strong> 20 ft.<br/><strong>Effect</strong> 20-ft.-radius centered on you<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell generates an illusory silt cloud that drifts around you and moves with you. The cloud provides total <Link to="/rule/concealment">concealment</Link> to creatures within it (including you) when the spell is cast. Creatures moving into the cloud after the spell is cast gain concealment (but not total concealment) due to the illusion. Any creatures within the cloud can see each other normally and can see out from within the cloud as though it were transparent. If a creature other than you that has total concealment due to the cloud makes an attack against any foe, it loses total concealment and gains concealment instead. If you make an attack against any creature, the spell ends.</p>
<p>A creature that examines the cloud from the outside and succeeds at a DC 20 Knowledge (nature) check notices the silt cloud is unnaturally compact and fast moving, and that creature can attempt an immediate saving throw to disbelieve the illusion. Other circumstances (such as if the silt cloud floats in the middle of otherwise clear waters) can modify the DC of the Knowledge (nature) check.</p>
<p>This spell can be cast only underwater.</p>
</>};
const _silver_darts = {title: "Silver Darts", jsx: <><h2 id="spell-silver_darts-silver-darts">Silver Darts</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 192</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> arcanist 3, bloodrager 3, magus 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a silver needle)<br/><strong>Range</strong> 15 ft.<br/><strong>Area</strong> cone-shaped burst<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><p>A cone of silver darts springs from your hand. These darts act as a silver weapon that deals 1d6 points of piercing damage per caster level (maximum 10d6). Any creature with an armor bonus greater than +4 or a natural armor bonus greater than +4 takes 50% less damage.</p>
</>};
const _silverlight = {title: "Silverlight", jsx: <><h2 id="spell-silverlight-silverlight">Silverlight</h2>
<p><strong>Sources</strong> <Link to="/source/guide_to_the_river_kingdoms">Guide to the River Kingdoms pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/light">light</Link>]; <strong>Level</strong> arcanist 3, bard 3, cleric 3, druid 3, hunter 3, oracle 3, paladin 3, skald 3, sorcerer 3, warpriest 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (1 sp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> object touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude partial (see text); <strong>Spell Resistance</strong> no</p><p>As <Link to="/spell/daylight">daylight</Link>, except the object touched sheds bright silvery light in a 20-foot radius. In addition to providing illumination, the area of bright light is painful to creatures that are susceptible to alchemical silver. A creature with DR/silver that begins its turn within the light of this spell is automatically dazzled and becomes sickened unless it succeeds on a Fortitude save. These effects disappear 1 round after the target leaves the silverlight. A creature that leaves the area and then returns must make a new saving throw. This spell provides dim light up to 40 feet away, but only creatures within 20 feet are subject to the above effects.</p>
</>};
const _simulacrum = {title: "Simulacrum", jsx: <><h2 id="spell-simulacrum-simulacrum">Simulacrum</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 343</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>); <strong>Level</strong> arcanist 7, psychic 7, sorcerer 7, summoner 5, wizard 7<br/><strong>Casting Time</strong> 12 hours<br/><strong>Components</strong> V, S, M (ice sculpture of the target plus powdered rubies worth 500 gp per HD of the simulacrum)<br/><strong>Range</strong> 0 ft.<br/><strong>Effect</strong> one duplicate creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>Simulacrum creates an illusory duplicate of any creature. The duplicate creature is partially real and formed from ice or snow. It appears to be the same as the original, but it has only half of the real creature's levels or HD (and the appropriate hit points, feats, skill ranks, and special abilities for a creature of that level or HD). You can't create a simulacrum of a creature whose HD or levels exceed twice your caster level. You must make a Disguise check when you cast the spell to determine how good the likeness is. A creature familiar with the original might detect the ruse with a successful Perception check (opposed by the caster's Disguise check) or a DC 20 Sense Motive check.</p>
<p>At all times, the simulacrum remains under your absolute command. No special telepathic link exists, so command must be exercised in some other manner. A simulacrum has no ability to become more powerful. It cannot increase its level or abilities. If reduced to 0 hit points or otherwise destroyed, it reverts to snow and melts instantly into nothingness. A complex process requiring at least 24 hours, 100 gp per hit point, and a fully equipped magical laboratory can repair damage to a simulacrum.</p>
<h3 id="spell-simulacrum-lesser-simulacrum">Lesser Simulacrum</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 238</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>); <strong>Level</strong> arcanist 4, psychic 4, red mantis assassin 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 hour<br/><strong>Components</strong> V, S, M (an ice sculpture of the target plus powdered rubies worth 50 gp per HD of the simulacrum)<br/><strong>Range</strong> 0 ft.<br/><strong>Effect</strong> one duplicate creature<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell functions as simulacrum, except you can't create a simulacrum of a creature whose HD or levels exceed your caster level, and it has no magical abilities. The creature is not under your control, though it recognizes you are its creator.</p>
</>};
const _siphon_magic = {title: "Siphon Magic", jsx: <><h2 id="spell-siphon_magic-siphon-magic">Siphon Magic</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_magic">Inner Sea Magic pg. 60</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 5, cleric 5, oracle 5, sorcerer 5, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a coiled length of copper wire wrapped around the palm)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell attempts to transfer a magical effect from a creature you touch to yourself. When you touch the creature, siphon magic attempts to end one ongoing spell that has been cast on that creature, as if via a targeted <Link to="/spell/dispel_magic">dispel magic</Link>. If you know the specific spell effect you wish to target, you can name that spell effect to target that specific spell; otherwise siphon magic begins with the highest-level spell in effect and works its way down through all spells affecting the target until it dispels one or runs out of effects, as per <em>dispel magic.</em></p>
<p>If siphon magic successfully ends a spell effect on the target, the remaining duration of that spell effect is transferred to you. That spell effect plays out for the rest of its duration as if you had been the original target. If the spell allows a saving throw to resist the effect, you gain a saving throw as if the spell were just being cast upon you, although this does not "reset" the spell's duration.</p>
</>};
const _siphon_might = {title: "Siphon Might", jsx: <><h2 id="spell-siphon_might-siphon-might">Siphon Might</h2>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 27</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 3, druid 3, hunter 3, magus 3, sorcerer 3, summoner 3, unchained summoner 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Fortitude half; <strong>Spell Resistance</strong> yes</p><p>You drain the might of the target and transfer that power to another creature. The subject takes a penalty to Strength equal to 1d6 + 1 per 2 caster levels (maximum 1d6 + 5). This effect can't cause the subject's Strength score to drop below 1. A successful Fortitude save halves this penalty. This penalty doesn't stack with itself or the penalty applied from ray of enfeeblement.</p>
<p>You can grant any one creature adjacent to you (including yourself) an enhancement bonus to Strength equal to the Strength penalty imposed by this spell.</p>
</>};
const _sirocco = {title: "Sirocco", jsx: <><h2 id="spell-sirocco-sirocco">Sirocco</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 244</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/air">air</Link>, <Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> arcanist 6, druid 6, hunter 6, magus 6, occultist 6, sorcerer 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (handful of fine sand cast into the air)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> cylinder (20-ft. radius, 60 ft. high)<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Fortitude partial, see text; <strong>Spell Resistance</strong> yes</p><p>A blast of furnace-hot wind blasts downward, inflicting 4d6 fire damage +1 point per caster level to all creatures in the area and knocking them prone. A successful Fortitude save halves the fire damage and negates being knocked prone. Flying creatures forced into the ground by the powerful downdraft take damage as if they fell unless they make a DC 15 Fly check, in which case they remain at their original altitude. Any creature that takes damage from a sirocco becomes fatigued (or exhausted, if already fatigued, such as from a previous round of exposure to a sirocco spell). Creatures with the water subtype take a -4 penalty on all saving throws against this spell and take double normal damage.</p>
</>};
const _skeleton_crew = {title: "Skeleton Crew", jsx: <><h2 id="spell-skeleton_crew-skeleton-crew">Skeleton Crew</h2>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 4, cleric 3, oracle 3, sorcerer 4, summoner 4, unchained summoner 4, warpriest 3, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M<br/><strong>Range</strong> touch<br/><strong>Targets</strong> one or more humanoid corpses touched<br/><strong>Duration</strong> 1 day/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell turns corpses into skeletons that act as crew and obey your commands to the extent of their abilities.</p>
<p>The undead you create are 1 Hit Die skeletons that possess Profession (sailor) scores equal to half your character level plus your Wisdom modifier (for clerics), Intelligence modifier (for witches and wizards), or Charisma modifier (for sorcerers and summoners). Each skeleton can perform the duties of one crew member but has no other abilities. The created skeletons cannot speak, attack, or even defend themselves. The only orders they obey are ones pertaining to the operation of a ship. Skeletal crew members are not proficient with any weapons or armor.</p>
<p>You can't create more Hit Dice of skeletal crew members than twice your caster level with a single casting of skeleton crew. The desecrate spell doubles this limit.</p>
<p>The undead you create by casting skeleton crew remain under your control for the duration of the spell, and do not count against your limit of total Hit Dice worth of undead creatures you can control.</p>
<p>A skeletal crew member can only be created from a mostly intact humanoid corpse. The corpse must have bones. When you cast this spell, any flesh left on the corpses melts away into fog.</p>
</>};
const _skim = {title: "Skim", jsx: <><h2 id="spell-skim-skim">Skim</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 19</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> alchemist 1, arcanist 1, bard 1, cleric 1, inquisitor 1, investigator 1, magus 1, occultist 1, oracle 1, psychic 1, shaman 1, skald 1, sorcerer 1, warpriest 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a dog-eared page)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 hour/level</p><p>This spell allows you to read written material in a quarter of the time it would normally take to read it. If you use this spell in conjunction with comprehend languages, you can read otherwise incomprehensible text four times faster than the spell indicates. If the text is fragmented, is particularly difficult to understand, or otherwise requires an ability check or skill check (such as a Linguistics check) to read quickly or at all, this spell doesn't directly increase your reading speed, but instead grants you a +8 bonus on the check. This bonus also applies to Research checks when you research a particular topic within a library.</p>
</>};
const _skin_tag = {title: "Skin Tag", jsx: <><h2 id="spell-skin_tag-skin-tag">Skin Tag</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/fear">fear</Link>, <Link to="/spelldef/haunted">haunted</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> alchemist 1, arcanist 1, medium 1, occultist 1, shaman 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S, M (beverage or food item, plus special reagents worth 25 gp)<br/><strong>Range</strong> touch (object); 1 mile (remote effects)<br/><strong>Target</strong> 1 beverage or piece of food touched<br/><strong>Duration</strong> 1 day plus 1 day/level<br/><strong>Saving Throw</strong> none (object), Fortitude negates; see text; <strong>Spell Resistance</strong> no (object), yes (creature)</p><p>You mix a malign spirit into a piece of food, a drink, or some other item to be consumed (including alchemical items, potions, elixirs, or similar items). The skin tag spell discharges when the item is consumed, affecting the creature that used the item unless it succeeds at a Fortitude save. The spirit embeds itself somewhere in the affected creature's skin, forming a painless set of wrinkles and tags of skin that looks vaguely like a face when the haunt activates. You are considered to have a body part from the affected creature for the purpose of scrying and similar divination spells. Once per day as a standard action, you can remotely cause the spirit to make the affected creature's skin crawl, causing the creature to become sickened for 1d4 rounds + 1 round per 2 caster levels you have (to a maximum of 5 extra rounds at 10th level) unless it succeeds at a Fortitude save. Alternatively, once per day you can remotely use a hex, a mind-affecting spell, or a necromancy spell that causes disease or possession on the affected creature. Each time you use the remote sickening or spell or hex effect, the spell's haunt-like manifestation occurs during that round.</p>
<h4 id="spell-skin_tag-haunt-statistics">Haunt Statistics</h4>
<div className="sideNoteWrap"><ScrollContainer id="spell-skin_tag--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to taste a hint of rot) or DC 25 (if the affected creature is wearing armor or heavy clothing)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>5</td></tr><tr><th id="spell-skin_tag--haunt-trigger" colSpan={2}>Trigger</th><td headers="spell-skin_tag--haunt-trigger">conditional (using the item or the spell's remote effects)</td><th id="spell-skin_tag--haunt-reset">Reset</th><td headers="spell-skin_tag--haunt-reset">none</td></tr></tbody></table></ScrollContainer></div></>};
const _skinsend = {title: "Skinsend", jsx: <><h2 id="spell-skinsend-skinsend">Skinsend</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 238</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> alchemist 2, arcanist 2, investigator 2, occultist 2, psychic 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 hour/level (D)</p><p>You cause your own skin to peel off your body and animate as a magical creature you control. You may project your consciousness to your animated skin or return it to your actual body as a standard action. When your consciousness is in your body, you are helpless (except for transferring your will to your skin, or dismissing the spell).</p>
<p>Your possessed skin is identical to you in all ways, except the following: It has only half the number of hit points you had at the time you cast the spell, and cannot be healed above this maximum; construct type, traits, and immunities; Str 3, Con -; DR 10/piercing or slashing; and <Link to="/umr/compression">compression</Link>. Your skin can take any actions you could normally take in your own body (such as to fight or cast spells).</p>
<p>When your skin leaves your body, your body's hit points drop to 0. Your body cannot heal damage naturally while you have no skin, nor do spells that cure hit point damage work on your body; only regeneration (from a <Link to="/spell/regenerate">regenerate</Link> spell, <Link to="/magic-ring/ring_of_regeneration">ring of regeneration</Link>, the <Link to="/umr/regeneration">regeneration</Link> monster ability, or any other effect that can regrow missing limbs) or heal can regrow your skin and allow you heal above 0 hit points.</p>
<p>If your body is regenerated before your skin returns to it, the skin dies and your consciousness returns automatically to your body. Your skin can be preserved with <Link to="/spell/gentle_repose">gentle repose</Link> and is suitable for any purpose that requires some of your flesh (such as a <Link to="/spell/resurrection">resurrection</Link> spell) or any magic or ritual that requires a creature's skin.</p>
<p>When your skin returns to your body, you regain hit points equal to your skin's remaining hit points. If the spell ends before you reunite with your skin or if your skin is killed while you are in your body, you remain helpless and at 0 hit points until your full body is restored to you (requiring powerful magic, as described above). If your body dies while you are possessing your skin, you die when the spell ends, regardless of how many hit points the skin has left. If your body or skin is slain with your consciousness in it, the spell ends and you are instantly killed.</p>
<p>This spell leaves long scars on your skin where it split apart, although these fade normally with the use of healing magic.</p>
</>};
const _sky_steed = {title: "Sky Steed", jsx: <><h2 id="spell-sky_steed-sky-steed">Sky Steed</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 235</Link>, <Link to="/source/animal_archive">Animal Archive pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> paladin 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> a creature you are mounted upon<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The target sprouts angelic wings and gains a fly speed equal to its base speed with average maneuverability. It also gains a bonus on Fly checks equal to your caster level.</p>
</>};
const _sky_swim = {title: "Sky Swim", jsx: <><h2 id="spell-sky_swim-sky-swim">Sky Swim</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 241</Link>, <Link to="/source/faiths_of_balance">Faiths of Balance pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/air">air</Link>]; <strong>Level</strong> bloodrager 3, cleric 3, druid 3, hunter 3, oracle 3, shaman 3, warpriest 3, witch 3 (Gozreh; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> Large or smaller creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong>  (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell grants the target the ability to swim through the air. If the target has a swim speed, it can move through the air at that speed. Otherwise, it must succeed at Swim checks to move as normal. Still air is treated as calm water, light or moderate wind is treated as rough water, strong or severe wind is treated as stormy water, and the target cannot swim through stronger winds. This spell does not grant the ability to breathe air to creatures that normally can't.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _skyshroud = {title: "Skyshroud", jsx: <><h2 id="spell-skyshroud-skyshroud">Skyshroud</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 9</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> (<Link to="/spelldef/scrying">scrying</Link>); <strong>Level</strong> arcanist 3, bard 3, cleric 3, oracle 3, skald 3, sorcerer 3, warpriest 3, wizard 3<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S, F (a jar of earth from the surface)<br/><strong>Range</strong> long (400 ft. + 40 ft./level); see text<br/><strong>Effect</strong> hemisphere that cannot extend beyond four 10-ft. cubes + one 10-ft. cube/level (S)<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>The caster designates the area of a hemisphere within the spell's range. If a solid object would block the creation of the hemisphere (such as a ceiling or wall), the spell instead conforms to the geometry of the location up to the maximum area of effect for the spell. The hemisphere displays an image of the sky as it appears directly above where the spell was cast. This effect bypasses natural impediments, such as rock or stone, that would obstruct the targeted location from the sky.</p>
<p>The image of the sky created by this spell counts as the actual sky for purposes of effects that require view of the sky, sun, stars, or other features (including for spell preparation or deific obediences). It does not enable spells or effects that draw effects from the sky (such as call lightning).</p>
<p>Light created by this effect functions normally and harms creatures vulnerable to bright light or direct sunlight.</p>
</>};
const _slave_to_sin = {title: "Slave to Sin", jsx: <><h2 id="spell-slave_to_sin-slave-to-sin">Slave to Sin</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 61</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 3, bard 2, cleric 3, inquisitor 3, mesmerist 2, oracle 3, paladin 2, skald 2, sorcerer 3, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a scrap of paper inscribed with the Sihedron rune)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates (see below); <strong>Spell Resistance</strong> yes</p><p>This spell allows you to reach into an evil creature's mind to expose and exploit its susceptibility to whichever of the seven so-called "deadly sins" it is most susceptible to. The targeted creature must succeed at a Will save or it is overwhelmed with an inability to repress urges to indulge in whatever sin most closely mirrors its personality, and a glowing rune appears upon the creature's body (usually the brow), identifying the sin. (The GM adjudicates which rune manifests on the creature's body, as appropriate.)</p>
<p>Each round, at the start of its turn, the target must attempt a new Will saving throw against the spell's DC to resist the sin's enslavement. If the target succeeds at this saving throw, it is sickened for that round by the distractions of its sin. If it fails, it is sickened and staggered as it spends part of its action wallowing in its targeted sin (a wrathful victim might waste time spouting threats and profanity, while a slothful victim might merely be slow and hesitant, and a lustful victim could well spend precious moments ogling or fawning over something of beauty).</p>
</>};
const _slay_living = {title: "Slay Living", jsx: <><h2 id="spell-slay_living-slay-living">Slay Living</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 344</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/death">death</Link>]; <strong>Level</strong> antipaladin 4, cleric 5, oracle 5, shaman 6, spiritualist 5, warpriest 5, witch 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> living creature touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude partial; <strong>Spell Resistance</strong> yes</p><p>You can attempt to slay any one living creature. When you cast this spell, your hand seethes with eerie dark fire. You must succeed on a melee touch attack to touch the target. The target takes 12d6 points of damage + 1 point per caster level. If the target's Fortitude saving throw succeeds, it instead takes 3d6 points of damage + 1 point per caster level. The subject might die from damage even if it succeeds on its saving throw.</p>
</>};
const _sleep = {title: "Sleep", jsx: <><h2 id="spell-sleep-sleep">Sleep</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 344</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> adept 1, arcanist 1, bard 1, mesmerist 1, occultist 1, psychic 1, shaman 1, skald 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (fine sand, rose petals, or a live cricket)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> one or more living creatures within a 10-ft.-radius burst<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>A sleep spell causes a magical slumber to come upon 4 HD of creatures. Creatures with the fewest HD are affected first. Among creatures with equal HD, those who are closest to the spell's point of origin are affected first. HD that are not sufficient to affect a creature are wasted. Sleeping creatures are helpless. Slapping or wounding awakens an affected creature, but normal noise does not. Awakening a creature is a standard action (an application of the aid another action). Sleep does not target unconscious creatures, constructs, or undead creatures.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-sleep--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Sleep</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 108</Link><br/>The spell affects up to 8 Hit Dice of creatures, and you can choose the order in which creatures are affected by the spell. Any effect that would automatically awaken a sleeping creature instead allows it to attempt a new Will saving throw to awaken.</p>
<p><em>Augmented (8th):</em> If you expend three uses of mythic power, you can target all living creatures other than you that have 8 Hit Dice or fewer in a 1-mile radius centered on you. Creatures that fail their saving throws fall asleep for a number of days equal to your tier. You can select a number of creatures up to your tier to not be affected by the spell.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _sleepwalk = {title: "Sleepwalk", jsx: <><h2 id="spell-sleepwalk-sleepwalk">Sleepwalk</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 244</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> inquisitor 4, mesmerist 4, psychic 4, witch 4<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (a sprig of belladonna worth 100 gp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> unconscious creature touched<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates, see text; <strong>Spell Resistance</strong> yes</p><p>You compel an unconscious or sleeping creature to rise and move in a half-awake state. The target creature staggers about if led or guided, but remains helpless for all other purposes. The subject moves at half speed and is limited to a single move action each round. It is not capable of moving at a higher rate of speed or taking actions other than movement except by magical assistance, and automatically fails any Dexterity- or Strength-based skill checks. If the creature takes any damage while sleepwalking it must make a new saving throw or the spell ends and the creature awakes (if it has more than 0 hit points). When the spell ends or is dismissed, the target remains unconscious and must be awoken normally. While sleepwalk allows an unconscious creature to move, it does not awaken the creature, nor does it stabilize or otherwise heal them. A disabled creature that moves about while under the effects of this spell does not start dying again as a result of this movement.</p>
</>};
const _sleepwalking_suggestion = {title: "Sleepwalking Suggestion", jsx: <><h2 id="spell-sleepwalking_suggestion-sleepwalking-suggestion">Sleepwalking Suggestion</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 127</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> bard 4, medium 3, mesmerist 4, psychic 5, sorcerer 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (two doses of oil of taggit worth 180 gp total)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 24 hours<br/><strong>Saving Throw</strong> Will negates or none, see text; <strong>Spell Resistance</strong> yes</p><p>You compel the target creature to rise from its sleep as if sleepwalking and perform a course of activity (limited to a sentence or two). The spell takes effect immediately if the target is already asleep, or as soon as the target falls asleep if it is conscious. You can specify that the creature should wait before taking action when you give your instructions if you so choose. A sleeping creature doesn't get a save against this spell. The suggested activity must not cause the target to directly harm itself or others, but it doesn't need to be reasonable. For example, you could instruct the target to unlock doors and windows or poison its ally's rations, but not jump off a roof or perform a <em>coup de grace</em> action against a sleeping ally. Instructions that cause direct harm prompt the target to awaken just prior to performing the action and the target experiences a vague memory of what it was supposed to do.</p>
<p>The target moves at its speed, but isn't capable of running or moving at a higher rate of speed. It moves in dark conditions as if it had darkvision and can perform most simple and skill-based actions, but it can't engage in combat, spellcasting, or actions that require significant cognitive awareness (like making complex decisions, solving puzzles, or using complicated magic items). If the creature takes any damage while sleepwalking, it must attempt a new saving throw. If it succeeds, the spell ends and the creature awakens. When the target completes the suggested course of activity, or when the spell ends or is dismissed, the target remains unconscious and returns to where it was sleeping and must be awoken normally. It retains no memory of what it did while unconscious (with the only exception described above).</p>
<p>Unlike the <Link to="/spell/sleepwalk">sleepwalk</Link> spell, attempts to use sleepwalking suggestion on a creature that is unconscious for any reason other than sleep automatically fail. A creature affected by sleepwalking suggestion is unaware it has been programmed to act in its sleep (unless awoken because it was about to cause harm).</p>
</>};
const _sleet_storm = {title: "Sleet Storm", jsx: <><h2 id="spell-sleet_storm-sleet-storm">Sleet Storm</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 344</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/cold">cold</Link>]; <strong>Level</strong> arcanist 3, bloodrager 3, druid 3, hunter 3, magus 3, shaman 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (dust and water)<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Area</strong> cylinder (40-ft. radius, 20 ft. high)<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>Driving sleet blocks all sight (even darkvision) within it and causes the ground in the area to be icy. A creature can walk within or through the area of sleet at half normal speed with a DC 10 Acrobatics check. Failure means it can't move in that round, while failure by 5 or more means it falls (see the <Link to="/skill/acrobatics">Acrobatics</Link> skill for details).</p>
<p>The sleet extinguishes torches and small fires.</p>
</>};
const _slick_walls = {title: "Slick Walls", jsx: <><h2 id="spell-slick_walls-slick-walls">Slick Walls</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> arcanist 2, bard 2, magus 2, skald 2, sorcerer 2, summoner 2, unchained summoner 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (drop of oil)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> 30-ft.-radius emanation centered on a point in space<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You coat all walls and ceilings within the spell's area with a slick substance. The DC of all Climb checks for the affected surfaces increases by twice your caster level (maximum +20). Creatures cannot take 10 on Climb checks while scaling the affected surfaces, even if they have a climb speed or other ability that would normally allow taking 10. This spell has no effect on magical walls or surfaces, such as the sides of a hole created with create pit.</p>
</>};
const _slipstream = {title: "Slipstream", jsx: <><h2 id="spell-slipstream-slipstream">Slipstream</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 244</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/water">water</Link>]; <strong>Level</strong> arcanist 2, bloodrager 2, druid 2, hunter 2, ranger 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a few drops of oil and water)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> Reflex negates (harmless); <strong>Spell Resistance</strong> no</p><p>You create a low-cresting wave of water that carries the target along the surface of water or the ground. When moving across level ground, the target's speed increases by 10 feet. If going downhill, speed increases by 20 feet instead, but slipstream provides no movement bonus when going uphill. While swimming, the slipstream increases the target's swim speed by 20 feet - if the target does not have a swim speed, this spell grants a swim speed of 20 ft.</p>
</>};
const _slough = {title: "Slough", jsx: <><h2 id="spell-slough-slough">Slough</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 128</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> arcanist 5, cleric 5, occultist 4, oracle 5, psychic 5, sorcerer 5, spiritualist 4, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a pinch of dried skin flakes)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>The target takes 1d4 points of Constitution damage each round as its skin loosens and splits. Once it has taken 5 or more points of Constitution damage in this way, its skin falls off to reveal its musculature. The creature ceases taking Constitution damage, but takes a -4 penalty on saving throws against disease, pain effects, or poison, and on Charisma-based skill checks with the exception of Intimidate and Use Magic Device. The creature's skin regrows rapidly-once its Constitution damage is fully healed, its skin becomes intact once again and the penalties end.</p>
</>};
const _slow = {title: "Slow", jsx: <><h2 id="spell-slow-slow">Slow</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 344</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, bloodrager 3, bard 3, magus 3, medium 2, occultist 3, psychic 3, red mantis assassin 3, skald 3, sorcerer 3, spiritualist 3, summoner 2, unchained summoner 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a drop of molasses)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>An affected creature moves and attacks at a drastically slowed rate. Creatures affected by this spell are staggered and can take only a single move action or standard action each turn, but not both (nor may it take full-round actions). Additionally, it takes a -1 penalty on attack rolls, AC, and Reflex saves. A slowed creature moves at half its normal speed (round down to the next 5-foot increment), which affects the creature's jumping distance as normal for decreased speed.</p>
<p>Multiple slow effects don't stack. Slow counters and dispels <Link to="/spell/haste">haste</Link>.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-slow--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Slow</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 109</Link><br/>The penalty on attack rolls, on Reflex saves, and to AC increases to -2, and affected creatures move at one-fourth speed. Select one affected creature; this creature is denied its Dexterity bonus to AC.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _slowing_mud = {title: "Slowing Mud", jsx: <><h2 id="spell-slowing_mud-slowing-mud">Slowing Mud</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 192</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> druid 4, hunter 4, shaman 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (earth and water)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 round/level (see text)<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>You coat the targets in thick, sticky mud. The mud acts as a <Link to="/spell/slow">slow</Link> spell and also blinds the targets. A creature can use a standard action to remove the mud from its eyes or the eyes of an adjacent creature, ending the blinded condition for that individual. Removing enough mud to end the slow effect is a full-round action. Jumping into a lake or being subject to an effect that creates a lot of water (such as create water or hydraulic push) removes all the mud in 1 round.</p>
<p>A haste effect cast on a creature slowed by the mud allows it to act normally for the duration of the haste. Slow does not stack with the effects of slowing mud. This spell cannot counter or dispel haste.</p>
</>};
const _smite_abomination = {title: "Smite Abomination", jsx: <><h2 id="spell-smite_abomination-smite-abomination">Smite Abomination</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 241</Link>, <Link to="/source/pathfinder_44_trial_of_the_beast">Pathfinder #44: Trial of the Beast pg. 69</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> cleric 5, inquisitor 4, oracle 5, warpriest 5 (Pharasma; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>Drawing upon positive energy, you emulate some of a paladin's power to smite undead. Choose one undead creature as your target. Your melee attacks against that target gain a bonus equal to your Charisma or Wisdom modifier, whichever is higher, on your attack rolls, and a bonus equal to your caster level on damage rolls. Your melee attacks also bypass the target's damage reduction. These bonuses do not stack with the bonuses from a paladin's smite.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _smug_narcissism = {title: "Smug Narcissism", jsx: <><h2 id="spell-smug_narcissism-smug-narcissism">Smug Narcissism</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 238</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 5, bard 3, mesmerist 3, psychic 5, skald 3, sorcerer 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a tiny shard of a mirror)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You cause your target to become overwhelmed by its own importance, talents, and attractiveness. The target cannot help but look at itself in every reflective surface at every possible opportunity. In social situations, the target always tries to comment about how attractive it is or how ugly someone else is by comparison. The target remains constantly distracted, always looking for a reflective surface to gaze upon (such as a mirror, pool of water, a polished shield, and so on). The distraction gives the target a -2 penalty on all skill checks. In combat, the target worries about enemies damaging its appearance, and focuses on defense rather than offense (casting defensive spells rather than offensive spells, using the fight defensively or total defense action, and so on).</p>
</>};
const _snake_staff = {title: "Snake Staff", jsx: <><h2 id="spell-snake_staff-snake-staff">Snake Staff</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 245</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> cleric 5, druid 5, hunter 5, oracle 5, shaman 6, warpriest 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a knife suitable for whittling)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> 1 or more pieces of wood, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>With a long hissing whisper, you transform ordinary pieces of wood into various sorts of snakes that immediately attack your foes. As long as the snakes remain within sight, you can direct their actions telepathically as a free action. You can only apply this spell to wooden objects not in a creature's possession or not part of a larger structure or plant. Each time you cast this spell you can create a number of snakes equal to your caster level. More powerful snakes take up more than one of your available total, as noted below. See Snake statistics and advanced and giant simple templates.</p>
<p><em>Venomous Snake:</em> A stick or piece of firewood. Counts as 1 snake.</p>
<p><em>Constrictor Snake:</em> A staff or tree branch. Counts as 2 snakes.</p>
<p><em>Advanced Venomous Snake:</em> A stick or piece of firewood. Counts as 2 snakes.</p>
<p><em>Advanced Constrictor Snake:</em> A staff or tree branch. Counts as 3 snakes.</p>
<p><em>Advanced Giant Venomous Snake:</em> A log or pile of debris. Counts as 4 snakes.</p>
<p><em>Advanced Giant Constrictor Snake:</em> A fallen tree or a large pile of debris. Counts as 5 snakes.</p>
</>};
const _snapdragon_fireworks = {title: "Snapdragon Fireworks", jsx: <><h2 id="spell-snapdragon_fireworks-snapdragon-fireworks">Snapdragon Fireworks</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 239</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/fire">fire</Link>, <Link to="/spelldef/light">light</Link>]; <strong>Level</strong> arcanist 1, bard 2, red mantis assassin 1, skald 2, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a bundle of sulfur wrapped in cloth)<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Effect</strong> dragon-shaped fireworks<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Reflex negates; <strong>Spell Resistance</strong> yes</p><p>A favorite display at halfling midsummer festivals, this spell lets you create fireworks in the shape of tiny dragons. Once per round, as a move action, you may designate a target 5-foot-square within range and launch a pyrotechnic in that direction. The pyrotechnic takes a zigzag path from you to that square, always missing creatures and objects in its path, and detonates in that square with a bang and a colorful burst of fire and light. Creatures in the target square take 1d4 points of fire damage and are dazzled for 1 round (Reflex half, a successful save negates the dazzled condition). Normally when this spell is used as part of a festival, the chosen target is high in the sky to increase visibility and protect observers.</p>
</>};
const _snare = {title: "Snare", jsx: <><h2 id="spell-snare-snare">Snare</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 344</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> druid 3, hunter 2, ranger 2<br/><strong>Casting Time</strong> 3 rounds<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> touched nonmagical circle of vine, rope, or thong with a 2 ft. diameter + 2 ft./level<br/><strong>Duration</strong> until triggered or broken<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell enables you to make a snare that functions as a magic trap. The snare can be made from any supple vine, a thong, or a rope. When you cast snare upon it, the cord-like object blends with its surroundings (DC 23 Perception check for a character with the trapfinding ability to locate). One end of the snare is tied in a loop that contracts around one or more of the limbs of any creature stepping inside the circle.</p>
<p>If a strong and supple tree is nearby, the snare can be fastened to it. The spell causes the tree to bend, straightening when the loop is triggered, dealing 1d6 points of damage to the creature trapped and lifting it off the ground by the trapped limb or limbs. If no such tree is available, the cord-like object tightens around the creature, dealing no damage but causing it to be entangled.</p>
<p>The snare is magical. To escape, a trapped creature must make a DC 23 Escape Artist check or a DC 23 Strength check that is a full-round action. The snare has AC 7 and 5 hit points. A successful escape from the snare breaks the loop and ends the spell.</p>
</>};
const _snow_shape = {title: "Snow Shape", jsx: <><h2 id="spell-snow_shape-snow-shape">Snow Shape</h2>
<p><strong>Sources</strong> <Link to="/source/humans_of_golarion">Humans of Golarion pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/water">water</Link>]; <strong>Level</strong> arcanist 2, cleric 2, druid 1, hunter 1, oracle 2, red mantis assassin 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a miniature shovel)<br/><strong>Range</strong> touch<br/><strong>Target</strong> snow or snow-sculpted object touched, up to 5 cubic ft. + 1 cubic ft./level<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>In frozen northern lands, where the earth may be hidden beneath heavy drifts of snow, Ulfen druids developed a variation of stone shape that other spellcasters have since learned.</p>
<p>You can form a mass of snow into any shape that suits your purpose, as per the spell stone shape. While it's possible to make crude objects with snow shape, most fine details aren't possible. However, a successful Craft (weapons) check allows you to create a bladed weapon from the snow. The DC of this check is equal to the DC listed with the Craft (weapons) skill. You must be the one to make the Craft check and must do so at the time of casting this spell. A failed check means that the spell is cast normally but the weapon created is malformed and useless. This spell can only be used to craft weapons and not more precise tools or elaborate armors.</p>
<p>Once you create the item with this spell, it solidifies into super-hard ice, gaining a hardness of 5 and 10 hit points per inch of thickness. This weapon takes double damage from fire. Anyone using an ice weapon takes a -2 penalty on attacks due to the slippery, unwieldy nature of the weapon, but the weapon deals 1 point of cold damage in addition to its normal damage. A weapon created by this spell lasts for 24 hours before melting into uselessness.</p>
</>};
const _snowball = {title: "Snowball", jsx: <><h2 id="spell-snowball-snowball">Snowball</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 235</Link>, <Link to="/source/people_of_the_north">People of the North pg. 26</Link>, <Link to="/source/pathfinder_67_the_snows_of_summer">Pathfinder #67: The Snows of Summer pg. 73</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/cold">cold</Link>, <Link to="/spelldef/water">water</Link>]; <strong>Level</strong> arcanist 1, bloodrager 1, druid 1, hunter 1, magus 1, sorcerer 1, summoner 1, unchained summoner 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> one ball of ice and snow<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>You throw a ball of elemental ice and snow at a single target as a ranged touch attack. The snowball deals 1d6 points of cold damage per caster level you have (maximum 5d6).</p>
</>};
const _soften_earth_and_stone = {title: "Soften Earth and Stone", jsx: <><h2 id="spell-soften_earth_and_stone-soften-earth-and-stone">Soften Earth and Stone</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 345</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> druid 2, hunter 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> 10-ft. square/level; see text<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>When this spell is cast, all natural, undressed earth or stone in the spell's area is softened. Wet earth becomes thick mud, dry earth becomes loose sand or dirt, and stone becomes soft clay that is easily molded or chopped. You affect a 10-foot square area to a depth of 1 to 4 feet, depending on the toughness or resilience of the ground at that spot. Magical, enchanted, dressed, or worked stone cannot be affected. Earth or stone creatures are not affected.</p>
<p>A creature in mud must succeed on a Reflex save or be caught for 1d2 rounds and unable to move, attack, or cast spells. A creature that succeeds on its save can move through the mud at half speed, and it can't run or charge. Loose dirt is not as troublesome as mud, but all creatures in the area can move at only half their normal speed and can't run or charge over the surface. Stone softened into clay does not hinder movement, but it does allow characters to cut, shape, or excavate areas they may not have been able to affect before.</p>
<p>While this spell does not affect dressed or worked stone, cavern ceilings or vertical surfaces such as cliff faces can be affected. Usually, this causes a moderate collapse or landslide as the loosened material peels away from the face of the wall or roof and falls (treat as a cave-in with no bury zone, see Environment).</p>
<p>A moderate amount of structural damage can be dealt to a manufactured structure by softening the ground beneath it, causing it to settle. However, most well-built structures will only be damaged by this spell, not destroyed.</p>
</>};
const _solid_fog = {title: "Solid Fog", jsx: <><h2 id="spell-solid_fog-solid-fog">Solid Fog</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 345</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> arcanist 4, magus 4, mesmerist 4, shaman 4, sorcerer 4, spiritualist 4, unchained summoner 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (powdered peas and an animal hoof)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> fog spreads in 20-ft. radius<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell functions like fog cloud, but in addition to obscuring sight, the solid fog is so thick that it impedes movement. Creatures moving through a solid fog move at half their normal speed and take a -2 penalty on all melee attack and melee damage rolls. The vapors prevent effective ranged weapon attacks (except for magic rays and the like). A creature or object that falls into solid fog is slowed so that each 10 feet of vapor that it passes through reduces the falling damage by 1d6. A creature cannot take a 5-foot-step while in solid fog. Solid fog, and effects that work like solid fog, do not stack with each other in terms of slowed movement and attack penalties.</p>
<p>Unlike normal fog, only a severe wind (31+ mph) disperses these vapors, and it does so in 1 round.</p>
<p>Solid fog can be made permanent with a <Link to="/spell/permanency">permanency</Link> spell. A permanent solid fog dispersed by wind reforms in 10 minutes.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-solid_fog--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Solid Fog</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 109</Link><br/>The penalty on melee attack and damage rolls increases to -4. The cloud's radius and height both increase to 50 feet.</p>
<p><em>Augmented:</em> The augmented version of mythic solid fog has the same additional benefits as the augmented version of mythic fog cloud.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _solid_note = {title: "Solid Note", jsx: <><h2 id="spell-solid_note-solid-note">Solid Note</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 245</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> bard 1, skald 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> one solidified musical note<br/><strong>Duration</strong> concentration+ 1 round/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You give temporary physical form to a single musical note and can hang it, suspended, wherever you wish within range, allowing you to use it as hook, pulley, door blocker, or anything else your imagination desires. The exact appearance of the solid note depends on your melody. You can make it spiked or smooth, simple or convoluted, and with any color pattern you wish, however, it always has a size approximately equal to that of your outstretched hand. Once created, the solid note resists all attempts to move it but instantly disappears if enough force or weight is brought to bear against it. The note has an effective Strength equal to 10 + your caster level. It cannot hold more weight than the equivalent of a heavy load for its Strength without disappearing. Any creature that wins an opposed Strength check against the note (by pushing open a door which the note is holding shut for example) also causes it to disappear. The note can never deal actual harm to a creature and disappears if successfully attacked (AC 10 + your Charisma modifier) or overcome with a combat maneuver such as bull rush (CMD 2 + your base attack bonus + your Charisma modifier). Any creature obstructed by the solid note simply fails to budge it and loses that action for the round.</p>
</>};
const _solidify_earth = {title: "Solidify Earth", jsx: <><h2 id="spell-solidify_earth-solidify-earth">Solidify Earth</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> arcanist 2, cleric 2, druid 2, hunter 2, oracle 2, shaman 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> up to two 10-foot cubes per level (S)<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Reflex negates (see text); <strong>Spell Resistance</strong> no</p><p>Stone, dirt, and other types of earth within the area become more tightly packed. Burrowing creature (including those using earth glide) treat the area as difficult terrain. Any creature that begins its turn burrowing in the affected area becomes entangled for 1 round (Reflex negates). Tremorsense and similar senses are ineffective within the affected area. Creatures with the earth mastery special ability (such as earth elementals) double their bonus on attack and damage rolls so long as both they and their targets are touching the area affected by this spell.</p>
</>};
const _song_of_discord = {title: "Song of Discord", jsx: <><h2 id="spell-song_of_discord-song-of-discord">Song of Discord</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 345</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>, <Link to="/spelldef/sonic">sonic</Link>]; <strong>Level</strong> bard 5, psychic 5, skald 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> creatures within a 20-ft.-radius spread<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell causes those within the area to turn on each other rather than attack their foes. Each affected creature has a 50% chance to attack the nearest target each round. (Roll to determine each creature's behavior every round at the beginning of its turn.) A creature that does not attack its nearest neighbor is free to act normally for that round. Creatures forced by a song of discord to attack their fellows employ all methods at their disposal, choosing their deadliest spells and most advantageous combat tactics. They do not, however, harm targets that have fallen unconscious.</p>
<h3 id="spell-song_of_discord-greater-song-of-discord">Greater Song of Discord</h3>
<p><strong>Sources</strong> <Link to="/source/chronicle_of_legends">Chronicle of Legends pg. 14</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>, <Link to="/spelldef/sonic">sonic</Link>]; <strong>Level</strong> bard 6, mesmerist 6, psychic 8, skald 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> creatures within a 20-ft. radius spread<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will partial; <strong>Spell Resistance</strong> yes</p><p>This spell functions as song of discord except that affected creatures automatically attack the nearest target each round. In addition, all affected creatures gain a +4 morale bonus to Strength for the duration of the spell. A creature that succeeds at the Will save reduces the effect's duration to 1 round.</p>
</>};
const _song_of_kyonin = {title: "Song of Kyonin", jsx: <><h2 id="spell-song_of_kyonin-song-of-kyonin">Song of Kyonin</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_magic">Inner Sea Magic pg. 60</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>); <strong>Level</strong> bard 4, skald 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> up to 3 creatures, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 round/level or until performance ends or changes (see text)</p><p>Certain elven bards of Kyonin are known for the restorative power of their performances-mostly as a result of this spell. You must have a bardic performance in effect to cast this spell (although this spell is called song of Kyonin, the bardic performance need not be singing). As long as that performance continues, up to 3 creatures affected by the performance gain fast healing 2. When this bardic performance ends or you change to a different bardic performance, the fast healing granted by this spell ends as well, but all creatures affected by this spell heal 1d8 points of damage + 1 point per caster level (maximum +15) and are cured of any of the following conditions: exhausted, fatigued, nauseated, paralyzed, sickened, or stunned.</p>
</>};
const _songbird = {title: "Songbird", jsx: <><h2 id="spell-songbird-songbird">Songbird</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 44</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> [<Link to="/spelldef/good">good</Link>]; <strong>Level</strong> arcanist 1, bard 1, cleric 1, mesmerist 1, oracle 1, paladin 1, psychic 1, skald 1, sorcerer 1, warpriest 1, wizard 1<br/><strong>Casting Time</strong> 1 swift action<br/><strong>Components</strong> S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round</p><p>You conjure uplifting music from the wilds of Elysium, Heaven, or Nirvana to bolster other musical activities.</p>
<p>If you cast songbird during the same round in which you attempt a Perform check, songbird acts as accompaniment and grants a +3 bonus on that Perform check.</p>
<p>If you cast songbird in the same round in which you activate a bardic performance, that round of bardic performance does not count against your total rounds of bardic performance available for the day.</p>
<p>If you cast songbird in the same round in which you cast a spell with the sonic descriptor, that spell's save DC increases by 1.</p>
</>};
const _sonic_form = {title: "Sonic Form", jsx: <><h2 id="spell-sonic_form-sonic-form">Sonic Form</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 193</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>) [<Link to="/spelldef/sonic">sonic</Link>]; <strong>Level</strong> alchemist 6, arcanist 6, bard 6, investigator 6, psychic 6, skald 6, sorcerer 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a pinch of dust gathered from a gravestone or a sacred shrine)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>Upon casting this spell, you keep your relative shape, but you and your equipment are transformed into semi-solid sound. While in this sonic form, you take no penalties for squeezing, and you can move through spaces without penalty as if you were a creature three size categories smaller. You can make a melee touch attack once per round that deals 1d6 points of sonic damage + 1 point per caster level. You are considered incorporeal (although you cannot move through solid objects). Any nonmagical attacks you make deal half damage. Magical attacks are unaffected, and you can use your magic items and other equipment as normal.</p>
<p>You cannot enter an area of silence. If you are in the area of a silence spell, you take 1d6 points of sonic damage per caster level of the silence spell in the round it is cast and in each round when you end your turn within the spell's area. You can attempt a Fortitude saving throw each round to take half damage.</p>
<p>If this spell's duration ends when you are in a square that a creature of your size cannot normally occupy, you take 3d6 points of damage and are shunted to the nearest open space that you can normally occupy.</p>
</>};
const _sonic_scream = {title: "Sonic Scream", jsx: <><h2 id="spell-sonic_scream-sonic-scream">Sonic Scream</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 193</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/sonic">sonic</Link>]; <strong>Level</strong> arcanist 2, bloodrager 2, bard 2, magus 2, psychic 2, skald 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 15 ft.<br/><strong>Area</strong> cone-shaped burst<br/><strong>Duration</strong> 1 round/level or until discharged (see text)<br/><strong>Saving Throw</strong> Reflex half (see text); <strong>Spell Resistance</strong> yes</p><p>Up to three times during this spell's duration, you can emit a cone of powerful sound as a standard action. The first cone deals 4d4 points of sonic damage to every creature in the area. The second deals 2d4 points of sonic damage to every creature in the area. The third deals 1d4 points of sonic damage to every creature in the area. A successful Reflex save against a cone halves that cone's damage. After the third cone of sound, the spell ends. Until you use all three cones, you cannot use your voice for any magic-related purpose (bardic performance, verbal spellcasting, and so on), and cannot speak at any volume lower than a shout.</p>
</>};
const _sonic_thrust = {title: "Sonic Thrust", jsx: <><h2 id="spell-sonic_thrust-sonic-thrust">Sonic Thrust</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 239</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/sonic">sonic</Link>]; <strong>Level</strong> arcanist 5, bard 4, psychic 5, skald 4, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Target</strong> see text<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (object) or none (see text); <strong>Spell Resistance</strong> yes (object) (see text)</p><p>You produce a sweeping rush of sound that can hurl creatures or objects away from you, like the violent thrust version of telekinesis. You can hurl one object or creature per caster level (maximum 15) that is within range; it flies in a straight line away from you. Any objects of creatures thrown must be within 10 feet of each other. You can hurl a total weight of up to 25 pounds per caster level (maximum 375 pounds at 15th level).</p>
<p>You can use this spell to hurl an object or creature toward a particular target. You must succeed on attack rolls (one per creature or object thrown) to hit the target with the items, using your base attack bonus + your Intelligence modifier (if a wizard) or Charisma modifier (if a bard or sorcerer). Hurled weapons cause standard damage (with no Strength bonus; note that arrows or bolts deal damage as daggers of their size when used in this manner). Other objects cause damage ranging from 1 point per 25 pounds (for less dangerous objects) to 1d6 points of damage per 25 pounds (for hard, dense objects). Objects and creatures that miss their target land in a square adjacent to the target.</p>
<p>Creatures that fall within the weight capacity of the spell can be hurled, but they are allowed Will saves (and spell resistance) to negate the effect, as are those whose held possessions are targeted by the spell.</p>
<p>If a hurled creature is thrown against a solid surface, it takes damage as if it had fallen 10 feet (1d6 points).</p>
</>};
const _soothe_construct = {title: "Soothe Construct", jsx: <><h2 id="spell-soothe_construct-soothe-construct">Soothe Construct</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 239</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 5, cleric 4, occultist 4, oracle 4, sorcerer 5, warpriest 4, wizard 5<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one construct<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You soothe the elemental spirit of a targeted construct, reducing its chance of going berserk by 1d4% per four caster levels (maximum 5d4%). If cast on a construct that has already gone berserk and you are its master, you may immediately roll d% to end the construct's berserk state, it returns to normal functioning, and its berserk chance returns to 0%.</p>
</>};
const _soothing_mud = {title: "Soothing Mud", jsx: <><h2 id="spell-soothing_mud-soothing-mud">Soothing Mud</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 236</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>) [<Link to="/spelldef/earth">earth</Link>, <Link to="/spelldef/water">water</Link>]; <strong>Level</strong> druid 3, hunter 3, ranger 3, shaman 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> dust, earth, sand, or water in one 5-ft. square/level<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You create an area of healing mud. Water, earth, sand, and dust thicken into a wet mud. The mud functions as difficult terrain and does not sink if created in water unless weighed down by more than 100 pounds per caster level you have. Each round a creature begins its turn in or on the mud, the mud restores 1 hit point to it; this healing is unaffected by effects that increase a creature's healing. A creature that rests partially or completely submerged in this mud for 1 full minute is also healed of 1d4 points of ability damage to an ability score of its choice. A creature can be healed of ability damage this way only once per day.</p>
</>};
const _soothing_word = {title: "Soothing Word", jsx: <><h2 id="spell-soothing_word-soothing-word">Soothing Word</h2>
<p><strong>Sources</strong> <Link to="/source/gamemastery_condition_cards">GameMastery Condition Cards pg. 0</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>); <strong>Level</strong> cleric 2, druid 2, hunter 2, inquisitor 2, oracle 2, paladin 2, ranger 2, warpriest 2, witch 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> 1 creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The target of this spell causes several conditions that he suffers from to be lessened in severity by one step. If he is nauseated, he is instead sickened. If he is stunned, he is instead dazed. If he is exhausted, he is fatigued. If he is frightened, he is shaken. If he is paralyzed, he is staggered. The duration of the effect is unchanged; the effect is simply reduced to the lesser version. This spell has no effect on conditions not listed above.</p>
</>};
const _sotto_voce = {title: "Sotto Voce", jsx: <><h2 id="spell-sotto_voce-sotto-voce">Sotto Voce</h2>
<p><strong>Sources</strong> <Link to="/source/faction_guide">Faction Guide pg. 61</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/fear">fear</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>, <Link to="/spelldef/sonic">sonic</Link>]; <strong>Level</strong> arcanist 0, bard 1, cleric 0, oracle 0, skald 1, sorcerer 0, warpriest 0, wizard 0<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one humanoid creature of 4 HD or less<br/><strong>Duration</strong> 1 round<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>Your dry, rasping whisper fills a living creature of 4 or fewer Hit Dice with unnatural dread. The affected creature must make a Will save or be shaken for 1 round.</p>
<p>This spell originated among the followers of the <Link to="/rule/whispering_way">Whispering Way</Link>, but necromancers and other intimidating folk outside that group are known to use it.</p>
</>};
const _soul_bind = {title: "Soul Bind", jsx: <><h2 id="spell-soul_bind-soul-bind">Soul Bind</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 345</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 9, cleric 9, oracle 9, psychic 9, shaman 9, sorcerer 9, witch 9, wizard 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (see text)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> corpse<br/><strong>Duration</strong> permanent<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> no</p><p>You draw the soul from a newly dead body and imprison it in a black sapphire gem. The subject must have been dead no more than 1 round per caster level. The soul, once trapped in the gem, cannot be returned through <Link to="/spell/clone">clone</Link>, <Link to="/spell/raise_dead">raise dead</Link>, <Link to="/spell/reincarnate">reincarnate</Link>, <Link to="/spell/resurrection">resurrection</Link>, <Link to="/spell/true_resurrection">true resurrection</Link>, or even a <Link to="/spell/miracle">miracle</Link> or a <Link to="/spell/wish">wish</Link>. Only by destroying the gem or dispelling the spell on the gem can one free the soul (which is then still dead).</p>
<p>The focus for this spell is a black sapphire of at least 1,000 gp value for every HD possessed by the creature whose soul is to be bound. If the gem is not valuable enough, it shatters when the binding is attempted. (While creatures have no concept of level or HD as such, the value of the gem needed to trap an individual can be researched.)</p>
</>};
const _soul_vault = {title: "Soul Vault", jsx: <><h2 id="spell-soul_vault-soul-vault">Soul Vault</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 33</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 4, cleric 3, druid 4, hunter 4, inquisitor 3, oracle 3, psychic 5, shaman 4, sorcerer 4, spiritualist 2, warpriest 3, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes</p><p>This spell protects the target's soul by briefly enveloping the target in an ethereal vault. The target gains a +4 bonus on saving throws against spells and effects that would trap or redirect its soul (such as magic jar, soul bind, and trap the soul) and effects that would transform the target into an undead creature. The target is granted a save to negate such effects even if one is not normally allowed. If it's cast on a living creature that then dies, the target's body and spirit are protected by the spell for its duration. If it's cast on a corpse within 1 round of death, the target's body and soul are both protected. Otherwise, only the body receives the protection.</p>
<p>Any spellcaster that worships Abadar may learn and cast soul vault as a 4th level spell, if it isn't normally on her class spell list. Soul vault can be made permanent with the <Link to="/spell/permanency">permanency</Link> spell at a cost of 7,500 gp and a minimum caster level of 11th.</p>
</>};
const _soulreaver = {title: "Soulreaver", jsx: <><h2 id="spell-soulreaver-soulreaver">Soulreaver</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_origins">Mythic Origins pg. 15</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/death">death</Link>]; <strong>Level</strong> arcanist 8, cleric 8, oracle 8, sorcerer 8, witch 8, wizard 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> living creatures in a 20-ft.-radius spread<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude half; <strong>Spell Resistance</strong> yes</p><p>Favored by the necromancer Geb as a tool to turn his enemies' armies against themselves, this potent death spell deals 1d6 points of damage per caster level (maximum 20d6) to living creatures in the area of effect.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-soulreaver--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Soulreaver</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_origins">Mythic Origins pg. 15</Link><br/>You can expend one use of mythic power to raise creatures killed by this effect as undead thralls. You can animate a number of Hit Dice worth of undead up to double your tier as if you had animated them with <Link to="/spell/animate_dead">animate dead</Link>. The undead created by this spell count toward the total number of Hit Dice worth of undead you can control.</p>
<p><em>Augmented (8th):</em> If you expend two uses of mythic power, you can raise slain foes as undead creatures chosen from the list of undead for create undead. By expending three uses of mythic power, you can select from the list for create greater undead. The total number of Hit Dice worth of undead created in this way can't exceed double your tier. Created undead are not automatically under your control. If you are capable of commanding undead, you may attempt to command the undead creatures as they form.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _soulseeker = {title: "Soulseeker", jsx: <><h2 id="spell-soulseeker-soulseeker">Soulseeker</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 44</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> cleric 8, medium 4, occultist 6, oracle 8, shaman 8, spiritualist 6, witch 8<br/><strong>Casting Time</strong> 1 hour<br/><strong>Components</strong> V, S, M (incense worth 250 gp), F (see text)<br/><strong>Range</strong> unlimited<br/><strong>Target</strong> one soul<br/><strong>Duration</strong> instantaneous or 1 hour/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> no</p><p>You identify the stage of a given soul's judgment, or determine its fate post-judgment. You must either unambiguously identify the soul you seek or use the skull of the body the soul vacated as a focus. If the subject does not share your alignment, the soul can attempt a Will save to resist this spell's effects as if it were still alive. If the subject is still alive or its soul has been destroyed, this spell fails without providing any information.</p>
<p>If the soul has not yet been judged and moved on to its final reward or punishment, soulseeker provides an estimate of its location; in most cases, this is somewhere in the River of Souls or the Boneyard. While this may assist in physically traveling to the soul's location, especially in cases involving effects such as soul bind or a devourer's devour soul ability, the spell's primary purpose is to identify how long the subject has been dead (and what form of life-restoring magic is necessary). If the soul has already been judged, soulseeker instead identifies the plane to which the soul has been sent as a petitioner and the petitioner's general location on that plane (such as "Elysium, beneath the boughs of the Witchwood").</p>
<p>If soulseeker is cast on the same plane on which the soul's new petitioner form currently exists, it guides you along the shortest, most direct physical route to the petitioner, as described in find the path. In this case, the spell's duration is 1 hour per level.</p>
</>};
const _soulswitch = {title: "Soulswitch", jsx: <><h2 id="spell-soulswitch-soulswitch">Soulswitch</h2>
<p><strong>Sources</strong> <Link to="/source/familiar_folio">Familiar Folio pg. 23</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 5, bard 5, cleric 5, druid 5, hunter 5, inquisitor 5, magus 5, oracle 5, shaman 5, skald 5, sorcerer 5, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (two brass collars worth 50 gp each)<br/><strong>Range</strong> touch<br/><strong>Targets</strong> you and your familiar<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You may only cast this spell if you currently have a familiar. You place your soul into the body of your familiar, and your familiar's soul is placed in your body. This functions as if you possessed your familiar using <Link to="/spell/magic_jar">magic jar</Link>; your familiar simultaneously possesses your body in the same manner. You can't freely transfer your soul between your body and your familiar's - if you choose to return to your body as a standard action, the spell ends. If either body is killed, both spirits return to their original bodies, the spell ends, and the original owner of the slain body dies.</p>
</>};
const _sound_burst = {title: "Sound Burst", jsx: <><h2 id="spell-sound_burst-sound-burst">Sound Burst</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 346</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/sonic">sonic</Link>]; <strong>Level</strong> bard 2, cleric 2, occultist 2, oracle 2, skald 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F/DF (a musical instrument)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> 10-ft.-radius spread<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude partial; <strong>Spell Resistance</strong> yes</p><p>You blast an area with a tremendous cacophony. Every creature in the area takes 1d8 points of sonic damage and must succeed on a Fortitude save to avoid being stunned for 1 round. Creatures that cannot hear are not stunned but are still damaged.</p>
</>};
const _sow_thought = {title: "Sow Thought", jsx: <><h2 id="spell-sow_thought-sow-thought">Sow Thought</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 185</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 1, bard 1, mesmerist 1, psychic 1, skald 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> permanent<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em><Link to="/race/changeling">Changelings</Link> have access to the following spell.</em></p>
</blockquote>
<p>You plant an idea, concept, or suspicion in the mind of the subject. The target genuinely believes that the idea is his own, but is not required to act upon it. If the idea is contrary to the target's normal thoughts (such as making a paladin think, "I should murder my friends") the target may suspect mind-altering magic is at play. The idea must be fairly clear, enough so that it can be conveyed in one or two sentences. You do not need to share a common language for the spell to succeed, but without a common language you can only sow the most basic rudimentary ideas.</p>
</>};
const _spark = {title: "Spark", jsx: <><h2 id="spell-spark-spark">Spark</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 246</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> arcanist 0, bard 0, cleric 0, druid 0, hunter 0, magus 0, occultist 0, oracle 0, skald 0, sorcerer 0, warpriest 0, witch 0, wizard 0<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V or S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one Fine object<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>You can make an unattended Fine flammable object catch on fire. This works as if you were using flint and steel except that you can use spark in any sort of weather and it takes much less time to actually ignite an object.</p>
</>};
const _spawn_calling = {title: "Spawn Calling", jsx: <><h2 id="spell-spawn_calling-spawn-calling">Spawn Calling</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 241</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/calling">calling</Link>) [<Link to="/spelldef/chaotic">chaotic</Link>, <Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> arcanist 9, cleric 9, oracle 9, sorcerer 9, witch 9, wizard 9 (Rovagug; see below)<br/><strong>Casting Time</strong> 1 week<br/><strong>Components</strong> V, S, M/DF (bull's blood, tallow, one or more humanoid victims totaling at least 15 Hit Dice)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> one Spawn of Rovagug<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>Having attained the highest and most profane form of magical achievement in the Great Destroyer's service, you are able to call forth his most dreaded creations: the Spawn of Rovagug. Casting this spell requires a week-long ritual involving the sacrifice of one or more sentient humanoid creatures that between them possess a total of at least 15 Hit Dice. You may not eat, sleep, or cast any other spells for the duration of this ritual. After the third day of the ritual, you must succeed at a Constitution check on each remaining day of the ritual (DC 10 + 1 for each previous check) or take 1d6 points of nonlethal damage from hunger. At the end of the ritual, you gain the exhausted condition from lack of sleep.</p>
<p>Upon completion of the ritual, the ground rumbles in a 100-foot radius centered on you. This effect lasts for 1 round. Any creature on the ground in this area that attempts to cast a spell during this round must succeed at a <Link to="/rule/concentration">concentration</Link> check (DC 20 + spell level) or lose the spell. Any creature on the ground in the area that attempts to attack or move during this round must succeed at a DC 15 Reflex save at the beginning of its turn or fall prone.</p>
<p>At the beginning of your next turn, a massive fissure full of dark fire and shrieking cries appears at a point you designate within the spell's range, and a Spawn of Rovagug emerges. This creature takes the form of a thunder behemoth with the advanced and entropic simple templates. Unlike with summon monster or similar spells, the caster has no control whatsoever over the called creature. The spawn immediately heads in a random direction or toward an obvious target such as a population center, destroying anything in its path, yourself and your allies included.</p>
<p>Any creature may attempt to control the called Spawn of Rovagug via spells like dominate monster or binding. However, if such an attempt fails, it draws the spawn's attention, and the monster immediately tries to destroy the creature that attempted to control it. Because the Spawn of Rovagug are all magical beasts native to the Material Plane, spells such as <Link to="/spell/banishment">banishment</Link> or <Link to="/spell/dismissal">dismissal</Link> have no effect on the called spawn.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-spawn_calling--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Spawn Calling</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 242</Link><br/>When casting this spell, you can specify a particular Spawn of Rovagug - including the Tarrasque, the Armageddon Engine; Chemnosit, the Monarch Worm; or Volnagur, the End-Singer - to call in place of the nameless behemoth spawned by the non-mythic version of this spell. In order to do so, you must expend one use of mythic power plus three additional uses of mythic power per point of Challenge Rating the specified spawn represents above CR 20. These must be expended on the final day of the weeklong ritual to cast the spell.</p>
</td></tr></tbody></table></ScrollContainer></div><aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _spawn_ward = {title: "Spawn Ward", jsx: <><h2 id="spell-spawn_ward-spawn-ward">Spawn Ward</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 101</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> cleric 5, inquisitor 5, oracle 5, warpriest 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level</p><blockquote>
<p><em><Link to="/race/dhampir">Dhampirs</Link> have access to the following spell.</em></p>
</blockquote>
<p>The target becomes resistant to the effects of energy drain and blood drain attacks made by undead creatures, and cannot be made into undead spawn if killed while the spell is in effect.</p>
<p>If the attacking undead's Hit Dice is less than or equal to your caster level, the blood drain or energy drain has no effect. If the attacking undead's Hit Dice are greater than your caster level, the undead must make a Fortitude save (against the DC of the spell) with each attack for those special abilities to have any effect. The spell only prevents the Constitution damage from blood drain and negative levels from energy drain, but not any other effects of these attacks.</p>
</>};
const _speak_local_language = {title: "Speak Local Language", jsx: <><h2 id="spell-speak_local_language-speak-local-language">Speak Local Language</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 1, bard 1, cleric 1, hunter 1, inquisitor 1, oracle 1, ranger 1, skald 1, sorcerer 1, warpriest 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, M/DF (a worn-out coin)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no</p><p>This spell functions as <Link to="/spell/tongues">tongues</Link>, except the creature touched gains only the ability to speak and understand a regional human language, such as Varisian or Common (Taldane in the Inner Sea region or Tien in Tian Xia), and the language granted must be one you know. You must select the language at the time of casting. The language can't be a dead language, such as Ancient Osiriani or Jistka.</p>
<p>The target speaks the language with a native accent, but the spell doesn't impart knowledge about any culture associated with the language, nor does it change the target's appearance.</p>
</>};
const _speak_with_animals = {title: "Speak with Animals", jsx: <><h2 id="spell-speak_with_animals-speak-with-animals">Speak with Animals</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 346</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> bard 3, druid 1, hunter 1, psychic 2, ranger 1, skald 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>You can ask questions of and receive answers from animals, but the spell doesn't make them any more friendly than normal. Wary and cunning animals are likely to be terse and evasive, while the more stupid ones make inane comments. If an animal is friendly toward you, it may do some favor or service for you.</p>
</>};
const _speak_with_dead = {title: "Speak with Dead", jsx: <><h2 id="spell-speak_with_dead-speak-with-dead">Speak with Dead</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 346</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/language_dependent">language-dependent</Link>]; <strong>Level</strong> cleric 3, inquisitor 3, medium 2, oracle 3, psychic 3, shaman 3, spiritualist 3, warpriest 3, witch 3<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> 10 ft.<br/><strong>Target</strong> one dead creature<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates; see text; <strong>Spell Resistance</strong> no</p><p>You grant the semblance of life to a corpse, allowing it to answer questions. You may ask one question per two caster levels. The corpse's knowledge is limited to what it knew during life, including the languages it spoke. Answers are brief, cryptic, or repetitive, especially if the creature would have opposed you in life.</p>
<p>If the dead creature's alignment was different from yours, the corpse gets a Will save to resist the spell as if it were alive. If successful, the corpse can refuse to answer your questions or attempt to deceive you, using Bluff. The soul can only speak about what it knew in life. It cannot answer any questions that pertain to events that occurred after its death.</p>
<p>If the corpse has been subject to <Link to="/spell/speak_with_dead">speak with dead</Link> within the past week, the new spell fails. You can cast this spell on a corpse that has been deceased for any amount of time, but the body must be mostly intact to be able to respond. A damaged corpse may be able to give partial answers or partially correct answers, but it must at least have a mouth in order to speak at all. This spell does not affect a corpse that has been turned into an undead creature.</p>
</>};
const _speak_with_haunt = {title: "Speak with Haunt", jsx: <><h2 id="spell-speak_with_haunt-speak-with-haunt">Speak with Haunt</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 193</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/language_dependent">language-dependent</Link>]; <strong>Level</strong> cleric 4, medium 2, oracle 4, psychic 4, shaman 3, spiritualist 4, warpriest 4, witch 4<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> 10 ft. (see text)<br/><strong>Target</strong> one haunt<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (see text); <strong>Spell Resistance</strong> no</p><p>You stir a haunt to a limited sense of awareness and consciousness, allowing it to answer questions. The spell's range must reach any square within 10 feet of the haunt's area. You must be aware of the haunt prior to casting the spell, and casting the spell does not trigger the haunt. You can ask one question per 2 caster levels. The haunt's knowledge is limited to what its original creature knew during life, including the languages it spoke. A haunt often remembers the circumstance that led to its existence (though this recollection might be from the original victim's perspective and therefore not objective), what triggers it, and how it can be laid to rest (destroyed). Answers are brief, cryptic, or repetitive, especially if the haunt is angry and vindictive.</p>
<p>If the haunt's alignment is more than one step away from yours, the haunt can attempt a Will save to resist the spell. A haunt's Will save modifier is equal to 3 + the haunt's CR. If the save is successful, the haunt can refuse to answer your questions or attempt to deceive you (using Bluff). A haunt's Bluff modifier equals its CR (minimum +0) or might be determined by the GM based upon the original victim. The haunt can speak only about what it knew in life and the circumstances by which it became a haunt. It cannot answer any questions that pertain to events that occurred after it was created. A neutral or good haunt might cooperate with similarly aligned creatures in order to end its suffering.</p>
<p>If a haunt has been subject to this spell within the past week, a new casting of this spell on it fails. You can cast this on a haunt that has been deceased for any amount of time. Unlike a corpse affected by <Link to="/spell/speak_with_dead">speak with dead</Link>, a haunt wants to express itself, if only to share its pain or to cause mischief.</p>
</>};
const _speak_with_plane = {title: "Speak with Plane", jsx: <><h2 id="spell-speak_with_plane-speak-with-plane">Speak with Plane</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 12</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 4, cleric 4, medium 3, oracle 4, shaman 4, sorcerer 4, summoner 3, unchained summoner 3, warpriest 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F/DF (a small glass bead)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one plane with a sentient structure<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (see text); <strong>Spell Resistance</strong> yes</p><p>You tap into the awareness and consciousness of a plane with a sentient structure, allowing it to answer questions. A tangible manifestation of the plane (such as the ground) must be within the spell's range upon casting. You can ask the sentient plane one question per 2 caster levels. If the plane's alignment is at least one step away from yours, the plane can attempt a Will save to resist the spell. A plane typically has a +20 bonus on Will saves, and a demiplane typically has a +15 bonus on Will saves. A plane's traits can further affect these bonuses: a mildly aligned plane receives a +2 bonus, and a strongly aligned plane or a plane with the wild magic trait receives a +4 bonus on its save.</p>
<p>If a plane has been subject to this spell within the past week, a new casting of this spell targeting the same plane fails. If speak with plane targets a plane that does not have a sentient structure, the spell fails.</p>
</>};
const _speak_with_plants = {title: "Speak with Plants", jsx: <><h2 id="spell-speak_with_plants-speak-with-plants">Speak with Plants</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 346</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> bard 4, druid 3, hunter 2, ranger 2, skald 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>You can communicate with normal plants and plant creatures, and can ask questions of and receive answers from them. A normal plant's sense of its surroundings is limited, so it won't be able to give (or recognize) detailed descriptions of creatures or answer questions about events outside its immediate vicinity. The spell doesn't make plant creatures any more friendly or cooperative than normal. Furthermore, wary and cunning plant creatures are likely to be terse and evasive, while the more stupid ones may make inane comments. If a plant creature is friendly, it may do some favor or service for you.</p>
</>};
const _speak_with_soul = {title: "Speak with Soul", jsx: <><h2 id="spell-speak_with_soul-speak-with-soul">Speak with Soul</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 45</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> antipaladin 4, cleric 6, medium 4, oracle 6, paladin 4, shaman 6, spiritualist 6, warpriest 6<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S, M (a drop of candle wax)<br/><strong>Range</strong> 10 ft.<br/><strong>Target</strong> see text<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates; see text; <strong>Spell Resistance</strong> no</p><p>You commune with the soul of a dead creature. To cast this spell, you must be at the soul's place of death or be in the soul's presence, whether it is contained in a receptacle, powers an intelligent magic item, or other possibilities. The soul can attempt a Will save to resist the spell as if it were alive.</p>
<p>A soul contacted this way can speak normally in any language it knows. Unlike <Link to="/spell/speak_with_dead">speak with dead</Link> and similar spells, you are not limited to asking questions and can engage in normal conversation with the soul (and vice versa). The soul isn't an undead creature and isn't compelled to speak or be truthful. Generally, the soul only knows what it knew in life, although souls that persisted with awareness of their surroundings after death may have more to offer.</p>
</>};
const _spear_of_purity = {title: "Spear of Purity", jsx: <><h2 id="spell-spear_of_purity-spear-of-purity">Spear of Purity</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/good">good</Link>]; <strong>Level</strong> cleric 2, oracle 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> spear-shaped projectile of good energy<br/><strong>Duration</strong> instantaneous (1 round)<br/><strong>Saving Throw</strong> Will partial (see text); <strong>Spell Resistance</strong> yes</p><p>You hurl a pure white or golden spear of light from your holy symbol, affecting any one target within range as a ranged touch attack.</p>
<p>An evil creature struck by the spear takes 1d8 points of damage per two caster levels (maximum 5d8). An evil outsider instead takes 1d6 points of damage per caster level (maximum 10d6) and is blinded for 1 round. A successful Will save reduces the damage to half and negates the blinded effect. This spell deals only half damage to creatures that are neither evil nor good, and they are not blinded. The spear has no effect on good creatures.</p>
</>};
const _spectral_hand = {title: "Spectral Hand", jsx: <><h2 id="spell-spectral_hand-spectral-hand">Spectral Hand</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 346</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 2, medium 2, occultist 2, psychic 2, sorcerer 2, spiritualist 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> one spectral hand<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>A ghostly hand shaped from your life force materializes and moves as you desire, allowing you to deliver low-level, touch range spells at a distance. On casting the spell, you lose 1d4 hit points that return when the spell ends (even if it is dispelled), but not if the hand is destroyed. (The hit points can be healed as normal.) For as long as the spell lasts, any touch range spell of 4th level or lower that you cast can be delivered by the spectral hand. The spell gives you a +2 bonus on your melee touch attack roll, and attacking with the hand counts normally as an attack. The hand always strikes from your direction. The hand cannot flank targets like a creature can. After it delivers a spell, or if it goes beyond the spell range or goes out of your sight, the hand returns to you and hovers.</p>
<p>The hand is incorporeal and thus cannot be harmed by normal weapons. It has improved evasion (half damage on a failed Reflex save and no damage on a successful save), your save bonuses, and an AC of 22 (+8 size, +4 natural armor). Your Intelligence modifier applies to the hand's AC as if it were the hand's Dexterity modifier. The hand has 1 to 4 hit points, the same number that you lost in creating it.</p>
</>};
const _spectral_saluqi = {title: "Spectral Saluqi", jsx: <><h2 id="spell-spectral_saluqi-spectral-saluqi">Spectral Saluqi</h2>
<p><strong>Sources</strong> <Link to="/source/occult_mysteries">Occult Mysteries pg. 58</Link>, <Link to="/source/osirion_land_of_the_pharaohs">Osirion, Land of the Pharaohs pg. 27</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 6, sorcerer 6, witch 6, wizard 6<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, F (a precious metal canine statue worth 100 gp)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> one spectral dog<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell creates a spectral saluqi, an undead canine resembling an oversized hound with black fur, a gray ruff and tail, and milky gray eyes. The hound shares your alignment and can converse with you telepathically. It can see and attack ethereal creatures, and otherwise has the same statistics as a yeth hound. It usually leaves no tracks because it prefers to fly an inch above the ground. You are immune to the hound's bay ability. The hound's bite is considered aligned to any single alignment you possess for the purposes of overcoming damage reduction.</p>
</>};
const _spectral_scout = {title: "Spectral Scout", jsx: <><h2 id="spell-spectral_scout-spectral-scout">Spectral Scout</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_116_fangs_of_war">Pathfinder #116: Fangs of War pg. 67</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> arcanist 3, bard 3, druid 3, hunter 3, ranger 3, shaman 3, skald 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 1 mile<br/><strong>Effect</strong> one incorporeal animal of size Tiny or smaller<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You summon a spectral creature in the shape of the Tiny or smaller animal of your choice, which always appears in your square. The creature emits a faint glow of a color you choose at the time of the spell's casting, providing the illumination of a candle. It has the same statistics as the creature after which it is modeled (including ability scores, Armor Class, feats, senses, skills, and speed), but is incorporeal and has only 1 hit point. A spectral scout cannot attack, but can otherwise follow any basic instructions that could be given to a pet or animal companion of similar intelligence but without the need to make Handle Animal skill checks.</p>
<p>A spectral scout can communicate verbally with the caster but can't be understood by others. A spectral scout can relay information it has directly witnessed with perfect clarity, including sights, sounds, and smells, but it cannot further interpret that information. For example, a spectral scout can report on how many individuals it sees, the direction they are going, and what equipment they carry; it can't tell the caster whether the people were friend or foe, or their objective.</p>
</>};
const _speechreaders_sight = {title: "Speechreader's Sight", jsx: <><h2 id="spell-speechreaders_sight-speechreaders-sight">Speechreader's Sight</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court pg. 10</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> alchemist 1, arcanist 1, bard 1, cleric 1, inquisitor 1, investigator 1, medium 1, mesmerist 1, occultist 1, oracle 1, psychic 1, skald 1, sorcerer 1, spiritualist 1, warpriest 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 hour/level (D)</p><p>If a creature within 100 feet that you can see is speaking a language you understand, you can read its lips with perfect accuracy. Reading lips in this manner gives the exact wording of conversation and does not assist in deciphering any obfuscated ideas such as secret messages or slang. Reading lips requires moderate concentration, and you take a -4 penalty on other Perception checks while doing so.</p>
<p>Speechreader's sight can be made permanent with a <Link to="/spell/permanency">permanency</Link> spell cast by a caster of 9th level or higher, at a cost of 2,500 gp.</p>
</>};
const _spell_absorption = {title: "Spell Absorption", jsx: <><h2 id="spell-spell_absorption-spell-absorption">Spell Absorption</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_magic">Inner Sea Magic pg. 61</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 5, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (a prism)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>If you successfully counterspell a 3rd-level or lower level spell (through either <Link to="/spell/dispel_magic">dispel magic</Link> or normal means) while spell absorption is in effect, you absorb the countered spell and use it to regain spells you have already cast. If you're a wizard, you regain the use of any single spell that you have cast since the last time you prepared spells. If you're a sorcerer, you regain a single spell slot. The spell recovered or spell slot regained must be of an equal level or lower than the spell you counterspelled.</p>
<h3 id="spell-spell_absorption-greater-spell-absorption">Greater Spell Absorption</h3>
<p><strong>Sources</strong> <Link to="/source/inner_sea_magic">Inner Sea Magic pg. 61</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 8, sorcerer 8, wizard 8<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (a prism)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>This spell functions as spell absorption, save that you can absorb countered spells of 6th level or lower.</p>
</>};
const _spell_gauge = {title: "Spell Gauge", jsx: <><h2 id="spell-spell_gauge-spell-gauge">Spell Gauge</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 242</Link>, <Link to="/source/faiths_of_balance">Faiths of Balance pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 2, bard 2, cleric 2, inquisitor 2, oracle 2, skald 2, sorcerer 2, warpriest 2, witch 2, wizard 2 (Nethys; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a silver piece)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You immediately discover some of the spells that the target knows or has prepared. The number of spells revealed to you is equal to your caster level. The target's lowest-level spells are revealed first - ignoring 0-level spells - in a random order. Once all of the target's 1st-level spells are revealed, the spell begins revealing 2nd-level spells, then 3rd-level spells. This spell does not reveal spells of 4th level or higher, nor does it reveal spell-like abilities or other special abilities. If cast on a creature that is not a spellcaster, that has only 0-level spells or spells of 4th level or higher prepared, that has expended all of its spells, or that has not prepared any spells that day, the spell has no effect.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _spell_immunity = {hasJL:true,title: "Spell Immunity", jsx: <><div className="jumpList" id="spell-spell_immunity-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-spell_immunity-communal-spell-immunity">Communal Spell Immunity</InnerLink></li><li><InnerLink toTop to="spell-spell_immunity-greater-spell-immunity">Greater Spell Immunity</InnerLink></li><li><InnerLink toTop to="spell-spell_immunity-greater-communal-spell-immunity">Greater Communal Spell Immunity</InnerLink></li></ul></div><h2 id="spell-spell_immunity-spell-immunity">Spell Immunity</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 346</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 4, cleric 4, inquisitor 4, investigator 4, occultist 4, oracle 4, psychic 4, spiritualist 4, warpriest 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The warded creature is immune to the effects of one specified spell for every four levels you have. The spells must be of 4th level or lower. The warded creature effectively has unbeatable spell resistance regarding the specified spell or spells. Naturally, that immunity doesn't protect a creature from spells for which spell resistance doesn't apply. Spell immunity protects against spells, spell-like effects of magic items, and innate spell-like abilities of creatures. It does not protect against supernatural or extraordinary abilities, such as breath weapons or gaze attacks.</p>
<p>Only a particular spell can be protected against, not a certain domain or school of spells or a group of spells that are similar in effect. A creature can have only one spell immunity or greater spell immunity spell in effect on it at a time.</p>
<h3 id="spell-spell_immunity-communal-spell-immunity" data-hash-target>Communal Spell Immunity</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 244</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 5, inquisitor 5, occultist 5, oracle 5, psychic 5, warpriest 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Targets</strong> creatures touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like spell immunity, except you divide the duration in 10-minute intervals among the creatures touched.</p>
<h3 id="spell-spell_immunity-greater-spell-immunity" data-hash-target>Greater Spell Immunity</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 347</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 8, oracle 8, psychic 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like spell immunity, except the immunity applies to spells of 8th level or lower. A creature can have only one spell immunity or greater spell immunity spell in effect on it at a time.</p>
<h3 id="spell-spell_immunity-greater-communal-spell-immunity" data-hash-target>Greater Communal Spell Immunity</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 245</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 9, oracle 9, psychic 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Targets</strong> creatures touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like greater spell immunity, except you divide the duration among the creatures in 10-minute intervals among the creatures touched.</p>
</>};
const _spell_resistance = {title: "Spell Resistance", jsx: <><h2 id="spell-spell_resistance-spell-resistance">Spell Resistance</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 347</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 5, cleric 5, inquisitor 5, investigator 5, occultist 5, oracle 5, psychic 5, spiritualist 5, warpriest 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The target gains spell resistance equal to 12 + your caster level.</p>
</>};
const _spell_scourge = {title: "Spell Scourge", jsx: <><h2 id="spell-spell_scourge-spell-scourge">Spell Scourge</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 243</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 7, cleric 7, oracle 7, sorcerer 7, witch 7, wizard 7 (Nethys; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous or 1d4 rounds; see text<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>A whip of cracking magical might appears in your hand, allowing you lash spells from the mind of enemy spellcasters. With a lash of bluish-purple energy, you strip many protective spells and effects from a single creature. If the target of this spell is currently under the effects of any harmless spells or effects, it must succeed at a Will save or all of those spells and effects end, stripping the target of the benefit of those spells. If the target is not currently under the effect of least one harmless spell, the target is instead confused for 1d4 rounds.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _spell_turning = {title: "Spell Turning", jsx: <><h2 id="spell-spell_turning-spell-turning">Spell Turning</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 347</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 7, psychic 7, sorcerer 7, summoner 5, unchained summoner 6, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a small silver mirror)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> until expended or 10 min./level</p><p>Spells and spell-like effects targeted on you are turned back upon the original caster. The abjuration turns only spells that have you as a target. Effect and area spells are not affected. Spell turning also fails to stop touch range spells. From seven to ten (1d4+6) spell levels are affected by the turning. The exact number is rolled secretly.</p>
<p>When you are targeted by a spell of higher level than the amount of spell turning you have left, that spell is partially turned. Subtract the amount of spell turning left from the spell level of the incoming spell, then divide the result by the spell level of the incoming spell to see what fraction of the effect gets through. For damaging spells, you and the caster each take a fraction of the damage. For non-damaging spells, each of you has a proportional chance to be the one who is affected. If you and a spellcasting attacker are both warded by spell turning effects in operation, a resonating field is created. Roll randomly to determine the result.</p>
<ScrollContainer id="spell-spell_turning--table-0"><table>
<thead>
<tr>
<th>d%</th>
<th>Effect</th>
</tr>
</thead>
<tbody><tr>
<td>01-70</td>
<td>Spell drains away without effect.</td>
</tr>
<tr>
<td>71-80</td>
<td>Spell affects both of you equally at full effect.</td>
</tr>
<tr>
<td>81-97</td>
<td>Both turning effects are rendered non-functional for 1d4 minutes.</td>
</tr>
<tr>
<td>98-100</td>
<td>Both of you go through a rift into another plane.</td>
</tr>
</tbody></table></ScrollContainer>
</>};
const _spellcasting_contract_lesser = {hasJL:true,title: "Lesser Spellcasting Contract", jsx: <><div className="jumpList" id="spell-spellcasting_contract_lesser-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-spellcasting_contract_lesser-spellcasting-contract">Spellcasting Contract</InnerLink></li><li><InnerLink toTop to="spell-spellcasting_contract_lesser-greater-spellcasting-contract">Greater Spellcasting Contract</InnerLink></li></ul></div><h2 id="spell-spellcasting_contract_lesser-lesser-spellcasting-contract">Lesser Spellcasting Contract</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_29_mother_of_flies">Pathfinder #29: Mother of Flies pg. 67</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> cleric 5, oracle 5, warpriest 5<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched; see text<br/><strong>Duration</strong> permanent until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><blockquote>
<p><em>These three spells are associated with <Link to="/faith/asmodeus">Asmodeus</Link>, but there are no restrictions on its use by others.</em></p>
</blockquote>
<p>This spell functions exactly like imbue with spell ability, except that you can imbue the target with any spell you have prepared (instead of just abjuration, divination, or conjuration [healing] spells) and the target may have more than one use of the imbued spells, depending upon the arrangements made when it is cast.</p>
<p>Casting this spell requires a contract between you and the target, explaining what spells are to be imbued and the circumstances that cause the contract to expire. The contract may be as simple as allowing the target one casting of each of the imbued spells (as per imbue with spell ability), or may continue for multiple days or even indefinitely, with the target regaining use of the imbued spells when you next prepare your own spells. You may include any proviso you see fit, such as requiring the target to pray to Asmodeus each morning, or restricting the target to only casting the imbued spells on himself. If the target does not agree to all the conditions in the contract, this spell fails when cast. The contract (and this spell) automatically expires if you or the target dies. While the contract remains in effect, you gain a profane bonus to your Armor Class, saving throws, and checks equal to the highest-level spell you have imbued.</p>
<p>Once you cast this spell, you cannot prepare a new 5th-level spell to replace it until the contract expires. If the number of 5th-level spells you can cast decreases, and that number drops below your current number of active lesser spellcasting contract spells, the more recently cast imbued spells are dispelled.</p>
<p>Unlike imbue with spell ability, how the target uses the spell has no reflection on your alignment or relationship with Asmodeus; the Prince of Darkness accepts that allowing another access to his magic for good may benefit his plans in the long run. Note that unlike imbue with spell ability, you cannot dismiss this spell; you must abide by the contract's termination clause (though the contract may include a proviso for at-will nullification by either or both parties). This spell cannot be combined with imbue with spell ability or similar spells to give a target more spells than the limit.</p>
<p><em>Example:</em> You cast this spell on your 5 HD fighter cohort after negotiating an appropriate contract, imbuing him with the ability to cast cure moderate wounds, magic weapon, and shield of faith once per day for 1 month. If he casts any of these spells, he recovers them when you prepare your spells. Until the contract ends, your 5th-level spell slot used to cast this spell remains expended and cannot be filled with a new spell. Because you imbued your cohort with a 2nd-level spell, you gain a +2 profane bonus to attacks, saves, and checks while the contract remains in effect.</p>
<h3 id="spell-spellcasting_contract_lesser-spellcasting-contract" data-hash-target>Spellcasting Contract</h3>
<p><strong>Sources</strong> <Link to="/source/pathfinder_29_mother_of_flies">Pathfinder #29: Mother of Flies pg. 68</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> cleric 7, oracle 7<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> permanent until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like lesser spellcasting contract, except if the target has 9 HD or more, you can imbue him with one or two 2nd-level spells and one 3rd-level spell.</p>
<h3 id="spell-spellcasting_contract_lesser-greater-spellcasting-contract" data-hash-target>Greater Spellcasting Contract</h3>
<p><strong>Sources</strong> <Link to="/source/pathfinder_29_mother_of_flies">Pathfinder #29: Mother of Flies pg. 68</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> cleric 9, oracle 9<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> permanent until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like lesser spellcasting contract, except if the target has 13 HD or more you can imbue him with one or two 4th-level spells and one 5th-level spell.</p>
</>};
const _spellcrash_lesser = {hasJL:true,title: "Lesser Spellcrash", jsx: <><div className="jumpList" id="spell-spellcrash_lesser-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-spellcrash_lesser-spellcrash">Spellcrash</InnerLink></li><li><InnerLink toTop to="spell-spellcrash_lesser-greater-spellcrash">Greater Spellcrash</InnerLink></li></ul></div><h2 id="spell-spellcrash_lesser-lesser-spellcrash">Lesser Spellcrash</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 194</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 4, cleric 4, oracle 4, psychic 4, sorcerer 4, warpriest 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; see text; <strong>Spell Resistance</strong> yes</p><p>You create a discordant blast of energy that disrupts the target's available magic each round at the start of its turn.</p>
<p>If the target prepares spells, it must choose one of its prepared 3rd-level spells, which is immediately lost; if the target has no 3rd-level spells prepared, it must lose a 2nd-level spell it has prepared (progressing down to 1st-level spell if it has no 2nd-level spells prepared).</p>
<p>If the target is a spontaneous spellcaster, it loses one of its available 3rd-level spell slots; if the target has no available 3rd-level spell slots, it must lose a 2nd-level spell slot (progressing down to 1st-level spell if it has no 2nd-level spell slots available).</p>
<p>There is no initial saving throw for this spell, but the target can attempt a Will saving throw each round at the end of its turn.</p>
<p>If the target has more than one spellcasting class, choose one at random to be affected. This spell has no effect on spell-like abilities.</p>
<p>Any spell or spell slot lost because of this spell is treated as if the caster had failed a <Link to="/rule/concentration">concentration</Link> check while trying to cast it - the spell or spell slot is wasted and has no effect, but is recovered normally the next time the character prepares spells or regains spell slots.</p>
<h3 id="spell-spellcrash_lesser-spellcrash" data-hash-target>Spellcrash</h3>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 193</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 6, cleric 6, oracle 6, psychic 6, sorcerer 6, warpriest 6, witch 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; see text; <strong>Spell Resistance</strong> yes</p><p>This spell functions as lesser spellcrash, except that it affects 5th-level or lower prepared spells or spell slots.</p>
<h3 id="spell-spellcrash_lesser-greater-spellcrash" data-hash-target>Greater Spellcrash</h3>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 194</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 8, cleric 8, oracle 8, sorcerer 8, witch 8, wizard 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; see text; <strong>Spell Resistance</strong> yes</p><p>This spell functions as lesser spellcrash, except that it affects 7th-level or lower prepared spells or spell slots.</p>
</>};
const _spellcurse = {title: "Spellcurse", jsx: <><h2 id="spell-spellcurse-spellcurse">Spellcurse</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 6</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/curse">curse</Link>]; <strong>Level</strong> antipaladin 2, cleric 3, inquisitor 2, occultist 4, oracle 3, psychic 3, shaman 4, witch 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a fragment of a destroyed magical item)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> 1 creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will half; <strong>Spell Resistance</strong> yes</p><p>You disrupt any spell energy affecting your target, causing that energy to crackle with power and harm the target. The target takes 1d6 points of damage for each spell with a duration of 1 round or greater currently affecting it. The spells themselves are not dispelled or modified.</p>
</>};
const _spellscar = {title: "Spellscar", jsx: <><h2 id="spell-spellscar-spellscar">Spellscar</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_magic">Inner Sea Magic pg. 61</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 8, cleric 8, oracle 8, sorcerer 8, wizard 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a pinch of sand from the Spellscar Desert)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> two 10-ft. cubes per level (S)<br/><strong>Duration</strong> 10 minutes/level (D)</p><p>This potent spell invokes the same sort of magical devastation that created the Mana Wastes so long ago, albeit on a much more localized (and thankfully temporary) scale. Within the area you choose to affect with spellscar, the terrain takes on a strange pale hue, as if colors were muted. Periodically, ripples of vibrant color wriggle through the terrain. Within this area, any spell, spell-like ability, or magic item activation automatically triggers a <Link to="/rule/primal_magic">primal magic</Link> event - a spellcaster can avoid triggering such an event by making a <Link to="/rule/concentration">concentration</Link> check (DC 15 + twice the spell's level), but non-spellcasters who activate magic items have no such option.</p>
<p>You gain a +4 insight bonus on concentration checks made to avoid triggering primal magic events while within a spellscar you have created, and if you do trigger a primal magic event, you may roll d% twice and pick which of the two results you wish to have occur.</p>
</>};
const _spellstaff = {title: "Spellstaff", jsx: <><h2 id="spell-spellstaff-spellstaff">Spellstaff</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 347</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> druid 6, hunter 6<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, F (the staff that stores the spell)<br/><strong>Range</strong> touch<br/><strong>Target</strong> wooden quarterstaff touched<br/><strong>Duration</strong> permanent until discharged<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>You store one spell that you can normally cast in a wooden quarterstaff. Only one such spell can be stored in a staff at a given time, and you cannot have more than one spellstaff at any given time. You can cast a spell stored within a staff just as though it were among those you had prepared, but it does not count against your normal allotment for a given day. You use up any applicable material components required to cast the spell when you store it in the spellstaff.</p>
</>};
const _spellsteal = {title: "Spellsteal", jsx: <><h2 id="spell-spellsteal-spellsteal">Spellsteal</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 200</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 5, cleric 5, oracle 5, psychic 5, sorcerer 5, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous and see text<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You create a discordant blast of energy that disrupts the target's available magic and transfers knowledge of that magic to you.</p>
<p>If the target prepares spells, it must choose one of its prepared 3rd-level spells, which is immediately lost. If the target has no 3rd-level spells prepared, it loses a 2nd-level spell it has prepared. This progresses down to a 1st-level spell if the target has no 2nd-level spells prepared, and this spell has no effect if the target also has no 1st-level spells prepared. If the spell is on your spell list, you can cast this lost spell (using your caster level) on your next turn.</p>
<p>If the target is a spontaneous spellcaster, it loses one of its available 3rd-level spell slots. If the target has no available 3rd-level spell slots, it must lose a 2nd-level spell slot (progressing as above). Randomly select one of the target's spells known of that spell level; if that spell is on your spell list, you can cast it (using your caster level) on your next turn.</p>
<p>You must provide any focus or material components to cast the stolen spell.</p>
<p>If the target has more than one spellcasting class, choose one at random to be affected. This spell has no effect on spell-like abilities.</p>
<p>Any spell or spell slot lost because of this spell is treated as if the caster had failed a <Link to="/rule/concentration">concentration</Link> check while trying to cast - the spell or spell slot is wasted and has no effect, but it is recovered normally the next time the character prepares spells or regains spell slots.</p>
</>};
const _sphere_of_warding = {title: "Sphere of Warding", jsx: <><h2 id="spell-sphere_of_warding-sphere-of-warding">Sphere of Warding</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 19</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 5, inquisitor 4, oracle 5, warpriest 5, witch 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Effect</strong> 10-ft.-radius sphere emanating from point touched<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Will negates (see text); <strong>Spell Resistance</strong> yes</p><p>You create a luminescent sphere of orbiting energy that harms incorporeal creatures and dispossesses them of any stolen bodies. An incorporeal creature must succeed at a Will save to enter a space overlapping with the sphere; failure means the creature cannot pass through the sphere, as though it were a wall of force. If the incorporeal creature succeeds, it may pass through the sphere at will, though if it ends its turn within the sphere, it takes a number of points of force damage equal to 1d6 + 1 per caster level (maximum +10).</p>
<p>If a creature possessing another creature's body (via either magic jar or a similar effect) enters a sphere of warding, that creature is immediately ejected from its host body, the host's spirit returns to its body if it's able, and the possession effect immediately ends. When ejected, the body enters the sphere, while the possessing creature takes the appropriate amount of force damage (no save) and is shunted to the exterior of the sphere.</p>
</>};
const _spherescry = {title: "Spherescry", jsx: <><h2 id="spell-spherescry-spherescry">Spherescry</h2>
<p><strong>Sources</strong> <Link to="/source/classic_treasures_revisited">Classic Treasures Revisited pg. 45</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> (<Link to="/spelldef/scrying">scrying</Link>); <strong>Level</strong> arcanist 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 hour<br/><strong>Components</strong> V, S, F (onyx sphere worth at least 50 gp)<br/><strong>Range</strong> see text<br/><strong>Target</strong> <Link to="/magic-artifact/sphere_of_annihilation">sphere of annihilation</Link><br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell allows remote viewing through spheres that have previously consumed some portion of the spellcaster's body: a single digit of a finger or toe at a minimum. The caster can view and listen to events within a 20-foot radius of the associated sphere; this radius follows the sphere if the sphere moves. Unlike a true scrying spell, no other spells operate through the associated sphere, but spherescry produces no indication of its activity on the target and cannot be discovered by normal methods of magical detection.</p>
</>};
const _spider_climb = {hasJL:true,title: "Spider Climb", jsx: <><div className="jumpList" id="spell-spider_climb-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-spider_climb-mythic_spider_climb">Mythic Spider Climb</InnerLink></li><li><InnerLink toTop to="spell-spider_climb-communal-spider-climb">Communal Spider Climb</InnerLink></li></ul></div><h2 id="spell-spider_climb-spider-climb">Spider Climb</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 347</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 2, arcanist 2, bloodrager 2, druid 2, hunter 2, investigator 2, magus 2, medium 2, occultist 2, psychic 2, red mantis assassin 2, sorcerer 2, summoner 2, unchained summoner 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a live spider)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The subject can climb and travel on vertical surfaces or even traverse ceilings as well as a spider does. The affected creature must have its hands free to climb in this manner. The subject gains a climb speed of 20 feet and a +8 racial bonus on Climb skill checks; furthermore, it need not make Climb checks to traverse a vertical or horizontal surface (even upside down). A spider climbing creature retains its Dexterity bonus to Armor Class (if any) while climbing, and opponents get no special bonus to their attacks against it. It cannot, however, use the run action while climbing.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-spider_climb--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-spider_climb-mythic_spider_climb" data-hash-target>Mythic Spider Climb</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 109</Link></p>
<p>The target gains a climb speed equal to its base land speed or 30 feet, whichever is higher. The target can take the run action while climbing and needs only one hand free to climb.</p>
<p>The target can move freely across spider webs (including giant spider webs), web spells, and similar adhesives of 2nd level or less (including tanglefoot bags) as if it were using freedom of movement.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-spider_climb-communal-spider-climb" data-hash-target>Communal Spider Climb</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 245</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 3, arcanist 3, druid 3, hunter 3, investigator 3, occultist 3, psychic 3, red mantis assassin 3, sorcerer 3, summoner 3, unchained summoner 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a live spider)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like spider climb, except you divide the duration in 10-minute intervals among the creatures touched.</p>
</>};
const _spike_growth = {title: "Spike Growth", jsx: <><h2 id="spell-spike_growth-spike-growth">Spike Growth</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 347</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> druid 3, hunter 2, ranger 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> one 20-ft. square/level<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Reflex partial; <strong>Spell Resistance</strong> yes</p><p>Any ground-covering vegetation in the spell's area becomes very hard and sharply pointed without changing its appearance.</p>
<p>In areas of bare earth, roots and rootlets act in the same way. Typically, spike growth can be cast in any outdoor setting except open water, ice, heavy snow, sandy desert, or bare stone. Any creature moving on foot into or through the spell's area takes 1d4 points of piercing damage for each 5 feet of movement through the spiked area.</p>
<p>Any creature that takes damage from this spell must also succeed on a Reflex save or suffer injuries to its feet and legs that slow its land speed by half. This speed penalty lasts for 24 hours or until the injured creature receives a cure spell (which also restores lost hit points). Another character can remove the penalty by taking 10 minutes to dress the injuries and succeeding on a Heal check against the spell's save DC.</p>
<p>Magic traps are hard to detect. A rogue (only) can use the Perception skill to find a spike growth. The DC is 25 + spell level, or DC 28 for spike growth (or DC 27 for spike growth cast by a ranger). Spike growth can't be disabled with the Disable Device skill.</p>
</>};
const _spike_stones = {title: "Spike Stones", jsx: <><h2 id="spell-spike_stones-spike-stones">Spike Stones</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 348</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> druid 4, hunter 4, shaman 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> one 20-ft. square/level<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Reflex partial; <strong>Spell Resistance</strong> yes</p><p>Rocky ground, stone floors, and similar surfaces shape themselves into long, sharp points that blend into the background.</p>
<p>Spike stones impede progress through an area and deal damage. Any creature moving on foot into or through the spell's area moves at half speed. In addition, each creature moving through the area takes 1d8 points of piercing damage for each 5 feet of movement through the spiked area.</p>
<p>Any creature that takes damage from this spell must also succeed on a Reflex save to avoid injuries to its feet and legs. A failed save causes the creature's speed to be reduced to half normal for 24 hours or until the injured creature receives a cure spell (which also restores lost hit points). Another character can remove the penalty by taking 10 minutes to dress the injuries and succeeding on a Heal check against the spell's save DC.</p>
<p>Magic traps such as spike stones are hard to detect. A rogue (only) can use the Perception skill to find spike stones. The DC is 25 + spell level, or DC 29 for spike stones. Spike stones is a magic trap that can't be disabled with the Disable Device skill.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-spike_stones--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Spike Stones</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 109</Link><br/>The damage dealt increases to 2d6 points of piercing damage plus 1 point of bleed damage. Add your tier to the DC to detect the magical trap.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _spindrift_spritz = {title: "Spindrift Spritz", jsx: <><h2 id="spell-spindrift_spritz-spindrift-spritz">Spindrift Spritz</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 14</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>) [<Link to="/spelldef/water">water</Link>]; <strong>Level</strong> cleric 2, druid 2, hunter 1, inquisitor 2, oracle 2, paladin 1, ranger 1, shaman 2, spiritualist 2, warpriest 2<br/><strong>Casting Time</strong> 1 immediate action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You can cast this spell only as a response to a target attempting a saving throw against an effect that would cause the fatigued, shaken, sickened, or staggered conditions. The target can roll its saving throw twice and take the higher result.</p>
<h3 id="spell-spindrift_spritz-mass-spindrift-spritz">Mass Spindrift Spritz</h3>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 14</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>) [<Link to="/spelldef/water">water</Link>]; <strong>Level</strong> cleric 4, druid 4, hunter 3, inquisitor 4, oracle 4, paladin 3, ranger 3, shaman 4, spiritualist 4, warpriest 4<br/><strong>Casting Time</strong> 1 immediate action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature/level, no two of which can be more than 20 ft. apart<br/><strong>Duration</strong> instant aneous<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions as spindrift spritz, except as noted above.</p>
</>};
const _spiral_ascent = {title: "Spiral Ascent", jsx: <><h2 id="spell-spiral_ascent-spiral-ascent">Spiral Ascent</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 43</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/teleportation">teleportation</Link>); <strong>Level</strong> cleric 3, inquisitor 3, oracle 3, warpriest 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Target</strong> you and touched objects<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>You transform yourself into a helical beam of divine energy that instantly transports you upward to a spot within range. The destination must be a square in the spell's range that's within 10 feet of a point directly above you. The destination must be within your line of sight or familiar to you. After using this spell, you can't take any other actions until your next turn. You can bring along objects as long as their weight doesn't exceed your maximum load.</p>
<p>If you arrive in a place that is already occupied by a solid body, you are teleported to a random open space on a suitable surface within the range and other limitations of the spell. If no such space is available, the spell simply fails. This spell does not function on a plane lacking gravity. On a plane with subjective directional gravity, you can use this spell to teleport in any direction.</p>
<h3 id="spell-spiral_ascent-spiral-descent">Spiral Descent</h3>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 43</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/teleportation">teleportation</Link>); <strong>Level</strong> cleric 2, inquisitor 2, oracle 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Target</strong> you and touched objects<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>This spell functions as spiral ascent, except the destination and direction of travel is downward from your current location.</p>
</>};
const _spirit_bonds = {title: "Spirit Bonds", jsx: <><h2 id="spell-spirit_bonds-spirit-bonds">Spirit Bonds</h2>
<p><strong>Sources</strong> <Link to="/source/divine_anthology">Divine Anthology pg. 13</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> [<Link to="/spelldef/meditative">meditative</Link>]; <strong>Level</strong> arcanist 3, cleric 3, shaman 3, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 hour<br/><strong>Components</strong> V, M (soothing incense worth 300 gp)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 24 hours or until discharged</p><p>You heighten your awareness of up to one willing creature or object per 3 caster levels, each of which must be within 30 feet of you during the entire hour you spend preparing spells and casting spirit bonds. By concentrating on one of these creatures or objects as a full-round action, you can learn its direction and relative distance from your location, provided that it is on the same plane. In the case of a creature, you can also learn the state of its emotion or health <Link to="/rule/auras">aura</Link> as a full-round action. In the case of an object, you can also get a sense of how damaged it is, similar to reading the health aura of a creature, or, in the case of a magic item that must be activated, you can learn when it was last activated (a full-round action in either case).</p>
<p>Additionally, at any time during the spell's duration, you can deliver a single message to any of the creatures that participated in the spell. This message is delivered telepathically regardless of range and can be up to 25 words in length. Delivering a message in this way severs your connection with that character, and you can no longer learn information about that creature through this spell, but doing so does not impact the remaining duration you have linked to other creatures or objects.</p>
</>};
const _spirit_call = {title: "Spirit Call", jsx: <><h2 id="spell-spirit_call-spirit-call">Spirit Call</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link>; <strong>Level</strong> druid 1, hunter 1, shaman 1<br/><strong>Casting Time</strong> 1 full-round action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> 100 ft.<br/><strong>Effect</strong> 100-ft.-radius spread centered on you<br/><strong>Duration</strong> 1 minute/level</p><p>You call out to nature spirits associated with your spirit (not your wandering spirit) if you are a shaman, or your domain if you are a druid, beckoning them forth to pay attention to your current location. For the duration of the spell, all spells from your spirit magic list or domain list that are cast within the affected area have their caster level increased by 1, and all spellcasters casting such spells receive a +4 insight bonus on their <Link to="/rule/concentration">concentration</Link> checks for those spells only.</p>
</>};
const _spirit_share = {title: "Spirit Share", jsx: <><h2 id="spell-spirit_share-spirit-share">Spirit Share</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 23</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 1, arcanist 1, bard 1, cleric 1, druid 1, hunter 1, investigator 1, occultist 1, oracle 1, shaman 1, skald 1, sorcerer 1, warpriest 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (liquid to be shared)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>This spell was first created as a minor parlor trick, but adventuring Caydenites have repurposed and improved on it for use on their travels. For the duration of the spell, as a standard action you can touch a willing target to deliver 1 dose of a potable liquid (including alcoholic drinks and potions and elixirs, but not poisons or other liquids that are primarily harmful when drunk) in your possession (though not necessarily held in hand) into her.</p>
</>};
const _spirit_bound_blade = {title: "Spirit-Bound Blade", jsx: <><h2 id="spell-spirit_bound_blade-spirit-bound-blade">Spirit-Bound Blade</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 186</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> medium 4, occultist 4, shaman 4, spiritualist 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> touch<br/><strong>Target</strong> weapon touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (object, harmless); <strong>Spell Resistance</strong> no</p><p>You focus emotional energy and weave it into a shroud of hardened ectoplasm around the weapon you touch, infusing it with a ghostly glow and great power. The weapon becomes a <Link to="/magic-enh/ghost_touch">ghost touch</Link> weapon, and gains one of the following additional benefits, depending on the type of emotion you infuse into the weapon. If a special ability wouldn't apply to the chosen weapon (such as vicious on a ranged weapon), the weapon doesn't gain that benefit.</p>
<blockquote>
<p><strong>Anger:</strong> The weapon also gains the <Link to="/magic-enh/vicious">vicious</Link> special ability.</p>
<p><strong>Dedication:</strong> The weapon also gains the <Link to="/magic-enh/returning">returning</Link> special ability.</p>
<p><strong>Despair:</strong> The weapon also gains the <Link to="/magic-enh/cruel">cruel</Link> special ability.</p>
<p><strong>Fear:</strong> The weapon also gains the <Link to="/magic-enh/menacing">menacing</Link> special ability.</p>
<p><strong>Hatred:</strong> The weapon also gains the <Link to="/magic-enh/cunning">cunning</Link> special ability.</p>
<p><strong>Jealousy:</strong> The weapon also gains the <Link to="/magic-enh/mimetic">mimetic</Link> special ability.</p>
<p><strong>Kindness:</strong> The weapon also gains the <Link to="/magic-enh/allying">allying</Link> special ability. &mdash; <Link to="/source/psychic_anthology">Psychic Anthology pg. 4</Link></p>
<p><strong>Remorse:</strong> The weapon also gains the <Link to="/magic-enh/heartseeker">heartseeker</Link> special ability. &mdash; <Link to="/source/occult_origins">Occult Origins pg. 19</Link></p>
<p><strong>Whimsey:</strong> The weapon also gains the <Link to="/magic-enh/merciful">merciful</Link> special ability. &mdash; <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe pg. 17</Link></p>
<p><strong>Zeal:</strong> The weapon also gains the <Link to="/magic-enh/keen">keen</Link> special ability.</p>
</blockquote>
<p>If you are a spiritualist and the type of emotional energy you choose matches the emotional focus of your phantom, the weapon grants its wielder a +2 bonus on skill checks with both skills you gain <Link to="/feat/skill_focus">Skill Focus</Link> in from your phantom's emotional focus.</p>
</>};
const _spiritual_ally = {title: "Spiritual Ally", jsx: <><h2 id="spell-spiritual_ally-spiritual-ally">Spiritual Ally</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 246</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> cleric 4, medium 4, oracle 4, spiritualist 4, warpriest 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> spiritual ally of force<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>An ally made of pure force appears in a single 5-foot square within range. The ally takes the form of a servant of your god. The spiritual ally occupies its space, though you and your allies can move through it, since it is your ally. The spiritual ally carries a single weapon, one favored by your deity (as for spiritual weapon), which has the same threat range and critical modifiers as a real weapon of its form. Each round on your turn, starting with the turn that you cast this spell, your spiritual ally can make an attack against a foe within its reach that you designate. The spiritual ally threatens adjacent squares and can flank and make attacks of opportunity as if it were a normal creature. The spiritual ally uses your base attack bonus (gaining extra attacks if your base attack bonus is high enough) plus your Wisdom bonus when it makes a melee attack. When the spiritual ally hits, it deals 1d10 points of force damage + 1 point of damage per 3 caster levels (maximum +5 at 15th level). It strikes as a spell, not a weapon, so it bypasses DR and can affect incorporeal creatures.</p>
<p>Each round after the first, you can move the spiritual ally as a swift action. It has a speed of 30 feet, and a fly speed of 30 feet (perfect maneuverability). Being a construct of force, the spiritual ally cannot be harmed by any physical attacks, but <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/disintegrate">disintegrate</Link>, a <Link to="/magic-artifact/sphere_of_annihilation">sphere of annihilation</Link>, or a <Link to="/magic-rod/rod_of_cancellation">rod of cancellation</Link> affects it. A spiritual ally's AC against touch attacks is 10.</p>
<p>If an attacked creature has spell resistance, you make a caster level check (1d20 + caster level) against that spell resistance the first time the spiritual ally strikes it. If the ally is successfully resisted, the spell is dispelled. If not, the weapon has its normal full effect on that creature for the duration of the spell.</p>
</>};
const _spiritual_squire = {title: "Spiritual Squire", jsx: <><h2 id="spell-spiritual_squire-spiritual-squire">Spiritual Squire</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 23</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> antipaladin 2, cleric 2, inquisitor 2, oracle 2, paladin 2, shaman 2, spiritualist 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> see text<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell causes an ally made of pure force to appear in a single 5-foot square within range. The ally takes the form of a servant of your god (if any) or an ancestor. The spiritual squire occupies its space, though you and your allies can move through it, since it is your ally. While the spiritual squire appears to wear armor and carry a weapon, it cannot make attacks and does not threaten any spaces. On your turn, the spiritual squire can do one of the following: retrieve one stowed item from your possessions, carry an object weighing no more than 10 pounds per caster level, hand you an object it is carrying, perform the aid another action on your behalf or for one of your allies, or help one creature of your choice don armor (which then takes half the normal time). When the spiritual squire attempts the aid another action in combat, its attack bonus is equal to your base attack bonus + your Wisdom modifier.</p>
<p>Each round after the first as a swift action, you can order the spiritual squire to move. It has a speed of 30 feet. Being a construct of force, the spiritual squire cannot be harmed by any physical attacks, but <Link to="/spell/disintegrate">disintegrate</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>, a <Link to="/magic-rod/rod_of_cancellation">rod of cancellation</Link>, or a <Link to="/magic-artifact/sphere_of_annihilation">sphere of annihilation</Link> affects it. A spiritual ally's AC against touch attacks is 10.</p>
</>};
const _spiritual_weapon = {title: "Spiritual Weapon", jsx: <><h2 id="spell-spiritual_weapon-spiritual-weapon">Spiritual Weapon</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 348</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> cleric 2, inquisitor 2, medium 2, oracle 2, shaman 2, spiritualist 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> magic weapon of force<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>A weapon made of force appears and attacks foes at a distance, as you direct it, dealing 1d8 force damage per hit, + 1 point per three caster levels (maximum +5 at 15th level). The weapon takes the shape of a weapon favored by your deity or a weapon with some spiritual significance or symbolism to you (see below) and has the same threat range and critical multipliers as a real weapon of its form. It strikes the opponent you designate, starting with one attack in the round the spell is cast and continuing each round thereafter on your turn. It uses your base attack bonus (possibly allowing it multiple attacks per round in subsequent rounds) plus your Wisdom modifier as its attack bonus. It strikes as a spell, not as a weapon, so for example, it can damage creatures that have damage reduction. As a force effect, it can strike incorporeal creatures without the reduction in damage associated with incorporeality. The weapon always strikes from your direction. It does not get a flanking bonus or help a combatant get one. Your feats or combat actions do not affect the weapon. If the weapon goes beyond the spell range, if it goes out of your sight, or if you are not directing it, the weapon returns to you and hovers.</p>
<p>Each round after the first, you can use a move action to redirect the weapon to a new target. If you do not, the weapon continues to attack the previous round's target. On any round that the weapon switches targets, it gets one attack. Subsequent rounds of attacking that target allow the weapon to make multiple attacks if your base attack bonus would allow it to. Even if the spiritual weapon is a ranged weapon, use the spell's range, not the weapon's normal range increment, and switching targets still is a move action.</p>
<p>A spiritual weapon cannot be attacked or harmed by physical attacks, but <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/disintegrate">disintegrate</Link>, a <Link to="/magic-artifact/sphere_of_annihilation">sphere of annihilation</Link>, or a <Link to="/magic-rod/rod_of_cancellation">rod of cancellation</Link> affects it. A spiritual weapon's AC against touch attacks is 12 (10 + size bonus for Tiny object).</p>
<p>If an attacked creature has spell resistance, you make a caster level check (1d20 + caster level) against that spell resistance the first time the spiritual weapon strikes it. If the weapon is successfully resisted, the spell is dispelled. If not, the weapon has its normal full effect on that creature for the duration of the spell.</p>
<p>The weapon that you get is often a force replica of your deity's own personal weapon. A cleric without a deity gets a weapon based on his alignment. A neutral cleric without a deity can create a spiritual weapon of any alignment, provided he is acting at least generally in accord with that alignment at the time. The weapons associated with each alignment are as follows: chaos (battleaxe), evil (light flail), good (warhammer), law (longsword).</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-spiritual_weapon--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Spiritual Weapon</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 109</Link><br/>The weapon gains your choice of one of the following magic weapon special abilities: flaming, frost, keen, merciful, shock, or thundering. Before or after the weapon attempts all of its attacks for the round, you can redirect it to a different target as a swift action instead of a move action</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _spit_venom = {title: "Spit Venom", jsx: <><h2 id="spell-spit_venom-spit-venom">Spit Venom</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/poison">poison</Link>]; <strong>Level</strong> cleric 4, druid 3, hunter 3, oracle 4, shaman 4, warpriest 4, witch 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> one stream of venom<br/><strong>Duration</strong> instantaneous; see text<br/><strong>Saving Throw</strong> Fortitude partial; <strong>Spell Resistance</strong> no</p><p>You spit a stream of venom at a target using a ranged touch attack. If the venom hits, it causes blindness for 1 round. The target must also save or be poisoned by black adder venom; the DC in successive rounds of the poison is equal to the spell's DC.</p>
</>};
const _spite = {title: "Spite", jsx: <><h2 id="spell-spite-spite">Spite</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 246</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> mesmerist 3, witch 4<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (rare inks worth 250 gp)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 hour/level (d) or until discharged</p><p>Choose a single touch range spell of 4th level or lower with a casting time of 1 standard action or less. As part of the action of casting spite, you cast the associated spell and bind it into a defensive ward in the form of a tattoo, birthmark, or wart somewhere upon your body. The next time you are hit by a melee attack or a combat maneuver is used successfully against you, the stored spell is triggered against your foe. You do not need to succeed on a touch attack to affect the target, but in all other respects the spell is treated as though you had cast it normally. If the attacking creature is not a valid target for the spell, the stored spell is lost with no effect.</p>
<p>You can have only one spite spell in effect at a time; if you cast this spell a second time, the previous spell effect ends.</p>
</>};
const _splinter_spell_resistance = {title: "Splinter Spell Resistance", jsx: <><h2 id="spell-splinter_spell_resistance-splinter-spell-resistance">Splinter Spell Resistance</h2>
<p><strong>Sources</strong> <Link to="/source/arcane_anthology">Arcane Anthology pg. 9</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, bloodrager 2, magus 2, occultist 2, psychic 2, shaman 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Targets</strong> melee or thrown weapon or up to 50 pieces of ammunition touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> no</p><p>You create an aura around the target weapon that weakens a foe's magical defenses. The first time each round the weapon damages a creature with spell resistance, that creature's spell resistance is reduced by 5 for 1 round. This reduction is not cumulative for multiple attacks within the same round, even if the target is struck by different weapons, each affected by a different casting of splinter spell resistance. However, the same creature's spell resistance can be reduced on multiple rounds by subsequent hits.</p>
</>};
const _spontaneous_immolation = {title: "Spontaneous Immolation", jsx: <><h2 id="spell-spontaneous_immolation-spontaneous-immolation">Spontaneous Immolation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 245</Link>, <Link to="/source/orcs_of_golarion">Orcs of Golarion pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> arcanist 2, psychic 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (pinch of saltpeter)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude half and Reflex (see description); <strong>Spell Resistance</strong> yes</p><p>You point your finger at a creature, causing it to spontaneously burst into flame. The target takes 3d6 points of fire damage and catches on fire. A successful Fortitude save reduces this damage by half and prevents the target from catching on fire. Each round on your turn, a burning target can attempt a new save to extinguish the flames (DC equal to the DC of the spell); otherwise it takes another 1d6 fire damage.</p>
</>};
const _spore_burst = {title: "Spore Burst", jsx: <><h2 id="spell-spore_burst-spore-burst">Spore Burst</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions pg. 21</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> [<Link to="/spelldef/poison">poison</Link>]; <strong>Level</strong> druid 2, hunter 2, ranger 3, shaman 2, witch 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a tiny puffball mushroom)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one plant creature; see text<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> special, see text; <strong>Spell Resistance</strong> no</p><p>You cause a willing plant creature's body to sprout small, puffy mushrooms that remain for 1 round per caster level or until the creature uses them. As a standard action, the target can cause these mushrooms to burst open, releasing a cloud of toxic spores that affect all creatures in a 20-foot-radius spread. Those in the area must succeed at Fortitude saves or be sickened for 1d6 rounds as they are overcome by sneezing and coughing. The caster is immune to this poison effect, as are all creatures of the plant type.</p>
</>};
const _spotlight = {title: "Spotlight", jsx: <><h2 id="spell-spotlight-spotlight">Spotlight</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/darkness">darkness</Link>, <Link to="/spelldef/light">light</Link>]; <strong>Level</strong> arcanist 3, bard 3, cleric 3, druid 3, hunter 3, inquisitor 3, magus 3, occultist 3, oracle 3, paladin 3, shaman 3, skald 3, sorcerer 3, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Reflex partial; <strong>Spell Resistance</strong> yes</p><p>You create a mobile area of bright light centered on one target while simultaneously suppressing other light sources surrounding it. The light level in the target's space increases to bright light, causing the target to take any penalties that it would normally take in bright light. In addition, all mundane light sources (and magic light sources of 3rd spell level or lower) within 20 feet of the target's space are suppressed, shedding no light as long as they remain within this spell's affected area and reverting the area normally affected by those light sources to their unmodified illumination levels.</p>
<p>The effects of spotlight are centered on the target and move as the target does. As a result, the target takes a -20 penalty on all Stealth checks for the spell's duration and cannot benefit from concealment normally provided by darkness, as though illuminated with faerie fire.</p>
<p>If the target succeeds at its Reflex save, the spotlight is created in the target's square but does not move with the target, and it hinders the Stealth checks only of creatures within that square.</p>
</>};
const _squeeze = {title: "Squeeze", jsx: <><h2 id="spell-squeeze-squeeze">Squeeze</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 209</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> alchemist 2, arcanist 2, investigator 2, red mantis assassin 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><blockquote>
<p><em><Link to="/race/vishkanya">Vishkanyas</Link> have access to the following spell.</em></p>
</blockquote>
<p>The target becomes flexible regardless of its actual size and mass. It can move through areas at least half its size with no penalty for squeezing. It can move through a space at least one-quarter its width using the penalties for squeezing through a space at least half its width.</p>
</>};
const _stabilize = {title: "Stabilize", jsx: <><h2 id="spell-stabilize-stabilize">Stabilize</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 348</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>); <strong>Level</strong> adept 0, cleric 0, druid 0, hunter 0, inquisitor 0, medium 0, occultist 0, oracle 0, psychic 0, shaman 0, spiritualist 0, warpriest 0, witch 0<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>Upon casting this spell, you target a living creature that has -1 or fewer hit points. That creature is automatically stabilized and does not lose any further hit points. If the creature later takes damage, it continues dying normally.</p>
</>};
const _stabilize_powder = {title: "Stabilize Powder", jsx: <><h2 id="spell-stabilize_powder-stabilize-powder">Stabilize Powder</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 245</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, red mantis assassin 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a few drops of liquor)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> 1 loaded firearm<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (object, harmless); <strong>Spell Resistance</strong> yes (object, harmless)</p><p>Ammunition currently loaded in the target firearm is less prone to misfire. Decrease the misfire range by 1 + 1 per five caster levels (maximum +5, minimum misfire 0) for the ammunition currently loaded into that firearm.</p>
</>};
const _stabilize_pressure = {title: "Stabilize Pressure", jsx: <><h2 id="spell-stabilize_pressure-stabilize-pressure">Stabilize Pressure</h2>
<p><strong>Sources</strong> <Link to="/source/aquatic_adventures">Aquatic Adventures pg. 61</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 2, bloodrager 2, cleric 2, druid 2, hunter 2, investigator 2, oracle 2, psychic 2, ranger 2, shaman 2, summoner 2, unchained summoner 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a piece of shell)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You instantly stabilize the target's pressure, causing it to adjust to its current pressure all at once. This doesn't help it readjust to future pressure changes.</p>
</>};
const _stage_fright = {title: "Stage Fright", jsx: <><h2 id="spell-stage_fright-stage-fright">Stage Fright</h2>
<p><strong>Sources</strong> <Link to="/source/arcane_anthology">Arcane Anthology pg. 27</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/fear">fear</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> antipaladin 3, arcanist 3, bard 3, inquisitor 3, mesmerist 3, psychic 3, skald 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> 1 creature/level, no two of which may be more than 30 ft. apart<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You fill your targets with the sudden fear of failure. A creature that fails its saving throw takes a -4 penalty on ability checks, skill checks, and any checks that require concentration (such as casting a spell in difficult circumstances or operating a complex device).</p>
</>};
const _staggering_fall = {title: "Staggering Fall", jsx: <><h2 id="spell-staggering_fall-staggering-fall">Staggering Fall</h2>
<p><strong>Sources</strong> <Link to="/source/rival_guide">Rival Guide pg. 35</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, cleric 2, oracle 2, red mantis assassin 2, sorcerer 2, warpriest 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 immediate action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one falling creature<br/><strong>Duration</strong> 1 round/level (see below)<br/><strong>Saving Throw</strong> Fortitude partial (see below); <strong>Spell Resistance</strong> yes</p><p>This spell must be cast on a creature as it falls, either from a height or after being knocked prone or tripped. The magic of this spell causes the creature to hit the ground particularly hard, knocking the wind from it. The creature takes an additional 1d6 points of damage from the fall. In addition, the creature becomes staggered for the duration of the spell unless it makes a Will save. Each round the spell's effects persist, the creature may attempt a new Will save as a free action to end the staggered effect early. A creature under the effects of this spell must take a standard action to stand up.</p>
</>};
const _stalwart_resolve = {title: "Stalwart Resolve", jsx: <><h2 id="spell-stalwart_resolve-stalwart-resolve">Stalwart Resolve</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 58</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> alchemist 2, cleric 2, inquisitor 1, investigator 2, oracle 2, paladin 1, warpriest 2, witch 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>Stalwart resolve was originally created to temporarily aid those suffering from certain afflictions. The recipient of stalwart resolve ignores the effects of ability damage and penalties to a single ability score of your choice, except that damage equal to or greater than the ability score still causes unconsciousness or death. This applies whether or not the ability damage or penalty happened before or during the spell's duration, and whether or not multiple sources are involved. This spell has no effect on ability drain.</p>
</>};
const _starsight = {title: "Starsight", jsx: <><h2 id="spell-starsight-starsight">Starsight</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> alchemist 1, arcanist 1, bard 1, cleric 1, druid 1, hunter 1, investigator 1, oracle 1, ranger 1, skald 1, sorcerer 1, warpriest 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 10 minutes/level</p><p>You can observe the night sky and all of its celestial bodies as if it were a clear night, regardless of weather conditions that would otherwise block your view. Your vision penetrates any light pollution from nonmagical sources, though this spell doesn't function in daylight, indoors, or underground. You see through forest canopies and similar natural obstructions, but only for the purpose of stargazing. For the spell's duration, you gain a +2 insight bonus on Knowledge (geography) checks relating to the stars and planets and Survival checks to avoid getting lost.</p>
</>};
const _statue = {title: "Statue", jsx: <><h2 id="spell-statue-statue">Statue</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 349</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 6, arcanist 7, investigator 6, occultist 6, sorcerer 7, wizard 7<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (lime, sand, and a drop of water stirred by an iron spike)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>A statue spell turns the subject to solid stone, along with any garments and equipment worn or carried. In statue form, the subject gains hardness 8. The subject retains its own hit points. The subject can see, hear, and smell normally, but it does not need to eat or breathe. Feeling is limited to those sensations that can affect the granite-hard substance of the individual's body. Chipping is equal to a mere scratch, but breaking off one of the statue's arms constitutes serious damage. The subject of a statue spell can return to its normal state, act, and then return instantly to the statue state (a free action) if it so desires as long as the spell duration is in effect.</p>
</>};
const _status = {title: "Status", jsx: <><h2 id="spell-status-status">Status</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 349</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> cleric 2, medium 2, occultist 2, oracle 2, psychic 2, spiritualist 2, warpriest 2, witch 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Targets</strong> one living creature touched per three levels<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>When you need to keep track of comrades who may get separated, status allows you to mentally monitor their relative positions and general condition. You are aware of direction and distance to the creatures and any conditions affecting them: unharmed, wounded, disabled, staggered, unconscious, dying, nauseated, panicked, stunned, poisoned, diseased, confused, or the like. Once the spell has been cast upon the subjects, the distance between them and the caster does not affect the spell as long as they are on the same plane of existence. If a subject leaves the plane, or if it dies, the spell ceases to function for it.</p>
</>};
const _stave_off_corruption = {title: "Stave Off Corruption", jsx: <><h2 id="spell-stave_off_corruption-stave-off-corruption">Stave Off Corruption</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 128</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 2, oracle 2, paladin 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (see text)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 day/2 caster levels<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You ward the target to slow the advancement of its corruption. The target receives a +2 circumstance bonus on saving throws against the advancement of its corruption, as described in the catalyst section of each corruption. Multiple applications of this spell do not stack, nor does the bonus stack with morale, profane, or sacred bonuses on saving throws against the advancement of the target's corruption.</p>
<p>The material components for this spell vary with the type of corruption. For example, garlic is used for a vampirism corruption, a sprig of wolfsbane is used for a lycanthropy corruption, and so on. The GM can determine appropriate material components, but the components should cost at least 25 gp.</p>
</>};
const _stay_the_hand = {title: "Stay the Hand", jsx: <><h2 id="spell-stay_the_hand-stay-the-hand">Stay the Hand</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 246</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> paladin 4<br/><strong>Casting Time</strong> 1 immediate action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level and special; see text<br/><strong>Saving Throw</strong> Will partial; <strong>Spell Resistance</strong> yes</p><p>You cause a creature's arm to waver and prevent it from striking another creature. You can cast this spell when the target is about to make a melee attack against another creature. On a failed saving throw, the target does not follow through with its attack, and its entire action is wasted for the round. On a successful saving throw, the target can make its attack, forcing its strike though the compulsion but losing both accuracy and power, taking a -5 penalty on its attack and damage rolls. Whether or not the target makes its initial save or not, it is subject to a -2 penalty on attack and damage rolls against the creature it originally targeted for the duration of the spell.</p>
</>};
const _steady_saddle = {title: "Steady Saddle", jsx: <><h2 id="spell-steady_saddle-steady-saddle">Steady Saddle</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 177</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> antipaladin 1, druid 1, hunter 1, paladin 1, ranger 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> saddle touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (object, harmless); <strong>Spell Resistance</strong> yes (object, harmless)</p><p>A saddle affected by this spell becomes more comfortable to sit in, and the magic stabilizes any shaking motion caused by riding at a high speed. For the duration of the spell, the penalty to use ranged weapons while mounted in the target saddle decreases by 2. This stacks with the benefit of the <Link to="/feat/mounted_archery">Mounted Archery</Link> feat and similar effects. Furthermore, the DC for any <Link to="/rule/concentration">concentration</Link> check required as a result of the mount's movement decreases by 2.</p>
</>};
const _steal_book = {title: "Steal Book", jsx: <><h2 id="spell-steal_book-steal-book">Steal Book</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_s03_10_the_immortal_connundrum">Pathfinder Society S03-10 The Immortal Connundrum</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> bard 3, inquisitor 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> one book touched<br/><strong>Duration</strong> permanent<br/><strong>Saving Throw</strong> Fortitude negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>This spell allows you to copy the contents of one book, folio, scroll, or other text to a blank one of suffient size. In doing so, the original pages are wiped blank, though any covers or bindings remain unchanged. Differences in size between the original and blank folio don't matter, though the blank folio must have an equal or greater amount of space (in number of pages or inches of scroll), or else any text that overflows the document is lost forever.</p>
<p>This spell cannot transfer magical writing (such as a wizard's spellbook or a magical scroll).</p>
<p>Optionally, if the GM allows it, the spell can restore lost information, such as a page obscured by spilled wine, text erased by magical or mundane means, or even pages lost to fire or another type of damage.</p>
</>};
const _steal_breath = {title: "Steal Breath", jsx: <><h2 id="spell-steal_breath-steal-breath">Steal Breath</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 95</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/air">air</Link>]; <strong>Level</strong> arcanist 2, bloodrager 2, bard 2, druid 2, hunter 2, mesmerist 2, psychic 2, red mantis assassin 2, skald 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 1 round (see text)<br/><strong>Saving Throw</strong> Fortitude negates, see text; <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em><Link to="/race/catfolk">Catfolk</Link> have access to the following spell.</em></p>
</blockquote>
<p>You pull the breath from a creature's lungs, dealing damage and leaving it unable to speak, use breath weapons, or cast spells with verbal components. If the target fails its saving throw, it takes 2d6 points of damage, and it cannot speak, use breath weapons, or anything else requiring breathing, and a visible line of swirling air leaves the target's mouth and enters your mouth.</p>
<p>If, during the duration, the target moves out of range or line of effect to you, the spell immediately ends. This spell has no effect on creatures that do not need to breathe air.</p>
</>};
const _steal_power = {title: "Steal Power", jsx: <><h2 id="spell-steal_power-steal-power">Steal Power</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 114</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 5, cleric 5, mesmerist 4, oracle 5, psychic 5, sorcerer 5, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one mythic creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You sap the power from a mythic creature, using it to restore your own. The target loses 1d4 uses of mythic power. If you have the ability to expend mythic power, you regain one use for each use the target loses.</p>
</>};
const _steal_size = {title: "Steal Size", jsx: <><h2 id="spell-steal_size-steal-size">Steal Size</h2>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 27</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, bloodrager 2, druid 3, hunter 3, magus 3, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a piece of iron shaped like a scale tray)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one humanoid creature larger than you<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>This spell reduces the target's size by one size category, as if it were affected by reduce person. You grow in size by one category, as if affected by enlarge person (if you can be targeted by that spell). If the spell is dispelled or otherwise ends for either you or the target, both you and the target return to your normal sizes.</p>
</>};
const _steal_voice = {title: "Steal Voice", jsx: <><h2 id="spell-steal_voice-steal-voice">Steal Voice</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 2, bard 2, medium 2, mesmerist 2, psychic 2, skald 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> permanent (D)<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>The target's throat constricts, giving it the <Link to="/rule/minor_spellblights">caster croak</Link> spellblight.</p>
</>};
const _steal_years = {title: "Steal Years", jsx: <><h2 id="spell-steal_years-steal-years">Steal Years</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_night">Blood of the Night pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, cleric 3, druid 3, hunter 3, oracle 3, red mantis assassin 3, sorcerer 3, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a handful of ash)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 24 hours<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>You temporarily drain youth and vitality from the target and channel it into yourself. If the target fails its Fortitude save, it physically ages 1d4 years per two caster levels (maximum 5d4), and you decrease your age by the same number of years. If this changes the age category of you or the target, only adjust physical ability scores. This effect cannot bring your age to lower than the <Link to="/rule/age">minimum age of adulthood</Link> for your race. This stolen youth does not actually change your age or prolong your life; you will still die at your allotted time, no matter how youthful you appear. Likewise, the spell does not add to the target's true age, and cannot make the target die of old age.</p>
<p>When the spell ends, the sudden weight of aging makes you fatigued for 1d4 hours.</p>
<h3 id="spell-steal_years-greater-steal-years">Greater Steal Years</h3>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_night">Blood of the Night pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 5, cleric 5, druid 5, hunter 5, oracle 5, sorcerer 5, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a handful of ash)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 day/level<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions like steal years, except you drain 1d6 years per two caster levels (maximum 10d6).</p>
</>};
const _steam_ray_fusillade = {title: "Steam Ray Fusillade", jsx: <><h2 id="spell-steam_ray_fusillade-steam-ray-fusillade">Steam Ray Fusillade</h2>
<p><strong>Sources</strong> <Link to="/source/aquatic_adventures">Aquatic Adventures pg. 61</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>, <Link to="/spelldef/water">water</Link>]; <strong>Level</strong> arcanist 7, sorcerer 7, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a scraping from a hydrothermal vent)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>For the duration of the spell, you can fire three rays of steam once per round as a standard action (and you also fire three such rays as part of casting the spell). These rays function similarly to the rays from <Link to="/spell/scorching_ray">scorching ray</Link> (you can fire them at close range, they're ranged touch attacks, they deal 4d6 points of fire damage each, and spell resistance negates them) except that they work both underwater and above water without a caster level check for being a fire spell.</p>
</>};
const _stench_of_prey = {title: "Stench of Prey", jsx: <><h2 id="spell-stench_of_prey-stench-of-prey">Stench of Prey</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 194</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> druid 3, hunter 3, ranger 3, shaman 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature (see text)<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (see text); <strong>Spell Resistance</strong> yes</p><p>The target exudes a strong odor that most predators recognize as the scent of helpless prey. The closest 1d4+1 predatory creatures within 30 feet must succeed at a Will save or start attacking the target (animals with the scent ability are affected if within 60 feet). If the predator is an animal, it can be called away from the target by a handler using the "down" trick or any effect that suspends or dispels emotion or rage effects.</p>
<p>This spell has no effect on constructs, undead, or creatures with the unnatural aura ability or effects that repel animals.</p>
</>};
const _stinking_cloud = {title: "Stinking Cloud", jsx: <><h2 id="spell-stinking_cloud-stinking-cloud">Stinking Cloud</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 349</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/poison">poison</Link>]; <strong>Level</strong> arcanist 3, bloodrager 3, magus 3, shaman 3, sorcerer 3, unchained summoner 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a rotten egg or cabbage leaves)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> cloud spreads in 20-ft. radius, 20 ft. high<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Fortitude negates; see text; <strong>Spell Resistance</strong> no</p><p>Stinking cloud creates a bank of fog like that created by fog cloud, except that the vapors are nauseating. Living creatures in the cloud become nauseated. This condition lasts as long as the creature is in the cloud and for 1d4+1 rounds after it leaves. (Roll separately for each nauseated character.) Any creature that succeeds on its save but remains in the cloud must continue to save each round on your turn. This is a poison effect.</p>
<p>Stinking cloud can be made permanent with a <Link to="/spell/permanency">permanency</Link> spell. A permanent stinking cloud dispersed by wind reforms in 10 minutes.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-stinking_cloud--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Stinking Cloud</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 109</Link><br/>Creatures that succeed at their saves are sickened while they remain in the cloud and for 1d4+1 rounds after they leave. Creatures that fail their saves continue to be sickened for 1 hour after leaving the cloud.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _stoke_the_inner_fire = {title: "Stoke the Inner Fire", jsx: <><h2 id="spell-stoke_the_inner_fire-stoke-the-inner-fire">Stoke the Inner Fire</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_95_anvil_of_fire">Pathfinder #95: Anvil of Fire pg. 66</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> cleric 2, inquisitor 2, oracle 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><blockquote>
<p><em>Priests of <Link to="/faith/zursvaater">Zursvaater</Link> have access to the following spell.</em></p>
</blockquote>
<p>You increase the natural heat within your body, transferring it to your weapons and armor. As a swift action, you may grant one of your natural or manufactured weapons the flaming special ability for 1 round. If you have the fire subtype, your weapon instead gains the flaming burst special ability. If the weapon leaves your hand for any reason, it loses the flaming (or flaming burst) special ability until you spend a swift action to activate it again. You can only have stoke the inner fire active on one weapon at a time, and spending a swift action to imbue a second weapon with the spell's power immediately ends its effect on the first weapon.</p>
<p>The spell also builds a wall of searing heat between your armor and your flesh. Anyone striking you with a natural weapon or unarmed strike takes 1 point of fire damage. A creature that grapples you or is grappled by you takes 1 point of fire damage each round the grapple persists. If you have the fire subtype, these damage values increase to 1d6 points of fire damage each. Removing your armor causes this wall of heat to dissipate and ends these effects.</p>
</>};
const _stolen_light = {title: "Stolen Light", jsx: <><h2 id="spell-stolen_light-stolen-light">Stolen Light</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 59</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/figment">figment</Link>); <strong>Level</strong> arcanist 3, bard 3, red mantis assassin 3, skald 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 full-round action<br/><strong>Components</strong> V, S, F (a gem worth at least 500 gp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> transparent gem touched<br/><strong>Duration</strong> permanent or 1 minute/level (see text)<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>Kreighton Shaine researched this spell from the fragmentary notes of a Vudrani ascetic recorded in a strange tome, and rumors credit him with no fewer than a dozen permanent stolen light gems hidden in compartments and drawers in his study. Stolen light stores images within a gem. To store an image, as part of casting you must touch a gem worth not less than 500 gp. You trap within the gem an image of everything visible within a 30-foot cone measured from the gem, in a direction of your choice. Alternatively, you can capture a less detailed image of a single object within sight. Once the casting is complete, the gem turns opaque, and the image inside cannot be seen. The stolen image remains within the gem until released or dispelled.</p>
<p>To release an image, you touch a gem holding stolen light as a standard action and speak a command word chosen at the time of casting. For 1 minute per caster level, the image stored within the gem becomes visible. Details can be made out as clearly as they could be perceived at the time of casting. Darkvision is of no use for making out details in a stolen image, though low-light vision or other exceptional visual talents may reveal information the caster did not see. Light sources brighter than bright light are reduced to bright light in the stolen image. Once the image has been released, it cannot again be recovered from the gem.</p>
<p>Stolen light can be made permanent with the <Link to="/spell/permanency">permanency</Link> spell by a caster of 10th level for a cost of 5,000 gp. This leaves the gem capable of projecting the image indefinitely, activated and deactivated by its command word, until it is destroyed or dispelled.</p>
</>};
const _stone_call = {title: "Stone Call", jsx: <><h2 id="spell-stone_call-stone-call">Stone Call</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 247</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> arcanist 2, bloodrager 2, druid 2, hunter 2, magus 2, ranger 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> cylinder (40-ft. radius, 20 ft. high)<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>A rain of dirt, gravel, and small pebbles fills the area, dealing 2d6 points of bludgeoning damage to every creature in the area. This damage only occurs once, when the spell is cast. For the remaining duration of the spell, this debris covers the ground, making the entire area difficult terrain. At the end of the duration, the rocks disappear, leaving no after-effects (other than the damage dealt).</p>
</>};
const _stone_discus = {title: "Stone Discus", jsx: <><h2 id="spell-stone_discus-stone-discus">Stone Discus</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 194</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> arcanist 2, bloodrager 2, druid 2, hunter 2, magus 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a pinch of earth or metal)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> one or more stone discuses<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You create a stone discus, which flies at an enemy. You can create one discus, plus one additional discus at 7th and 11th caster levels. For each discus you create, you decide whether its edge is blunt (and deals bludgeoning damage) or sharp (and deals slashing damage). Each discus requires a ranged attack to hit and deals 4d6 points of damage. The discuses can be launched at more than one target, but all must be aimed at targets within 30 feet of each other and launched simultaneously.</p>
<p>At caster level 5th, the discuses count as magic and silver. At caster level 10th, they also count as cold iron. At caster level 15th, they also count as adamantine.</p>
</>};
const _stone_fist = {title: "Stone Fist", jsx: <><h2 id="spell-stone_fist-stone-fist">Stone Fist</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 247</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> alchemist 1, arcanist 1, bloodrager 1, druid 1, hunter 1, investigator 1, magus 1, red mantis assassin 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a chip of granite)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level (D)</p><p>This spell transforms your hands into living stone. While this spell is in effect, your unarmed strikes do not provoke attacks of opportunity and deal 1d6 points of lethal bludgeoning damage (1d4 if you are Small). In addition, your unarmed strikes ignore the hardness of any object with a hardness less than 8.</p>
<p><Link to="/spell/stone_to_flesh">Stone to flesh</Link> immediately dispels stone fist. Should you be the target of <Link to="/spell/transmute_rock_to_mud">transmute rock to mud</Link>, this spell immediately ends and you take 4d6 points of damage.</p>
</>};
const _stone_shape = {title: "Stone Shape", jsx: <><h2 id="spell-stone_shape-stone-shape">Stone Shape</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 349</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> arcanist 4, cleric 3, druid 3, hunter 3, occultist 3, oracle 3, red mantis assassin 4, shaman 3, sorcerer 4, warpriest 3, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (soft clay)<br/><strong>Range</strong> touch<br/><strong>Target</strong> stone or stone object touched, up to 10 cu. ft. + 1 cu. ft./level<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You can form an existing piece of stone into any shape that suits your purpose. While it's possible to make crude coffers, doors, and so forth with stone shape, fine detail isn't possible. There is a 30% chance that any shape including moving parts simply doesn't work.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-stone_shape--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Stone Shape</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 109</Link><br/>The duration changes to 1 round/level and instantaneous (see text). Each round after the round you cast the spell, you can spend a standard action to shape up to 5 additional cubic feet of stone you touch. Shaped stone has an instantaneous duration (meaning it does not revert to its previous form when the spell ends).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _stone_shield = {title: "Stone Shield", jsx: <><h2 id="spell-stone_shield-stone-shield">Stone Shield</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 149</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> arcanist 1, bloodrager 1, cleric 1, druid 1, hunter 1, magus 2, oracle 1, shaman 1, sorcerer 1, summoner 1, unchained summoner 1, warpriest 1, wizard 1<br/><strong>Casting Time</strong> 1 immediate action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> 0 ft.<br/><strong>Effect</strong> stone wall whose area is one 5-ft. square<br/><strong>Duration</strong> 1 round<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><blockquote>
<p><em><Link to="/race/oread">Oreads</Link> have access to the following spell.</em></p>
</blockquote>
<p>A 1-inch-thick slab of stone springs up from the ground, interposing itself between you and an opponent of your choice. The stone shield provides you with cover from that enemy until the beginning of your next turn, granting you a +4 bonus to Armor Class and a +2 bonus on Reflex saving throws. If the opponent's attack misses you by 4 or less, the attack strikes the shield instead. The stone shield has hardness 8 and 15 hit points. If the shield is destroyed, the spell ends and the shield crumbles away into nothingness. Spells and effects that damage an area deal damage to the shield.</p>
<p>You cannot use this spell if you are not adjacent to a large area of earth or stone such as the ground or a wall. At 4th level, a <Link to="/arc-monk/qinggong_monk">qinggong monk</Link> may select this spell as a ki power costing 1 ki point to activate.</p>
</>};
const _stone_tell = {title: "Stone Tell", jsx: <><h2 id="spell-stone_tell-stone-tell">Stone Tell</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 349</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> druid 6, hunter 6, psychic 6, shaman 7<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>You gain the ability to speak with stones, which relate to you who or what has touched them as well as revealing what is covered or concealed behind or under them. The stones relate complete descriptions if asked. A stone's perspective, perception, and knowledge may prevent the stone from providing the details you are looking for. You can speak with natural or worked stone.</p>
<h3 id="spell-stone_tell-speak-with-waves">Speak with Waves</h3>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 14</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> [<Link to="/spelldef/water">water</Link>]; <strong>Level</strong> druid 6, hunter 6, shaman 7<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>This spell functions as stone tell but allows conversations only with a body of standing or flowing fresh water at least as large as you are. Flowing water can generally speak about events happening upstream but not events happening downstream.</p>
</>};
const _stone_throwing = {title: "Stone Throwing", jsx: <><h2 id="spell-stone_throwing-stone-throwing">Stone Throwing</h2>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 27</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, bloodrager 1, cleric 2, druid 2, hunter 1, magus 2, oracle 2, ranger 1, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (powdered stone)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The subject gains the rock throwing and rock catching abilities. It can use these abilities with any solid, mostly inflexible object with a hardness of at least 5.</p>
<p>The subject can hurl rocks up to two categories smaller than its own size. The range increment for this attack is 20 feet, and rocks can be hurled a maximum of 5 range increments. Damage is based on the size of the subject-1d8 points of damage for a Large creature, 1d6 for a Medium creature, or 1d4 for a Small creature-plus 1-1/2 times the thrower's Strength bonus.</p>
<p>For every size category smaller than Large the subject is, it receives a cumulative -5 penalty on Reflex saves to catch rocks (or similar projectiles) thrown at it.</p>
</>};
const _stone_to_flesh = {title: "Stone to Flesh", jsx: <><h2 id="spell-stone_to_flesh-stone-to-flesh">Stone to Flesh</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 350</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 6, magus 6, shaman 6, sorcerer 6, witch 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a drop of blood mixed with earth)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one petrified creature or a cylinder of stone from 1 ft. to 3 ft. in diameter and up to 10 ft. long<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude negates (object); see text; <strong>Spell Resistance</strong> yes</p><p>This spell restores a petrified creature to its normal state, restoring life and goods. The creature must make a DC 15 Fortitude save to survive the process. Any petrified creature, regardless of size, can be restored. The spell also can convert a mass of stone into a fleshy substance. Such flesh is inert and lacking a vital life force unless a life force or magical energy is available. For example, this spell would turn an animated stone statue into an animated flesh statue, but an ordinary statue would become a mass of inert flesh in the shape of the statue. You can affect an object that fits within a cylinder from 1 foot to 3 feet in diameter and up to 10 feet long or a cylinder of up to those dimensions in a larger mass of stone.</p>
</>};
const _stoneskin = {hasJL:true,title: "Stoneskin", jsx: <><div className="jumpList" id="spell-stoneskin-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-stoneskin-mythic_stoneskin">Mythic Stoneskin</InnerLink></li><li><InnerLink toTop to="spell-stoneskin-clay-skin">Clay Skin</InnerLink></li><li><InnerLink toTop to="spell-stoneskin-communal-stoneskin">Communal Stoneskin</InnerLink></li></ul></div><h2 id="spell-stoneskin-stoneskin">Stoneskin</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 350</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> adept 4, alchemist 4, arcanist 4, bloodrager 4, druid 5, hunter 5, inquisitor 4, investigator 4, magus 4, occultist 4, psychic 4, shaman 5, sorcerer 4, summoner 3, unchained summoner 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (granite and diamond dust worth 250 gp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 min./level or until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The warded creature gains resistance to blows, cuts, stabs, and slashes. The subject gains DR 10/adamantine. It ignores the first 10 points of damage each time it takes damage from a weapon, though an adamantine weapon bypasses the reduction. Once the spell has prevented a total of 10 points of damage per caster level (maximum 150 points), it is discharged.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-stoneskin--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-stoneskin-mythic_stoneskin" data-hash-target>Mythic Stoneskin</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 109</Link></p>
<p>The target gains a +4 bonus on saving throws against disease, poison, and stun effects. There is a 50% chance any critical hit or sneak attack against the target is treated as a normal hit, as if the target were wearing medium fortification armor.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-stoneskin-clay-skin" data-hash-target>Clay Skin</h3>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 17</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 3, arcanist 3, bloodrager 3, inquisitor 3, investigator 3, magus 3, sorcerer 3, summoner 3, unchained summoner 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (clay and iron fillings)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level or until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The target's skin becomes as thick and tough as clay, granting the target DR 5/adamantine. Once the spell has prevented a total of 5 points of damage per caster level (maximum 50 points), it is discharged and the spell ends.</p>
<h3 id="spell-stoneskin-communal-stoneskin" data-hash-target>Communal Stoneskin</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 245</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 5, arcanist 5, druid 6, hunter 6, inquisitor 5, investigator 5, occultist 5, psychic 5, sorcerer 5, summoner 4, unchained summoner 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (granite and diamond dust worth 250 gp per creature affected)<br/><strong>Range</strong> touch<br/><strong>Targets</strong> creatures touched<br/><strong>Duration</strong> 10 min./level or until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like stoneskin, except you divide the duration in 10 minute intervals among the creatures touched. Once the spell has prevented 10 points of damage per caster level (maximum 150 points) for a subject, the spell's effects end for that subject.</p>
</>};
const _storm_of_blades = {title: "Storm of Blades", jsx: <><h2 id="spell-storm_of_blades-storm-of-blades">Storm of Blades</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands pg. 11</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> arcanist 2, cleric 3, magus 2, oracle 3, sorcerer 2, warpriest 3, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a sword)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You create floating swords of the type used as the material component for this spell (such as a rapier or scimitar) and magically propel them at your target. You can create one sword for every 2 caster levels that you possess, up to a maximum of five swords at 10th level. You must have line of effect between you and the target, and the target must be within the spell's range. You make a ranged attack roll for each sword (with no penalties for range increments or using melee weapons as ranged weapons); each attack has the same threat range and critical modifier and deals the same damage as a standard sword of the type expended. Swords created by this spell disappear after striking (or missing) their targets.</p>
</>};
const _storm_of_vengeance = {title: "Storm of Vengeance", jsx: <><h2 id="spell-storm_of_vengeance-storm-of-vengeance">Storm of Vengeance</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 350</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/summoning">summoning</Link>); <strong>Level</strong> cleric 9, druid 9, oracle 9, shaman 9, witch 9<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Effect</strong> 360-ft.-radius storm cloud<br/><strong>Duration</strong> concentration (maximum 10 rounds) (D)<br/><strong>Saving Throw</strong> see text; <strong>Spell Resistance</strong> yes</p><p>You create a huge black storm cloud in the air. Each creature under the cloud must succeed on a Fortitude save or be deafened for 1d4 &times; 10 minutes. Each round you continue to concentrate, the spell generates additional effects as noted below. Each effect occurs on your turn.</p>
<p><em>2nd Round:</em> Acid rains down in the area, dealing 1d6 points of acid damage (no save).</p>
<p><em>3rd Round:</em> You call six bolts of lightning down from the cloud. You decide where the bolts strike. No two bolts may be directed at the same target. Each bolt deals 10d6 points of electricity damage. A creature struck can attempt a Reflex save for half damage.</p>
<p><em>4th Round:</em> Hailstones rain down in the area, dealing 5d6 points of bludgeoning damage (no save).</p>
<p><em>5th through 10th Rounds:</em> Violent rain and wind gusts reduce visibility. The rain obscures all sight, including darkvision, beyond 5 feet. A creature 5 feet away has concealment (attacks have a 20% miss chance). Creatures farther away have total concealment (50% miss chance, and the attacker cannot use sight to locate the target). Speed is reduced by three-quarters.</p>
<p>Ranged attacks within the area of the storm are impossible. Spells cast within the area are disrupted unless the caster succeeds on a <Link to="/rule/concentration">concentration</Link> check against a DC equal to the storm of vengeance's save DC + the level of the spell the caster is trying to cast.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-storm_of_vengeance--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Storm of Vengeance</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 109</Link><br/>The acid damage dealt increases to 1d8 points of acid damage. The lightning damage dealt increases to 10d8 points of electricity damage. You can call down a bolt of lightning on the 2nd and 4th rounds (equivalent to those on the 3rd round). You can strike the same target with a bolt more than once during the casting of the spell, but not more than once per round.</p>
<p><em>Augmented (7th):</em> If you expend three uses of mythic power, the storm cloud's radius increases to 1,000 feet. Structures in the storm take 1d10 points of damage per round (this damage bypasses hardness). You can call down one additional bolt in the 2nd and 4th rounds, and three additional bolts in the 3rd round.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _storm_sight = {title: "Storm Sight", jsx: <><h2 id="spell-storm_sight-storm-sight">Storm Sight</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 184</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> (<Link to="/spelldef/scrying">scrying</Link>); <strong>Level</strong> arcanist 2, cleric 2, druid 2, hunter 2, oracle 2, shaman 2, sorcerer 2, warpriest 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, F (a storm, either natural or magical)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You step into any magical or naturally occurring storm and commune directly with the power of the wind and rain. This spell allows the storm's power to fill you, granting you knowledge and images of what else lies within its reach. As long as you remain within the storm, you can concentrate on it for 1 minute to determine whether or not other living creatures with an Intelligence score of 3 or higher are caught in the storm within 400 feet of you. Due to the nature of the spell, you do not need to attempt concentration checks against violent wind or storms when casting the spell, but other elements that might disrupt spellcasting require checks as normal. While the spell is in effect, you no longer need to attempt concentration checks as a result of wind or storms for spells you cast or concentrate on.</p>
<p>Once you've sensed creatures with this spell by concentrating for 1 minute, you can continue concentrating to learn more. After you concentrate for 1 additional round, the spell reveals to you via winds and rain the presence of any Small or larger living creature with an Intelligence of 3 or higher within 400 feet of you. After 2 consecutive rounds of concentration, you learn the approximate distance to the detected life forms from your current location. After 3 rounds of concentration, the rain and winds allow you to determine the approximate direction of each life form. Once you've concentrated in this way for 3 rounds, you gain a bonus equal to half your caster level on your next initiative check during the spell's duration.</p>
</>};
const _storm_step = {title: "Storm Step", jsx: <><h2 id="spell-storm_step-storm-step">Storm Step</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements pg. 13</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/teleportation">teleportation</Link>) [<Link to="/spelldef/electricity">electricity</Link>]; <strong>Level</strong> arcanist 3, magus 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> you<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><p>You are able to harness the power of the storm to transport yourself a short distance, by taking the form of a furious, sizzling bolt of elemental electricity. You must either have line of sight to your destination or you must specify a direction and distance within range. Creatures and objects in the path of your passage take 1d8 points of electricity damage per 2 caster levels (maximum 5d8). A successful Reflex save halves the damage.</p>
<p>If your path intersects with a solid object, you damage the barrier accordingly. If the damage is enough to break through the barrier, you continue beyond the barrier as long as the spell's range permits; otherwise, your movement stops in the square adjacent to the barrier and the effect ends.</p>
</>};
const _stormbolts = {title: "Stormbolts", jsx: <><h2 id="spell-stormbolts-stormbolts">Stormbolts</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 247</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/electricity">electricity</Link>]; <strong>Level</strong> arcanist 8, cleric 8, druid 8, oracle 8, shaman 8, sorcerer 8, witch 8, wizard 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a copper rod)<br/><strong>Range</strong> 30 ft.<br/><strong>Area</strong> a 30-ft.-radius spread, centered on you<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude partial; <strong>Spell Resistance</strong> yes</p><p>When you cast this spell, lightning spills forth from your body in all directions. The bolts do not harm natural vegetation or creatures in the area you wish to exclude from damage. Any other creatures within the area take 1d8 points of electricity damage per caster level (maximum 20d8) and are stunned for 1 round. A successful saving throw halves the damage and negates the stun effect.</p>
</>};
